-- Poems batch 97
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b5a464e2-fca5-4624-8a0e-314b2b108d6f','下章安杜瀆七首  其五','姚寬','宋','宋诗','song-poetry','','[]','夢寐家山老歲華，何時滿眼送煙花。',32,'全唐诗/poet.song.115000.json','["夢寐家山老歲華，何時滿眼送煙花。", "定知難取通侯印，亦許歸乘下澤車。"]'),
('cd825a55-b422-444d-bc62-a2b767739d29','下章安杜瀆七首  其六','姚寬','宋','宋诗','song-poetry','','[]','風林葉脫減秋聲，山擁秋光到眼明。',32,'全唐诗/poet.song.115000.json','["風林葉脫減秋聲，山擁秋光到眼明。", "秋興悲秋俱有賦，安仁宋玉是前生。"]'),
('0cb70734-a901-4dee-a6a6-466c1aadaff5','下章安杜瀆七首  其七','姚寬','宋','宋诗','song-poetry','','[]','饑來驅我幾何厭，塵務縈心更可嫌。',32,'全唐诗/poet.song.115000.json','["饑來驅我幾何厭，塵務縈心更可嫌。", "不似陶潜戀松菊，未聞膠鬲舉魚鹽。"]'),
('d7fd37e5-f389-4f4e-a723-0c90e1480b60','行鴻祐路偶作','姚寬','宋','宋诗','song-poetry','','[]','尋幽無十里，闊處見風濤。',48,'全唐诗/poet.song.115000.json','["尋幽無十里，闊處見風濤。", "綠樹雨中密，澹山雲外高。", "心情親醉境，愁色上顛毛。", "早賦歸來引，悠悠誤爾曹。"]'),
('bc29dc3f-2f93-4568-ba88-7080707b2ef2','古博嶺','姚寬','宋','宋诗','song-poetry','','[]','北風獵獵駕寒雲，低壓平川路欲昏。',32,'全唐诗/poet.song.115000.json','["北風獵獵駕寒雲，低壓平川路欲昏。", "人馬忽驚俱辟易，一聲乳虎下前村。"]'),
('9f2b61dd-9963-4765-947c-0c96823bdede','絕句四首  其一','姚寬','宋','宋诗','song-poetry','','[]','一雨一風花欲零，在官在私蛙亂鳴。',32,'全唐诗/poet.song.115000.json','["一雨一風花欲零，在官在私蛙亂鳴。", "留春欲繫金鴉脚，日日日斜樓上情。"]'),
('f47e2595-bd32-40f7-86fe-5ba50ca55448','絕句四首  其二','姚寬','宋','宋诗','song-poetry','','[]','花信今吹第幾風，香苞未拆牡丹叢。',32,'全唐诗/poet.song.115000.json','["花信今吹第幾風，香苞未拆牡丹叢。", "雨聲細入窗前樹，夜夜夜寒春夢中。"]'),
('39124ed0-e48b-427f-ac19-9afae0940c4e','絕句四首  其三','姚寬','宋','宋诗','song-poetry','','[]','京洛逢春思昔時，翩翩遊騎醉中歸。',32,'全唐诗/poet.song.115000.json','["京洛逢春思昔時，翩翩遊騎醉中歸。", "平川花柳濃如錦，樹樹樹頭蜂蝶飛。"]'),
('b7fa3be3-fffe-4c40-b17b-e42187325ae9','絕句四首  其四','姚寬','宋','宋诗','song-poetry','','[]','愁將老眼到花梢，獨自傷春歎絕交。',32,'全唐诗/poet.song.115000.json','["愁將老眼到花梢，獨自傷春歎絕交。", "王謝風流今不見，家家家屋燕成巢。"]'),
('10bc2160-cdae-4293-8b74-45e8bef060dd','隴頭','姚寬','宋','宋诗','song-poetry','','[]','下隴流水咽，上隴征人別。',48,'全唐诗/poet.song.115000.json','["下隴流水咽，上隴征人別。", "秦樹暗秋雲，燕鴻隔春雪。", "閃倏見胡騎，翩翩傳漢節。", "戍客起愁心，心與飛蓬折。"]'),
('02ef52af-2701-419c-a953-22907470c359','苧蘿山  其一','姚寬','宋','宋诗','song-poetry','','[]','娉婷初出苧蘿春，一笑當年國自傾。',32,'全唐诗/poet.song.115000.json','["娉婷初出苧蘿春，一笑當年國自傾。", "絲網珠璣迷去路，鴟夷風月倍多情。"]'),
('9c559b38-684e-4946-8b11-ab05a0e9f580','苧蘿山  其二','姚寬','宋','宋诗','song-poetry','','[]','遥山尚擁雲鬟翠，流水空聞玉佩聲。',32,'全唐诗/poet.song.115000.json','["遥山尚擁雲鬟翠，流水空聞玉佩聲。", "千古人傳浣紗地，王軒何事得逢迎。"]'),
('f1b5af14-58b5-47d4-871a-71dd446d60e7','寄衣曲','許志仁','宋','宋诗','song-poetry','','[]','貂裘雖云溫，非妾手中跡。',104,'全唐诗/poet.song.115000.json','["貂裘雖云溫，非妾手中跡。", "唯此萬里衣，一鍼三歎息。", "歎息恐人聞，縫時常避人。", "開緘勿嫌涴，中有雙淚痕。", "江南十月雁初飛，邊地纔秋塞草衰。", "衣成妾手君寧見，寒到君邊妾自知。", "寄書問征夫，好在何當還。", "西風吹妾夢，夜度魯陽關。"]'),
('1985811a-3021-4a60-8240-1b394998b4ec','妾薄命','許志仁','宋','宋诗','song-poetry','','[]','雙雙林間鳥，雌雄相並棲。',60,'全唐诗/poet.song.115000.json','["雙雙林間鳥，雌雄相並棲。", "驚風忽吹散，各自東西飛。", "妾意如斷絃，斷絃猶可續。", "君心似流水，流水何當復。", "何當復，又是空房將淚宿。"]'),
('0991219d-0598-4ab3-9c4b-2532fb414e4c','和姚令威春晚即事','許志仁','宋','宋诗','song-poetry','','[]','卧看遊絲媚遠天，起尋幽徑却茫然。',64,'全唐诗/poet.song.115000.json','["卧看遊絲媚遠天，起尋幽徑却茫然。", "句成落絮飛花裏，心在殘霞夕照邊。", "無復雙魚傳尺素，空餘寶瑟思華年。", "老來情味人應笑，白首傷春只醉眠。"]'),
('7c692b6c-d844-4dd3-b4f5-080b34e79670','繫冠船蓬自戲','許志仁','宋','宋诗','song-poetry','','[]','竹皮狗尾粗斕斑，神虎門前興已闌。',64,'全唐诗/poet.song.115000.json','["竹皮狗尾粗斕斑，神虎門前興已闌。", "每恨誤身誠可溺，殆將苴履不須彈。", "數莖漸覺勝簪怯，一免當知復冠難。", "柱後惠文非所志，寧從子夏學酸寒。"]'),
('7ef18af5-71f8-4a99-984d-a11439684673','和寶月彈桃源春曉','許志仁','宋','宋诗','song-poetry','','[]','何年鑿源開混茫，桃香兩岸吹紅香。',176,'全唐诗/poet.song.115000.json','["何年鑿源開混茫，桃香兩岸吹紅香。", "煙消遠浦生微陽，魚舟誤行溪水長。", "溪回岸轉山隙光，疑有絳闕仙人房。", "居民爭出羅酒漿，花間笑語音琅琅。", "抱琴釋子眉髮蒼，響泉韻磬鳴長廊。", "能彈往事悲孟嘗，昔時臺沼今耕桑。", "又如勇士赴敵場，坐令遊子思故鄉。", "清猿抱木號鴻荒，孤吟劃見丹鳳翔。", "曲終待月西南廂，重調十指初不忙。", "如見古畫秦衣裳，春天百鳥爭頡頏。", "桃源歸來今已忘，彈到落月空斷腸。"]'),
('5a51b919-277c-48f7-a5c4-22b713f069d6','謝張學士惠靈壽杖','許志仁','宋','宋诗','song-poetry','','[]','九疑連綿青未了，郴江擘出蛟龍吼。',128,'全唐诗/poet.song.115000.json','["九疑連綿青未了，郴江擘出蛟龍吼。", "雷公霹靂搜巖幽，化爲鬰律黄蛇走。", "飛電迸火出奇節，黄蛇起立僵如鐵。", "携看玉女洗頭盆，拄上九疑探禹穴。", "莫挑馬箠渡黄河，莫扣天門閽者訶。", "但掛百錢時一醉，從教風雨濕漁簑。", "青錢學士方年少，年少羞爲老人調。", "即看飛步上蓬瀛，別有青藜夜相照。"]'),
('b1ce9f0b-9395-495d-a54e-706c7a85ee16','天竺道中','許志仁','宋','宋诗','song-poetry','','[]','紫蘭含春風，日暮香更遠。',48,'全唐诗/poet.song.115000.json','["紫蘭含春風，日暮香更遠。", "澗道水平分，曲折渡清淺。", "飛花當面墮，顛倒落苔蘚。", "念此芳意闌，歸思紛莫遣。"]'),
('067ea46f-bddf-43aa-95b0-02f544848381','雁蕩道中','許志仁','宋','宋诗','song-poetry','','[]','千丈巖頭一點紅，春風吹落淺莎中。',32,'全唐诗/poet.song.115000.json','["千丈巖頭一點紅，春風吹落淺莎中。", "山僧倚杖移時去，說似溪邊採藥翁。"]'),
('7525d270-5373-406a-9ce7-b42c2ff92891','湖上吟','許志仁','宋','宋诗','song-poetry','','[]','誰家短笛吹楊柳，何處扁舟唱採菱。',64,'全唐诗/poet.song.115000.json','["誰家短笛吹楊柳，何處扁舟唱採菱。", "湖水欲平風作惡，秋雲太薄雨無憑。", "近人白鷺麾方去，隔岸青山喚不應。", "好景滿前難著語，夜歸茅屋望疏燈。"]'),
('3ad28b7d-e89c-40dc-8e69-66b142b2160b','折楊柳','許志仁','宋','宋诗','song-poetry','','[]','東風來何時，百花已飄零。',72,'全唐诗/poet.song.115000.json','["東風來何時，百花已飄零。", "獨餘堤上柳，慘淡含春榮。", "扁舟復何適，延客江上亭。", "顧無青玉案，何以送子行。", "攀條欲相贈，上有雙流鶑。", "□□正求友，奈此別離情。"]'),
('4055c15e-2ed0-467a-a812-e0f8407720c1','採蓮吟','許志仁','宋','宋诗','song-poetry','','[]','湖邊日落鴛鴦飛，羅衣香轉蘭舟移，蓮根斷處手滿絲。',40,'全唐诗/poet.song.115000.json','["湖邊日落鴛鴦飛，羅衣香轉蘭舟移，蓮根斷處手滿絲。", "手滿絲，不能理。", "秋雲深，隔君子。"]'),
('1b6371be-dac5-48c5-a50c-b88202e3e212','杜宇','許志仁','宋','宋诗','song-poetry','','[]','四海常爲客，三春却倦游。',48,'全唐诗/poet.song.115000.json','["四海常爲客，三春却倦游。", "能飛歸不得，雖去有何求。", "故國三千恨，行人萬里愁。", "年來風過耳，無淚與君流。"]'),
('70264959-0273-4f42-a01f-af106d095deb','鷺','許志仁','宋','宋诗','song-poetry','','[]','春暗汀洲杜若香，風標公子白霓裳。',32,'全唐诗/poet.song.115000.json','["春暗汀洲杜若香，風標公子白霓裳。", "碧天片雪忽飛去，何處人家水滿塘。"]'),
('a857a7da-a429-4fb8-a6d1-9d054eb9d352','烏夜啼','許志仁','宋','宋诗','song-poetry','','[]','碧煙障樓天欲暮，飛烏夜集蕪城戍。',64,'全唐诗/poet.song.115000.json','["碧煙障樓天欲暮，飛烏夜集蕪城戍。", "雲外畢逋銜尾來，月明腷膊同枝語。", "樓中有人輟機杼，玉笙怨咽凝江霧。", "惆悵幽悽夜未闌，桂樹秋風蘭葉露。"]'),
('843da89b-52cb-4185-a5dd-605e4b5563be','臨高臺','許志仁','宋','宋诗','song-poetry','','[]','高臺跨崇岡，簷宇鎖空霧。',72,'全唐诗/poet.song.115000.json','["高臺跨崇岡，簷宇鎖空霧。", "新晴洗雙目，千里在跬步。", "霏霏漁浦煙，冉冉富春樹。", "風花不我私，何以理愁緒。", "誰疏白玉窗，中有浮雲度。", "浮雲吹不開，不見行人去。"]'),
('2ae92a9b-1222-4b94-8fde-9987f698cbbc','架壁','許志仁','宋','宋诗','song-poetry','','[]','架壁珍藏萬古書，世間清絕在吾廬。',64,'全唐诗/poet.song.115000.json','["架壁珍藏萬古書，世間清絕在吾廬。", "綠瓶香破分家釀，曲圃雲開翦露蔬。", "白日漸隨秋意短，故人盡向老來疏。", "今年種得回峰菊，亂點東籬玉不如。"]'),
('ee6151f0-ac84-4727-9b72-5d4107125ba4','東門行','許志仁','宋','宋诗','song-poetry','','[]','東門楊柳暗藏鴉，東門行客欲離家。',96,'全唐诗/poet.song.115000.json','["東門楊柳暗藏鴉，東門行客欲離家。", "樹頭春風草頭露，鴉自不飛人自去。", "妾家南浦桂爲堂，房櫳瑉玉簾夜光。", "爐煙多，綺羅重，水檻風入笙簫凉。", "歡娛未畢車輪遠，方寸秋絲紛百繭。", "願郎功業落人間，長使春閨女無怨。"]'),
('79771aea-5bf1-4ac3-b83e-4bf1f28228cb','窗間','許志仁','宋','宋诗','song-poetry','','[]','秋香爛熳入屏帷，金粟樓臺富貴時。',32,'全唐诗/poet.song.115000.json','["秋香爛熳入屏帷，金粟樓臺富貴時。", "曉起旋收花上露，窗間閑寫夜來詩。"]'),
('c0648d82-0375-422d-94bd-f820b0b515ec','和虞智父登清谿閣','許志仁','宋','宋诗','song-poetry','','[]','葉脫林梢處處秋，壯懷易感更登樓。',64,'全唐诗/poet.song.115000.json','["葉脫林梢處處秋，壯懷易感更登樓。", "日斜鍾阜煙凝碧，霜落秦淮水慢流。", "人似仲宣思故國，詩如杜老到夔州。", "十年前作金陵夢，重撫闌干說舊遊。"]'),
('75d2ba03-8000-4b66-b18a-06e808f25548','白苧歌','許志仁','宋','宋诗','song-poetry','','[]','大垂手，小垂手，江南白苧世希有。',128,'全唐诗/poet.song.115000.json','["大垂手，小垂手，江南白苧世希有。", "吳姬十指玉纖纖，白苧新裁舞衣小。", "秋江四面繞吳宮，吳宮霜橘樹樹紅。", "吳王夜宴不知曉，但見紅日昇曈矓。", "美人低鬟復回袖，持酒獻君君一笑。", "人生得意不行樂，白日如梭夜催晝。", "吳山依舊吳江清，離宮故苑難爲情。", "不知誰遣南山鹿，還向姑蘇臺下行。"]'),
('dc1b8e3e-b1cc-4820-a6cc-fc21c2a037ff','存目  其一','許志仁','宋','宋诗','song-poetry','','[]','詩題：傾城誤人身寄內翰洪丈首句：傾城誤人身。',22,'全唐诗/poet.song.115000.json','["詩題：傾城誤人身寄內翰洪丈首句：傾城誤人身。"]'),
('145d9346-001a-4b38-b324-8323498fc97e','存目  其二','許志仁','宋','宋诗','song-poetry','','[]','詩題：蟻飲研槽歌首句：晴窗棐几風日舒。',19,'全唐诗/poet.song.115000.json','["詩題：蟻飲研槽歌首句：晴窗棐几風日舒。"]'),
('05234a41-15cc-442b-941a-7ebdd4fde8a2','橫浦樓','賈成之','宋','宋诗','song-poetry','','[]','橫槎三月江如束，風浪縈行接天綠。',48,'全唐诗/poet.song.115000.json','["橫槎三月江如束，風浪縈行接天綠。", "郡樓新創插雲飛，盡日江山對雙目。", "樓中剌史幽興長，百斛載春供不足。"]'),
('95aae5d6-f2bf-42d8-9f78-8f6dfd115036','偈','釋智鑒','宋','宋诗','song-poetry','','[]','世尊有密語，迦葉不覆藏。',24,'全唐诗/poet.song.115000.json','["世尊有密語，迦葉不覆藏。", "一夜落花雨，滿城流水香。"]'),
('5da53869-8e6f-4c14-9394-2d152041c053','頌古十一首  其一','釋智鑒','宋','宋诗','song-poetry','','[]','土面灰頭不染塵，華街柳巷樂天真。',32,'全唐诗/poet.song.115000.json','["土面灰頭不染塵，華街柳巷樂天真。", "金鷄唱曉瓊樓夢，一樹華開浩劫春。"]'),
('d7885428-37a6-4b67-ad84-053892ca30af','頌古十一首  其二','釋智鑒','宋','宋诗','song-poetry','','[]','倒却門前剎竿，全提那涉玄端。',30,'全唐诗/poet.song.115000.json','["倒却門前剎竿，全提那涉玄端。", "翻身不坐空王殿，月照千峯夜色寒。"]'),
('fa37701f-3890-4301-ba78-f40b8e131624','頌古十一首  其三','釋智鑒','宋','宋诗','song-poetry','','[]','即心是佛外忘求，心佛圓明不假修。',32,'全唐诗/poet.song.115000.json','["即心是佛外忘求，心佛圓明不假修。", "雲浄遠山千點翠，水和明月一天秋。"]'),
('bc93a9cc-dce5-4144-ba95-1998a9b7ff6e','頌古十一首  其四','釋智鑒','宋','宋诗','song-poetry','','[]','百非路絕透離微，四句情忘發上機。',32,'全唐诗/poet.song.115000.json','["百非路絕透離微，四句情忘發上機。", "竹密不妨流水過，山高豈礙白雲飛。"]'),
('fad63d4f-b981-4277-a020-3a015e76bb67','頌古十一首  其五','釋智鑒','宋','宋诗','song-poetry','','[]','背前面後揚家醜，揭地洪音師子吼。',32,'全唐诗/poet.song.115000.json','["背前面後揚家醜，揭地洪音師子吼。", "分付仙陀知不知，法身午夜藏北斗。"]'),
('e19f0846-7724-4443-a3b2-61d0857087cf','頌古十一首  其六','釋智鑒','宋','宋诗','song-poetry','','[]','雲巢夢斷月華秋，玉女翻身過斗牛。',32,'全唐诗/poet.song.115000.json','["雲巢夢斷月華秋，玉女翻身過斗牛。", "卸却花冠歸舊隠，玄途鳥道未容收。"]'),
('febb6a90-e02c-44b0-bf77-8509556abfd7','頌古十一首  其七','釋智鑒','宋','宋诗','song-poetry','','[]','玄途不涉透離微，道合平常發上機。',32,'全唐诗/poet.song.115000.json','["玄途不涉透離微，道合平常發上機。", "無影樹頭春色曉，金鷄啼在不萌枝。"]'),
('ffd1b24d-5ac7-4dc7-9737-2c1777fae422','頌古十一首  其八','釋智鑒','宋','宋诗','song-poetry','','[]','趙州一匝天輪轉，婆子知音未足酬。',32,'全唐诗/poet.song.115000.json','["趙州一匝天輪轉，婆子知音未足酬。", "普爲人天開正眼，大千沙界一毫收。"]'),
('16b77712-7356-4306-b474-d3f57ef3f450','頌古十一首  其九','釋智鑒','宋','宋诗','song-poetry','','[]','虛玄鳥道沒纖埃，玉殿空然瑣綠苔。',32,'全唐诗/poet.song.115000.json','["虛玄鳥道沒纖埃，玉殿空然瑣綠苔。", "挂壁梭飛秋蛻骨，滄溟老蚌盡懷胎。"]'),
('62e019af-8b2b-4908-827a-38c76d837c29','頌古十一首  其一○','釋智鑒','宋','宋诗','song-poetry','','[]','覿面全提少室令，當機不薦過新羅。',32,'全唐诗/poet.song.115000.json','["覿面全提少室令，當機不薦過新羅。", "清風樓上逢知己，撥動烟塵不奈何。"]'),
('afe2e452-184a-4966-83ab-ebf1c1411c24','頌古十一首  其一一','釋智鑒','宋','宋诗','song-poetry','','[]','青山是父白雲兒，雲散青山總不知。',32,'全唐诗/poet.song.115000.json','["青山是父白雲兒，雲散青山總不知。", "玉兔晝眠雲母地，金烏夜宿不萌枝。"]'),
('d51a4709-5bb1-4703-b45d-60a3c13ab5fe','獻壽詩','孫緯','宋','宋诗','song-poetry','','[]','面臉丹如朱頂鶴，髭髯長似綠毛龜。',32,'全唐诗/poet.song.115000.json','["面臉丹如朱頂鶴，髭髯長似綠毛龜。", "欲知相府生辰日，此是人間祭竈時。"]'),
('9e9a6c61-8381-46f7-b674-679e9fa022d8','過練湖','顧松年','宋','宋诗','song-poetry','','[]','行行何處慰吟觀，負郭平湖萬頃寬。',64,'全唐诗/poet.song.115000.json','["行行何處慰吟觀，負郭平湖萬頃寬。", "兩寺鐘聲烟外聽，六朝山色鏡中看。", "難追鷗鷺朋儔密，頗怪魚龍窟宅寒。", "請濯塵纓自茲始，爲辭雲水向長安。"]'),
('aed6c5f2-a7f8-45da-a9ca-5e1151340838','虎跑泉','廖顒','宋','宋诗','song-poetry','','[]','真馭遺蹤古，寒泉瀉石清。',24,'全唐诗/poet.song.115000.json','["真馭遺蹤古，寒泉瀉石清。", "養源人莫測，流潤濟蒼生。"]'),
('7c910c9a-02b3-40f3-b44d-b7535d631beb','遊七星巖','廖顒','宋','宋诗','song-poetry','','[]','斗峰遥憶舊松臺，爲勸農耕特地來。',64,'全唐诗/poet.song.115000.json','["斗峰遥憶舊松臺，爲勸農耕特地來。", "短李高名光翠壁，僞劉陳迹沒蒼苔。", "洞天日永風埃浄，巖壑雲收霽色開。", "好景最宜供宴賞，操觚欲賦愧非才。"]'),
('bfc883a0-747c-4205-994d-7275b6920f92','游黄山','謝鳳','宋','宋诗','song-poetry','','[]','歷覽岧嶤接斗牛，巖排雲樹翠陰稠。',64,'全唐诗/poet.song.115000.json','["歷覽岧嶤接斗牛，巖排雲樹翠陰稠。", "風生藥臼清香遠，日照丹巖紫氣浮。", "仙樂有聲聞晝夜，靈泉無火沸春秋。", "猶多奇絕應難到，聊寫新詩紀勝遊。"]'),
('1ea5d1e1-429d-45e2-bfff-a11a2c5e5b2a','句','謝鳳','宋','宋诗','song-poetry','','[]','兩袖清風蓬島路，一襟明月海天秋。',16,'全唐诗/poet.song.115000.json','["兩袖清風蓬島路，一襟明月海天秋。"]'),
('f5a392dd-0582-469e-b233-5356bfe2a438','凈聖庵','王賓','宋','宋诗','song-poetry','','[]','樂道巖前沙路平，淡烟和月照人行。',64,'全唐诗/poet.song.115000.json','["樂道巖前沙路平，淡烟和月照人行。", "林端仙館千山合，石罅靈泉一派清。", "藴藻競嚴朝斗意，琳瑯惟聽步虛聲。", "青書奏罷黄冠睡，獨有灘雷徹夜鳴。"]'),
('99397ed3-6e49-44b2-a6e3-56db8e2e20d6','句  其一','孫仲鰲','宋','宋诗','song-poetry','','[]','名向阿衡篇裏得，書從復古殿中來。',16,'全唐诗/poet.song.115000.json','["名向阿衡篇裏得，書從復古殿中來。"]'),
('4de6a231-ec6e-43b1-8e01-9c0e3508d3bb','句  其二','孫仲鰲','宋','宋诗','song-poetry','','[]','淚川紫岫洗詩愁，朱橘白魚供飲痛。',16,'全唐诗/poet.song.115000.json','["淚川紫岫洗詩愁，朱橘白魚供飲痛。"]'),
('a0867446-6812-446b-bed3-8176aba5eb36','江纂墓碑','孫起卿','宋','宋诗','song-poetry','','[]','家有古冢碑，近自田家獲。',252,'全唐诗/poet.song.115000.json','["家有古冢碑，近自田家獲。", "藏之五六年，未甚見省錄。", "古苔侵文理，封結殆莫識。", "偶然嗟其窮，一一爲磨剔。", "始若漫無文，細尋適可讀。", "文云晉江纂，長夜垂茲刻。", "貞石殊不用，塊然但埏埴。", "合葬無別銘，背面書反覆。", "一字不涉華，本枝記明白。", "二父遂兼書，于逌乃宗嫡。", "考諸晉史篇，真是小出入。", "字畫亦嶮勁，然不類鎸斲。", "漢魏尚豐碑，茲獨何褊迫。", "豈時丁喪亂，不暇如品式。", "於時義熙季，處次實庚戌。", "五胡剖中原，典午竄南極。", "苟簡理宜爾，寧詒不孝責。", "審訂既昭然，疑去喜自適。", "歷年七百餘，瞥爾駒過隙。", "名節苟不傳，埃化先瓦石。", "寘茲當眼前，用代銘几席。"]'),
('f61f5f06-7997-46c8-9615-0cedb0c4ee90','癸水','翟傑','宋','宋诗','song-poetry','','[]','癸水繞東城，刀兵不用憂。',24,'全唐诗/poet.song.115000.json','["癸水繞東城，刀兵不用憂。", "須勤疏道力，常使達潮頭。"]'),
('12e4e2ec-3676-44d5-9040-a887201e8bbf','藤州道上','李孟博','宋','宋诗','song-poetry','','[]','道上何嘗識故侯，解鞍聊發小遲留。',32,'全唐诗/poet.song.115000.json','["道上何嘗識故侯，解鞍聊發小遲留。", "莫向漳江更南望，四十八驛是藤州。"]'),
('bee89283-e485-4102-a6bc-04d60d78c9e0','句','曹筠','宋','宋诗','song-poetry','','[]','浩浩秦淮千萬頃，好將餘浪到灘頭。',16,'全唐诗/poet.song.115000.json','["浩浩秦淮千萬頃，好將餘浪到灘頭。"]'),
('f4bcd368-b537-41e5-b068-bd9b88042065','句','季南壽','宋','宋诗','song-poetry','','[]','我以銅符吏營浦，聞古刺史元最賢。',16,'全唐诗/poet.song.115000.json','["我以銅符吏營浦，聞古刺史元最賢。"]'),
('08eeffae-ce8a-4045-87b8-8c87b183baae','祠龐潁公','王九齡','宋','宋诗','song-poetry','','[]','賢哉龐潁公，天相佑仁宗。',288,'全唐诗/poet.song.115000.json','["賢哉龐潁公，天相佑仁宗。", "清規映當代，勁節摩秋空。", "皇祐維四年，蠻寇南海邕。", "委身任虎將，獻馘魯侯宮。", "又能識君實，薦鶚如孔融。", "人言主與賓，霜降鳴豐鐘。", "至今勳業在，隠然齊岱嵩。", "少時居蔭下，讀書此堂中。", "三年足不市，紛華塵垢同。", "平生經綸志，於此涵養豐。", "梁間産靈芝，秀異鬰青葱。", "殿角存琬琰，揮毫氣吐虹。", "常時有識者，固知非卧龍。", "一朝十載遇，談笑集勳庸。", "後人勤仰止，圖像君子容。", "蕭然堂廡間，香火一時共。", "地遠塵不到，山高氣自雄。", "松竹交蔭鬰，桃李間繁穠。", "堂經百年久，隳圮幾一空。", "斷砌行春蚓，敗壁號秋蛩。", "僧有惟勔者，鼎施葺施工。", "興僕廣湫隘，疏林撤翳蒙。", "至今山下路，冠蓋仍憧憧。", "我來爲此邑，坐閲三年窮。"]'),
('64e294e7-8d80-41d6-8cc7-28256056c157','聽鼓琴','王九齡','宋','宋诗','song-poetry','','[]','至音不傳徒按譜，不傳之妙心自許。',160,'全唐诗/poet.song.115000.json','["至音不傳徒按譜，不傳之妙心自許。", "手揮五絃目飛鴻，千載流風如接武。", "鶉衣百結甘藍縷，鬢雪浸浸用心苦。", "我知若人之用心，指下堪爲兒女語。", "神怡志定一齊鼓，和氣沖融塞天宇。", "忽然作意變軒昂，亦不哀吟動凄楚。", "醉翁已作黄鶴舉，君獨何爲在塵土。", "琅然清圖請更彈，使我三歎首屢俯。", "人生識意天所予，性情之適適其所。", "高山流水有知音，莫道吾人不如古。"]'),
('3a6ea5a4-9ce5-499e-a9f2-a38471a1f304','題吉昌橋','吳武陵','宋','宋诗','song-poetry','','[]','一水長流出澗溪，衆山綿密與雲齊。',32,'全唐诗/poet.song.115000.json','["一水長流出澗溪，衆山綿密與雲齊。", "武陵橋上觀春色，自笑劉郎去路迷。"]'),
('401c8937-3446-4bb6-82d6-fe851a54854d','王文孺臞菴  其一','程敦厚','宋','宋诗','song-poetry','','[]','待月凝雲關，垂竿釣雪灘。',48,'全唐诗/poet.song.115000.json','["待月凝雲關，垂竿釣雪灘。", "虛窗摇冷翠，傑閣聳高寒。", "籠養千齡鶴，爐燒九轉丹。", "不須論許事，心目自清安。"]'),
('15d03aae-3120-4f57-a380-3409cc90dc59','王文孺臞菴  其二','程敦厚','宋','宋诗','song-poetry','','[]','壁上煙蘿子，窗前鴻素書。',48,'全唐诗/poet.song.115000.json','["壁上煙蘿子，窗前鴻素書。", "短籬開窈窕，嫩竹轉扶疏。", "世事霜前葉，聲名澗底樗。", "柴桑陶靖節，日暮荷歸鋤。"]'),
('5c419223-6f43-423e-885c-b38a9dc15fb5','題陳宏畫明皇太真聯鑣圖','程敦厚','宋','宋诗','song-poetry','','[]','並轡春風禁籞遊，外間底事上心頭。',32,'全唐诗/poet.song.115000.json','["並轡春風禁籞遊，外間底事上心頭。", "騎馿後日嘉陵道，料得君王始欲愁。"]'),
('44ea662c-1f7c-4164-95c8-eb53b8a1b4a7','題陳宏畫太真上馬圖','程敦厚','宋','宋诗','song-poetry','','[]','阿環百巧專恩寵，自是三郎騃不知。',32,'全唐诗/poet.song.115000.json','["阿環百巧專恩寵，自是三郎騃不知。", "上馬未應乏無力，要回一顧特遲遲。"]'),
('2cba3f70-2c39-4eaa-b3a4-39c58e604df2','和冬曦海棠','程敦厚','宋','宋诗','song-poetry','','[]','花中名品異，人重比甘棠。',96,'全唐诗/poet.song.115000.json','["花中名品異，人重比甘棠。", "苞嫩相思密，紅深琥珀光。", "好風傳馥鬰，凡卉愧芬芳。", "爛漫雲成瑞，葳蕤女有嬙。", "生來先蜀國，開處始朝陽。", "賞即笙歌地，題稱翰墨場。", "煙霞容易散，蜂蝶等閒忙。", "誰是多情侶，欄邊重舉觴。"]'),
('c2917b44-bc7e-407d-9a69-304a05e54d9c','今朝秋氣蕭瑟不意海棠再開因書二絕期好事者和  其一','程敦厚','宋','宋诗','song-poetry','','[]','曾逐狂飈取意飛，一時春色便依稀。',32,'全唐诗/poet.song.115000.json','["曾逐狂飈取意飛，一時春色便依稀。", "舊叢還有香心在，却被西風管領歸。"]'),
('fbceca9c-fce9-4334-8b6f-e1880b7c9cae','今朝秋氣蕭瑟不意海棠再開因書二絕期好事者和  其二','程敦厚','宋','宋诗','song-poetry','','[]','露濕燕脂淚臉寒，獨將幽恨倚闌干。',32,'全唐诗/poet.song.115000.json','["露濕燕脂淚臉寒，獨將幽恨倚闌干。", "精神不比籬邊菊，莫把尋常醉眼看。"]'),
('201ae3e9-ec6a-4282-abf2-6da588e69dd7','雨中海棠','程敦厚','宋','宋诗','song-poetry','','[]','玉脆紅輕不耐寒，無端風雨苦相干。',32,'全唐诗/poet.song.115000.json','["玉脆紅輕不耐寒，無端風雨苦相干。", "曉來試卷珠簾看，蔌蔌飛香滿畫欄。"]'),
('fac781e8-c6a3-43bd-82aa-e882fd30a07b','惜海棠開晚','程敦厚','宋','宋诗','song-poetry','','[]','今年春色可勝嗟，二月山中未見花。',32,'全唐诗/poet.song.115000.json','["今年春色可勝嗟，二月山中未見花。", "長憶去年今夜月，海棠花影到窗紗。"]'),
('a9a49196-e41e-4390-bbf1-f4f4db1acd65','擢秀峰','程敦厚','宋','宋诗','song-poetry','','[]','化境何年斵取還，嶄然擢秀瘴茅間。',32,'全唐诗/poet.song.115000.json','["化境何年斵取還，嶄然擢秀瘴茅間。", "我來授記開潛閲，從此佳名溢世寰。"]'),
('034f1afe-4ce5-4574-a910-613327e4b6ff','草堂','程敦厚','宋','宋诗','song-poetry','','[]','地控三州界，池開十丈蓮。',48,'全唐诗/poet.song.115000.json','["地控三州界，池開十丈蓮。", "桑麻無杜曲，松菊有斜川。", "別浦歸帆遠，他山晚照妍。", "江河春水闊，幽興白鷗前。"]'),
('2e0d2310-f071-430c-86ff-5e03383cc0db','牡丹','程敦厚','宋','宋诗','song-poetry','','[]','芳叢列翠幰，新苞吐香麝。',36,'全唐诗/poet.song.115000.json','["芳叢列翠幰，新苞吐香麝。", "滿地方爭妍，何花肯相下。", "牡丹持晚節，羣芳甘共亞。"]'),
('8be8ca57-2be4-4f12-8555-e325c32f1cd6','海棠','程敦厚','宋','宋诗','song-poetry','','[]','柔條還自立，絕色所不鬭。',24,'全唐诗/poet.song.115000.json','["柔條還自立，絕色所不鬭。", "昂然氣格高，下視羣卉陋。"]'),
('a013b0ae-b8be-4eb9-aa6c-eba9950c8dc0','酴醿','程敦厚','宋','宋诗','song-poetry','','[]','獨憐朱臉花容俗，全學瑶臺玉女粧。',32,'全唐诗/poet.song.115000.json','["獨憐朱臉花容俗，全學瑶臺玉女粧。", "素月共成中夜色，好風分散四鄰香。"]'),
('da4a3784-998a-4905-92fc-f99b1bb464d3','餘甘子','程敦厚','宋','宋诗','song-poetry','','[]','愁苦人意未相諳，率以初嘗廢後甘。',32,'全唐诗/poet.song.115000.json','["愁苦人意未相諳，率以初嘗廢後甘。", "王氏有詩旌橄欖，可憐遺咏在巴南。"]'),
('d333afe4-89f6-4374-835f-4dabc645b5eb','梨','程敦厚','宋','宋诗','song-poetry','','[]','遠意來佳惠，秋筠啟翠籃。',48,'全唐诗/poet.song.115000.json','["遠意來佳惠，秋筠啟翠籃。", "清香殊未散，奇品至相參。", "鳳卵辭丹穴，龍珠出古潭。", "剖輕刀匕快，嚼易齒牙甘。"]'),
('67c59901-cfdf-4f82-a696-b65892b8c632','句  其一','程敦厚','宋','宋诗','song-poetry','','[]','萬蘂紛妍照畫堂，一林春思尚緘藏。',16,'全唐诗/poet.song.115000.json','["萬蘂紛妍照畫堂，一林春思尚緘藏。"]'),
('c6034c31-4eb1-4b10-b5fd-d88f8fd99951','句  其二','程敦厚','宋','宋诗','song-poetry','','[]','一色鮮猩血。',6,'全唐诗/poet.song.115000.json','["一色鮮猩血。"]'),
('bc0b7fd5-0450-4e3d-a2fe-1216d460da93','句  其三','程敦厚','宋','宋诗','song-poetry','','[]','牆頭荔子已爛斑。',8,'全唐诗/poet.song.115000.json','["牆頭荔子已爛斑。"]'),
('0dc86bba-4c88-4ff1-b46e-9ee3fc00af23','句  其四','程敦厚','宋','宋诗','song-poetry','','[]','綠幄紫籠文縠皺，絳囊包就寸珠圓。',16,'全唐诗/poet.song.115000.json','["綠幄紫籠文縠皺，絳囊包就寸珠圓。"]'),
('6aa88e61-66e7-415b-b04b-aa62e7d995bf','句  其五','程敦厚','宋','宋诗','song-poetry','','[]','味重带新馳驛貢，花旌難老隔年芳。',16,'全唐诗/poet.song.115000.json','["味重带新馳驛貢，花旌難老隔年芳。"]'),
('6d78c36d-0657-449b-b560-9cc31b21d8da','句  其六','程敦厚','宋','宋诗','song-poetry','','[]','春飛白玉花，秋吐黄金實。',12,'全唐诗/poet.song.115000.json','["春飛白玉花，秋吐黄金實。"]'),
('e25d5b31-da53-48dc-9732-9774d0504251','句  其七','程敦厚','宋','宋诗','song-poetry','','[]','香散風前麝，漿寒霜後蜜。',12,'全唐诗/poet.song.115000.json','["香散風前麝，漿寒霜後蜜。"]'),
('e0c2f78b-16e3-47b5-ab68-84ce93be6182','句  其八','程敦厚','宋','宋诗','song-poetry','','[]','粲粲核中仁，尚可瀹奇茗。',12,'全唐诗/poet.song.115000.json','["粲粲核中仁，尚可瀹奇茗。"]'),
('d8d079e7-6572-44f7-b5d1-da355f121999','句  其九','程敦厚','宋','宋诗','song-poetry','','[]','孤出亭亭羽蓋高，撐開圓葉臂抽條。',16,'全唐诗/poet.song.115000.json','["孤出亭亭羽蓋高，撐開圓葉臂抽條。"]'),
('52279b86-d049-4e72-b977-ca95c027da34','句  其一○','程敦厚','宋','宋诗','song-poetry','','[]','纛影叱㲚竿影直，雪中霜裏伴松筠。',16,'全唐诗/poet.song.115000.json','["纛影叱㲚竿影直，雪中霜裏伴松筠。"]'),
('f76232eb-7215-4c84-bd3c-94f7d847be09','新安採樵行','沈作喆','宋','宋诗','song-poetry','','[]','種粟上山椒，種禾水沒腰。',92,'全唐诗/poet.song.115000.json','["種粟上山椒，種禾水沒腰。", "田家作苦不如樵，炊桂之地甚不遥。", "一艘千束莫復朝，順風順水不動橈。", "歸來醉飽吹短簫，野花插鬢樵女嬌。", "農夫忍饑自芸苗，粟米自熟腹自枵。", "明年賣田賣山去，誰能辛苦輸王賦。"]'),
('610727e8-6f3b-4601-ad95-f88c6f1be3fd','哀扇工歌','沈作喆','宋','宋诗','song-poetry','','[]','某州竹扇名字著，織扇供官困追捕。',256,'全唐诗/poet.song.115000.json','["某州竹扇名字著，織扇供官困追捕。", "使君開府未浹旬，欲戴綸巾揮白羽。", "新模巧製旋剪裁，百中無一中程度。", "犀革鎸柄出蟲魚，麝煤熏紙生煙霧。", "蕺山老姥羞翰墨，漢宮佳人掩紈素。", "衙內白取知何名，帳下雄拏不知數。", "供輸不辦箠楚頻，一朝赴水將誰訴。", "使君崇重了不聞，嗚呼何以慰黎庶。", "聞道園家賣菜翁，又說江頭打魚戶。", "號令亟下須所無，官不與錢期限遽。", "歸來痛哭辭妻兒，宿昔投繯挂枯樹。", "一雙婉婉良家子，吏兵奪取名爲顧。", "弟兄號叫鄰里驚，兩家吞聲喪其嫗。", "死者已矣可奈何，冤魂成羣空號呼。", "殺人縱欲勢位尊，貪殘無道天所怒。", "邦人蓄憤不敢言，君其拊馬章臺路。"]'),
('7a25ab8b-543c-48c6-a471-a585ecd8b5af','馬上吟','湯莘叟','宋','宋诗','song-poetry','','[]','宿雨洗山新綠嫩，曉風吹杏淺紅乾。',32,'全唐诗/poet.song.115000.json','["宿雨洗山新綠嫩，曉風吹杏淺紅乾。", "沙頭路暖日欲上，行客揚鞭不覺難。"]'),
('fccd3bbd-48c8-4862-8855-d35ec5830403','題舫齋','湯莘叟','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','誰人能使陸行舟，涉水寧無險覆憂。',64,'全唐诗/poet.song.115000.json','["誰人能使陸行舟，涉水寧無險覆憂。", "日照簷楹帆影動，風摇窗戶櫓聲柔。", "夢回渭水清新句，歌罷浯溪欵乃愁。", "更看霜天晴夜月，幌然如過洞庭秋。"]'),
('ac98545c-1c8d-4051-9382-31a021f0c938','登宜春臺','湯莘叟','宋','宋诗','song-poetry','','[]','草徑無邊綠，江空見底清。',48,'全唐诗/poet.song.115000.json','["草徑無邊綠，江空見底清。", "遥峰橫晚色，古木自秋聲。", "客舍孤雲遠，鄉心一雁鳴。", "憑高寄吳楚，倚杖獨含情。"]'),
('5adaba4a-90bc-44f9-a4a9-ed020eaea8a6','句','湯莘叟','宋','宋诗','song-poetry','','[]','葛巾簪下無多髮，茅舍門前有好山。',16,'全唐诗/poet.song.115000.json','["葛巾簪下無多髮，茅舍門前有好山。"]'),
('46d99caf-bdfe-4281-9867-cb21647a657a','弔屈原','黄熙','宋','宋诗','song-poetry','','[]','放逐臣之常，胡爲乎汨江。',24,'全唐诗/poet.song.115000.json','["放逐臣之常，胡爲乎汨江。", "不先於楚死，未免作秦降。"]'),
('4a72a644-6350-408c-8cd0-c61640d2ba1b','送友至飛雲渡','林亮功','宋','宋诗','song-poetry','','[]','五里風濤路，人烟隔岸洲。',48,'全唐诗/poet.song.115000.json','["五里風濤路，人烟隔岸洲。", "去帆欹綠水，別棹會中流。", "西峴鐘聲曉，東山塔影浮。", "何人有機事，驚起一沙鷗。"]'),
('dd377c1a-fdc3-41af-89d1-4bf7b8d91f0d','句','林大鼐','宋','宋诗','song-poetry','','[]','日移花影上簾鈎。',8,'全唐诗/poet.song.115000.json','["日移花影上簾鈎。"]'),
('661a4f9f-9014-4b47-829d-0b242d20ddb7','遊鳴山','林芘','宋','宋诗','song-poetry','','[]','杏花舞徑亂紅雨，麥浪漲空摇翠煙。',32,'全唐诗/poet.song.115000.json','["杏花舞徑亂紅雨，麥浪漲空摇翠煙。", "十里清風尋小寺，快船如馬水如天。"]'),
('92ecf408-938e-4c25-8a1a-d2a9ca82df0d','觀潮閣','林芘','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江山不受範，偃蹇散莫收。',96,'全唐诗/poet.song.115000.json','["江山不受範，偃蹇散莫收。", "領略得要會，聚此百尺樓。", "霽色明千峰，斜陽带歸舟。", "堪洗北客塵，似脫南冠囚。", "二子倚秋晚，岸巾送明眸。", "杯寒風景切，句落雲煙愁。", "况我江海人，二頃亦易秋。", "百年鷗盟在，脫幘行當休。"]'),
('90ef8305-acfa-47b4-861c-64464806004c','蒙齋','劉藻','宋','宋诗','song-poetry','','[]','蒙齋遠廛市，勝概幾多清。',48,'全唐诗/poet.song.115000.json','["蒙齋遠廛市，勝概幾多清。", "山下一泉湧，望中千畝平。", "林深俗客少，巖小曉煙輕。", "杖屨從登眺，誰知有利名。"]'),
('b85ac0de-7cb8-4a6a-9485-d38eb0cbb851','柱笏軒','周操','宋','宋诗','song-poetry','','[]','未偶凶渠那便擊，已逢昭代不須還。',32,'全唐诗/poet.song.115000.json','["未偶凶渠那便擊，已逢昭代不須還。", "子猷老去身無用，拄頰朝來穩看山。"]'),
('8232b68c-ac02-448f-af85-c4ba932cc6b5','和潘良貴題明州三江亭韻','鄭若谷','宋','宋诗','song-poetry','','[]','望遠登高萬象侵，元戎端不爲花尋。',64,'全唐诗/poet.song.115000.json','["望遠登高萬象侵，元戎端不爲花尋。", "未誇駕鶴蓬山路，應壯斬鯨遼海心。", "小艇鱸肥盤膾玉，危欄客醉椀揮金。", "中流擊楫雄圖遠，回笑三閭澤畔吟。"]'),
('6642c6ef-fd2b-4118-a557-a23b58fc3491','澹巗','謝用賓','宋','宋诗','song-poetry','','[]','雲山野客，家在浯溪。',20,'全唐诗/poet.song.115000.json','["雲山野客，家在浯溪。", "乘風而來，泛月而歸。"]'),
('2411cf52-dcb0-444f-bfca-8a08038fcf1a','登䂬溪仙人巗','鄭厚','宋','宋诗','song-poetry','','[]','短帽依然九日風，巖頭的的問仙翁。',32,'全唐诗/poet.song.115000.json','["短帽依然九日風，巖頭的的問仙翁。", "神仙料不私將橘，乞與陳黄方薛公。"]'),
('b313c612-e48f-419e-aa81-a24691c54ae1','寒食登韓亭','鄭厚','宋','宋诗','song-poetry','','[]','燔身介子意何忙，理迹昌黎道更光。',64,'全唐诗/poet.song.115000.json','["燔身介子意何忙，理迹昌黎道更光。", "慷慨一封論佛骨，流離萬里入蠻鄉。", "孤芳亭角留韓木，遺愛人心比召棠。", "勿謂筆端無造化，如何祛鰐似祛羊。"]'),
('c25ebd9f-fbe4-4c17-b9f4-dfe9d3031a72','登東山','鄭厚','宋','宋诗','song-poetry','','[]','小雨上東山，層層着意看。',48,'全唐诗/poet.song.115000.json','["小雨上東山，層層着意看。", "尋泉行處僻，就石坐來寒。", "赤舄歸周旦，蒼生起謝安。", "功能成底事，一抹暮雲殘。"]'),
('ce54f5c3-6418-4c13-b2ba-f38761b01b7e','林和靖墓','鄭厚','宋','宋诗','song-poetry','','[]','山前山後冢纍纍，處士孤墳沒草萊。',64,'全唐诗/poet.song.115000.json','["山前山後冢纍纍，處士孤墳沒草萊。", "古宅更遭新燒火，荒林難覓舊栽梅。", "月香水影詩空好，鶴怨猿驚客共哀。", "回首西泠橋外寺，晚來金碧擁樓臺。"]'),
('cbdbdf5c-3770-493e-af3d-78b5d34c8960','楚塞亭','陳柏年','宋','宋诗','song-poetry','','[]','舟行三峽亂峯間，雪浪如山毛骨寒。',32,'全唐诗/poet.song.115000.json','["舟行三峽亂峯間，雪浪如山毛骨寒。", "一帆喜見楚天闊，回首長吁蜀地難。"]'),
('09ec572d-fb1e-48bc-bef6-06cd81da94a6','句','陸彥遠','宋','宋诗','song-poetry','','[]','雖貧未肯氣如霄。',8,'全唐诗/poet.song.115000.json','["雖貧未肯氣如霄。"]'),
('4bf8ebc9-7f75-4b60-ae04-2b36006b50e4','上衆官','鄭廣','宋','宋诗','song-poetry','','[]','鄭廣有詩上衆官，文武看來總一般。',32,'全唐诗/poet.song.115000.json','["鄭廣有詩上衆官，文武看來總一般。", "衆官做官却做賊，鄭廣做賊却做官。"]'),
('60b4dc18-4bf2-46c1-b1e7-0a75dd02c242','楚塞樓','劉長源','宋','宋诗','song-poetry','','[]','出峽朝天第一州，使君重敞最高樓。',32,'全唐诗/poet.song.115000.json','["出峽朝天第一州，使君重敞最高樓。", "蜀江雪浪初平處，楚國金城欲盡頭。"]'),
('d95fffb1-154d-4266-8beb-8aa1e970302a','楚萍歌','彭大年','宋','宋诗','song-poetry','','[]','雲夢青丘蟠楚藪，萍實江邊大如斗。',96,'全唐诗/poet.song.115000.json','["雲夢青丘蟠楚藪，萍實江邊大如斗。", "故壘摧頹百戰餘，舊事流傳千載後。", "青崖半裂玄猿吼，空坡突過黄狐走。", "山深落日少人行，寂寞鳴蜩在高柳。", "湖江入夢倏三年，慰我漂零一杯酒。", "群盜雖降漢赤眉，故侯慣作秦黔首。"]'),
('d42a9658-9bf8-4fec-9468-1f786e62cb9c','題上封寺','胡宏','宋','宋诗','song-poetry','','[]','百年身似客，浩蕩世間遊。',216,'全唐诗/poet.song.115000.json','["百年身似客，浩蕩世間遊。", "入望青山好，夢魂偏我留。", "我家巫山十二峰，浮江直過巴陵東。", "瀟湘水與蒼梧通，環繞衡嶽青冥中。", "扁舟白雲不可度，杖藜蠟屐乘春風。", "山光浮動可攬結，雲舒霞卷飛煙虹。", "深巖大壑翠巘列，足力已到心無窮。", "羣峰迤邐勢不競，上盡祝融五千仞。", "祝融峯高天更高，太空人世如牛毛。", "風雲萬變一瞬息，紅塵奔走真徒勞。", "蓬萊羽化慕神仙，神仙渺茫何處傳。", "雪山清浄問因緣，未識乾坤造化權。", "獨立高寒明月裏，此心無著已怡然。", "從今識盡青山好，歸向人間別看天。"]'),
('9a408996-09fa-4d0d-b086-4d4f29c2f4c4','送友人歸荆南','胡宏','宋','宋诗','song-poetry','','[]','瞬息光陰便百年，壯時無謂此身堅。',256,'全唐诗/poet.song.115000.json','["瞬息光陰便百年，壯時無謂此身堅。", "莫隨白日悠悠去，要見先民的的傳。", "心耻文俳似班馬，眼看青紫自頭旋。", "望雲飛鳥長天外，臨水不知魚在筌。", "沈吟巖野意不展，燮理一身居屢遷。", "願學只知依孔聖，懶從禪客問因緣。", "聖門子貢最明達，肯使宮牆但及肩。", "天生我才樸更拙，未逢良匠入雕鎸。", "清漳見公二十載，論仁一句期超然。", "致知兩字足功力，方信能行窮化先。", "南山文會未振起，公今遠去岷江邊。", "聞說豺狼卧當路，日向黄昏休更前。", "況復江城動鼙鼓，四時烽火長相連。", "征輪决去曳不止，男兒性命絕可憐。", "曉月子規驚別夢，冥冥空有淚痕濺。", "臨岐相贈要切語，慎勿使我空華顛。"]'),
('c37c45f1-dbdc-4bbd-9baa-7bce55951536','簡彪漢明','胡宏','宋','宋诗','song-poetry','','[]','斯文久寥落，我欲問蒼天。',192,'全唐诗/poet.song.115000.json','["斯文久寥落，我欲問蒼天。", "蒼天默無言，復欲問古先。", "古先羣聖人，去我三千年。", "紛紛儒林士，章句以爲賢。", "問之性命理，醉夢俱茫然。", "皓月隠重雲，明珠媚深淵。", "近得程夫子，一綫通天泉。", "蕩滌浄塵垢，逸駕真無前。", "自從喪亂來，鼙鼓聲闐闐。", "日事干戈末，那尋孔孟傳。", "湘中彪夫子，有志窮益堅。", "讀書文字表，至善時一遷。", "老去不自止，直欲求純全。", "問我曾點意，乘風舞雩顛。", "行年付造化，笑問青銅錢。", "默契天地心，誰能泥青編。"]'),
('0b8f9404-20aa-4dbe-be28-00eef1be7ba1','西林寺廓然堂有懷','胡宏','宋','宋诗','song-poetry','','[]','超然峰頭秋氣清，廓然堂延秋月明。',108,'全唐诗/poet.song.115000.json','["超然峰頭秋氣清，廓然堂延秋月明。", "我乘清秋弄秋月，中有所感思冥冥。", "峰勢凌蒼穹，上有烟林封。", "去天不盈尺，路斷心忡忡。", "堂空人何在，澹然思無窮。", "寂寂本心流太空，虛名過耳如松風，惆悵禍亂波流洪。", "目極征鴻淡淡天，萬古消沉向此中。"]'),
('57cff039-5cb3-4cdd-9c41-a3d79e8da914','和江子玉二首  其一','胡宏','宋','宋诗','song-poetry','','[]','無奇試學居盤谷，誰信斷絃膠可續。',112,'全唐诗/poet.song.115000.json','["無奇試學居盤谷，誰信斷絃膠可續。", "湘天冷落數家村，曩時曾枉旌麾沐。", "潺湲階下碧溪橫，柳靜風微幽意足。", "知君文武濟時才，舊時軍律寒生粟。", "文書脫畧是人師，應有魏昭能換粥。", "我無真樂送芳年，悵望顔回屢空腹。", "凄凉指日秋風高，願更同來寫心曲。"]'),
('d7658d9e-3380-492a-ac11-a4ff2ad6d995','和江子玉二首  其二','胡宏','宋','宋诗','song-poetry','','[]','白駒皎皎來空谷，希聲絕世人難續。',112,'全唐诗/poet.song.115000.json','["白駒皎皎來空谷，希聲絕世人難續。", "異端蠭起亂羣風，擺脫敝衣聊一沐。", "悠然良夜得酣寢，覺來無欠亦無足。", "不蹈紅塵陌上花，自種青雲隴頭粟。", "嗚呼夫子大聖人，七日藜羹食無粥。", "休爭得失等雞蟲，克己樂善充身腹。", "風雲變化會有時，微吟袖手清溪曲。"]'),
('c3d7ee32-33c5-4113-b3d1-b0d9232c72ce','圃景大吟呈伯氏','胡宏','宋','宋诗','song-poetry','','[]','青鞋黄帽侵晨起，杖策徐行聽流水。',144,'全唐诗/poet.song.115000.json','["青鞋黄帽侵晨起，杖策徐行聽流水。", "雲輕淡月欲明時，竹裏清風開太始。", "山鐘間發催天曙，廟鼓連聲動羣耳。", "東山青樹映霞明，西嶺朱樓眇烟裏。", "樵夫荷斧晨出山，漁子携魚午趨市。", "靜看岐路人營營，獨坐小亭秋靡靡。", "已知物理時常改，因見天工神不死。", "胸中浩蕩一乾坤，世上榮枯均泰否。", "悠然種植得佳趣，春意生生自無已。"]'),
('42b8b720-f430-486a-9d14-1b4dcf4033da','寄題向伯元敦止堂','胡宏','宋','宋诗','song-poetry','','[]','君不聞伊摯初耕有莘野，祿之弗顧千駟馬。',278,'全唐诗/poet.song.115000.json','["君不聞伊摯初耕有莘野，祿之弗顧千駟馬。", "春作秋成隨老農，貧賤甘心萬人下。", "一朝幡然感三聘，五就成湯五就夏。", "悠悠如雲行太空，竟使三風變爲雅。", "東西南北頼來蘇，天下農夫誰似者。", "又不聞傅說安身操板築，遠離世間名與祿。", "那知商帝夢中形，遠近搜求不容伏。", "草茅夕起朝爲相，俾后從繩正如木。", "四海俊乂咸風從，跋扈諸侯盡臣僕。", "功成止見顔容改，了了壯心無反覆。", "平生懶性願退藏，退藏恐遂成荒唐。", "因求古人作鑑戒，管寧華歆情所當。", "齊名遯迹俱鋤菜，擲之不顧爲人量。", "詩書俎豆化遼海，威武富貴何披猖。", "初年虛名大可耻，末路高風紓思長。", "有志君當學伊傅，忘情我不傲羲皇。", "願如幼安有終始，進退一致宜加詳。"]'),
('88e680c4-473f-4341-ab4a-4e0eb4e010c6','雲月','胡宏','宋','宋诗','song-poetry','','[]','朝看南山雲，暮看西山月。',48,'全唐诗/poet.song.115000.json','["朝看南山雲，暮看西山月。", "雲物時有無，月魄遞盈闕。", "月明雲昭章，雲散月奇絕。", "屈伸至理中，莫道吾生拙。"]'),
('d33ed768-5875-4add-8e6d-fd41531277af','南山即事','胡宏','宋','宋诗','song-poetry','','[]','南山崇崇幾千丈，今晨忽被蠻烟蜑霧埋其高。',53,'全唐诗/poet.song.115000.json','["南山崇崇幾千丈，今晨忽被蠻烟蜑霧埋其高。", "安得萬里飄風一吹散，見巍峩蒼翠解我心鬰陶。", "鬰陶心匪他，爲愛南山高。"]'),
('0caeb5ec-aacc-46a3-a2e3-0a66d96d9b75','題楊氏猗猗閣  其一','胡宏','宋','宋诗','song-poetry','','[]','望處積雲深，妙見此君心。',80,'全唐诗/poet.song.115000.json','["望處積雲深，妙見此君心。", "中虛抱元氣，不受一塵侵。", "嗟哉人生逐利名，雞犬放去猶知尋。", "我愛坐君閣，游戲猗猗林。", "明月照我懷，清風吹我襟。", "消磨胸中沈著病，無愧衛武生于今。"]'),
('6dd1bd80-a99e-4229-a649-1a4d6e3304da','題楊氏猗猗閣  其二','胡宏','宋','宋诗','song-poetry','','[]','林生何猗猗，挺立似豪傑。',64,'全唐诗/poet.song.115000.json','["林生何猗猗，挺立似豪傑。", "新稍一直上青冥，本末便與春風徹。", "嗟哉流俗人，交義隨情决。", "寒霜落千山，我愛此君節。", "眷焉題閣心，萬變不磨滅。"]'),
('f1435e6e-5050-4486-8220-afb07109a2cd','蒼天','胡宏','宋','宋诗','song-poetry','','[]','蒼天映清水，下見白雲飛。',48,'全唐诗/poet.song.115000.json','["蒼天映清水，下見白雲飛。", "天水從何來，飛雲更何依。", "人生亦如此，融結中有機。", "此機即天命，吾心端不違。"]'),
('7d7adb8c-75b3-4b73-8604-1457197fc840','碧泉興作即事有感因續魏武之詩','胡宏','宋','宋诗','song-poetry','','[]','對酒當歌，人生幾何。',60,'全唐诗/poet.song.115000.json','["對酒當歌，人生幾何。", "往者如江，來者如何。", "往來無盡，弗移弗那。", "奉身理物，何少何多。", "天長地久，我生靡它。", "樂此泉兮，于山之阿。"]'),
('d588feb7-2562-4ff8-962c-3c43e304c4f8','題談氏濯纓亭','胡宏','宋','宋诗','song-poetry','','[]','茶陵水似滄浪清，我行征驂登小亭。',64,'全唐诗/poet.song.115000.json','["茶陵水似滄浪清，我行征驂登小亭。", "孔聖去矣不可見，野人有歌誰復聽。", "孟子能推孔聖心，寥寥斯意有誰尋。", "中原可惜無人問，此日聊爲梁父吟。"]'),
('177bfebd-60fc-4d71-965e-2dda48be303e','觀建安七子詩','胡宏','宋','宋诗','song-poetry','','[]','作文發妙理，經國厲遠圖。',156,'全唐诗/poet.song.115000.json','["作文發妙理，經國厲遠圖。", "游目建安中，才子足歡娛。", "王劉與應阮，精神可交輸。", "西南落漢日，揚益奮兩隅。", "山河裂地軸，星象分天衢。", "八師遇有姚，萬世垂楷模。", "一元均大化，五服擁皇都。", "悠悠彼七子，流光失其孚。", "飛觴宴婉孌，鼓瑟吹笙竽。", "主人敬愛客，徒爾相揚揄。", "魏祚竟不長，詒謀止斯須。", "逡巡數十年，劉石橫八區。", "所以漢高帝，慢駡輕文儒。"]'),
('889e5cca-5561-40b2-a4d8-9606e54dd0ab','小圃將成','胡宏','宋','宋诗','song-poetry','','["\u8861\u5c71"]','我愛青山好，衡山鎮南極。',188,'全唐诗/poet.song.115000.json','["我愛青山好，衡山鎮南極。", "連峰疊翠西池西，五峰新亭面相直。", "喬嶽崢嶸天地中，飄零身寄衡山側。", "衡山之峰七十二，奔走芙蓉盡供職。", "紫蓋峰頭走日東，不朝芙蓉理莫測。", "芙蓉峰巔栖白鶴，今人不見雙飛翼。", "應是赤霄隨鳳遊，遠向青田謀雁食。", "逍遥九皋鳴聞天，奇蹤只許羣仙識。", "平生苦無適俗韵，置身大禹巡方域。", "雲舒烟卷試懷抱，月下風前得消息。", "四時有酒兼有花，百年無喪亦無得。", "儘教人作畫圖傳，杖藜見我看山色。"]'),
('102b6ef9-4c3e-44dc-857f-cdf1ac0f127b','送璉老','胡宏','宋','宋诗','song-poetry','','[]','湘中應中古道場，復有峩眉道人住。',144,'全唐诗/poet.song.115000.json','["湘中應中古道場，復有峩眉道人住。", "昔日三生藏裏來，今朝十二峰前去。", "杖錫飄然別故人，笑望梅花理征路。", "我曾問公五宗派，電掃羣生小見解。", "直指萬法無盡身，坐覺靈光滿沙界。", "辨舌橫放傾天河，崢嶸整頓禪宗壞。", "吁嗟我生在儒門，儒門大業無人論。", "滔滔姑想天之下，衣冠滿目如雲屯。", "焚香再拜願聖主，一統三教清乾坤。"]'),
('5e5aaebb-7933-4484-9bb0-382098a456a4','水心亭','胡宏','宋','宋诗','song-poetry','','["\u8861\u5c71"]','水從靈澗來，清泚不可汚。',180,'全唐诗/poet.song.115000.json','["水從靈澗來，清泚不可汚。", "經過我亭下，妙見涓涓處。", "見處事如何，欲說豈無路。", "百丈生潮頭，一勺本性具。", "經紀大地間，形勢中國著。", "江漢荆襄望，河渭關洛固。", "衡山折底柱，觸石堆灧澦。", "沄沄三千丈，瀁瀁四海布。", "豈有不巖阻，盈科演然去。", "豈有不隄防，潤下渙無住。", "畇畇青山田，渺渺均𣼩注。", "蕩蕩白虹舟，飄颺任奔翥。", "來者無終窮，濟者無量數。", "周流造化功，妙體不競愫。", "寄語觀水人，事不在章句。"]'),
('1deb7c65-4a78-4bd1-9d14-5548b1c916d2','同伯氏還鄉','胡宏','宋','宋诗','song-poetry','','[]','江村沙暖蔞蒿長，味比枸杞新甘香。',80,'全唐诗/poet.song.115000.json','["江村沙暖蔞蒿長，味比枸杞新甘香。", "茁茁荻芽生近渚，紫花臺萊初未嘗。", "白羊烏牀俱在牧，茅舍竹籬是故鄉。", "人生未必須富貴，萬里且願身康强。", "徑買官場舊醅酒，共醉春風殊未央。"]'),
('c78308a3-3956-4f1a-8d22-456085886339','桃源行','胡宏','宋','宋诗','song-poetry','','[]','北歸已過沅湘渡，騎馬東風武陵路。',260,'全唐诗/poet.song.115000.json','["北歸已過沅湘渡，騎馬東風武陵路。", "山花無限不關心，惟愛桃花古來樹。", "聞說桃花更有源，居人共得仙家趣。", "之子漁舟安在哉，我欲乘之望源去。", "江頭相逢老漁父，煙水蒼蒼雲日暮。", "投竿拱手向我言，桃源之說非真然。", "當時漁子漁得錢，買酒醉卧桃花邊。", "桃花風吹入夢裏，自有人世相周旋。", "酒醒驚怪告儔侶，遠近接響俱相傳。", "靖節先生絕世人，奈何記僞不考真。", "先生高步宭末代，雅志不肯爲秦民。", "故作斯文寫幽意，要似寰海雜風塵。", "不然川原遠近蒸霞開，宜有一片隨水從東來。", "嗚呼神明通八極，豈特秘爾桃源哉。", "我聞是言發深省，勒馬却辭漁父回。", "及晨徧覽三春色，莫便風雨空莓苔。"]'),
('f7497c78-88a3-493b-a4a3-1af605ee16ec','獨坐','胡宏','宋','宋诗','song-poetry','','["\u8861\u5c71"]','卜居幽勝衡山繞，五峯西望青冥杳。',64,'全唐诗/poet.song.115000.json','["卜居幽勝衡山繞，五峯西望青冥杳。", "乍聚乍散看浮雲，時去時來送飛鳥。", "卷舒自在都無情，飲啄天然類不擾。", "我生何似鳥與雲，掉頭心向人間了。"]'),
('e8ca6051-cba4-498f-bc99-facb69111dad','梅花呈孫奇父諸公','胡宏','宋','宋诗','song-poetry','','[]','萬里春回過短牆，孤標亦似殿年芳。',64,'全唐诗/poet.song.115000.json','["萬里春回過短牆，孤標亦似殿年芳。", "蕭疎月下天然瘦，澹宕風前自在香。", "寒色重時花正發，暖烟纔禁實先嘗。", "越人不向梁臺路，畫角一聲堪斷腸。"]'),
('1705d8f2-707f-4fd9-99ee-696af06c531b','題友人養素軒','胡宏','宋','宋诗','song-poetry','','[]','少時情意在滄洲，壯歲還知學孔丘。',64,'全唐诗/poet.song.115000.json','["少時情意在滄洲，壯歲還知學孔丘。", "萬事只嫌心有病，百年不作夢中遊。", "紫泥詔下人須在，黄卷人開我自收。", "耻向紅塵浪奔走，看雲消盡意橫秋。"]'),
('608bac64-c8a3-4e54-8fee-9e9f6888d180','春日郊行','胡宏','宋','宋诗','song-poetry','','[]','東郊野馬爛氛氳，聊駕柴車問訊春。',64,'全唐诗/poet.song.115000.json','["東郊野馬爛氛氳，聊駕柴車問訊春。", "遠草綠沉煙霧裏，高花紅照綺羅新。", "迎風柳占鶑啼處，带雨泥融燕觜勻。", "動植自私還自足，天邊愁殺踏青人。"]'),
('b87ed8b2-8088-410e-bf69-8810e507e9ac','和韓叔夏碧泉','胡宏','宋','宋诗','song-poetry','','[]','靈源一派似河傾，隠映長天萬古情。',64,'全唐诗/poet.song.115000.json','["靈源一派似河傾，隠映長天萬古情。", "林影淡摇秋月冷，澗翻先凝玉壺清。", "舊栽沿岸柳陰合，新種數株梅子成。", "誰引人來問消息，只緣山外有流聲。"]'),
('d9149d93-42fa-415b-aa8b-adf111abcb0a','題法輪寺','胡宏','宋','宋诗','song-poetry','','[]','春色初收夏氣清，路分松檜入崢嶸。',64,'全唐诗/poet.song.115000.json','["春色初收夏氣清，路分松檜入崢嶸。", "深盤岣嶁千峯下，遠抱瀟湘一綫明。", "大衆總迷身在處，三關除却道方平。", "山林若是有情住，何異紅塵爭利名。"]'),
('77a2b9b6-f395-452d-8d3b-dbd65a7635cc','郭氏嘉山亭','胡宏','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山何似洛城居，不久從來亦不餘。',64,'全唐诗/poet.song.115000.json','["衡山何似洛城居，不久從來亦不餘。", "赤縣人希舊勛業，清閒身自富時書。", "搜羅神化觀周易，略去玄黄陋太初。", "最是忘機湘水上，風輕日淡看游魚。"]'),
('7040fa3b-5d1b-4d47-a728-a3731508a7c8','湘中館','胡宏','宋','宋诗','song-poetry','','[]','館瞰瀟湘畫不成，波瀾入海是通津。',64,'全唐诗/poet.song.115000.json','["館瞰瀟湘畫不成，波瀾入海是通津。", "風吹枕席清無夢，煙覆江城曉變春。", "柳色幾回輕別首，梅花偏見遠征人。", "誰能不逐紅塵去，到處分明認得身。"]'),
('5a52fc00-179a-4ce2-95c2-1081355ab654','和范公授','胡宏','宋','宋诗','song-poetry','','[]','貧病離居莫厭侵，滿牀黄卷靜披尋。',64,'全唐诗/poet.song.115000.json','["貧病離居莫厭侵，滿牀黄卷靜披尋。", "情通不礙天機妙，行到方知學海深。", "宇宙一身雖小小，乾坤萬象總森森。", "分明此意人難會，長望青衿肯嗣音。"]'),
('b95a71bd-5eb3-46e6-b9d9-7e87b7d1b443','紫蓋峯前作小圃日親圃事情見乎辭呈伯氏兼簡彥達先生','胡宏','宋','宋诗','song-poetry','','[]','有志從來不浪憂，只憂心不似前脩。',64,'全唐诗/poet.song.115000.json','["有志從來不浪憂，只憂心不似前脩。", "敷菑未竟已頭白，待穫忘情在晚秋。", "自覺才疎勝北海，又無經學震西州。", "甘爲稼圃南山下，長謝周公愧孔丘。"]'),
('3b131d5c-462f-453a-a3a3-72dad929bfa5','和伯氏','胡宏','宋','宋诗','song-poetry','','[]','爲園非是學樊須，鋤罷歸來又讀書。',64,'全唐诗/poet.song.115000.json','["爲園非是學樊須，鋤罷歸來又讀書。", "董子不窺緣底事，陶公成趣愛吾廬。", "華枝瘦日應抬舉，草色回春莫剗除。", "長遣箇中消息在，此生何處不安居。"]'),
('84ff260b-b3ab-4d17-b76f-f7464b828b08','水石','胡宏','宋','宋诗','song-poetry','','[]','水石平生性所便，栽花種柳亦天然。',64,'全唐诗/poet.song.115000.json','["水石平生性所便，栽花種柳亦天然。", "春風花發遊人見，秋月雲收照我員。", "玩意隴雲情自逸，放懷天理道無偏。", "坐消白日千峯下，長嘯一聲箕斗邊。"]'),
('f4741240-ea9a-4af2-82e5-123e385aacd3','碧泉九日有感  其一','胡宏','宋','宋诗','song-poetry','','[]','祝融地勢東南俯，西北星辰拱漢關。',64,'全唐诗/poet.song.115000.json','["祝融地勢東南俯，西北星辰拱漢關。", "冷落山河憑玉几，凋殘名物損朱顔。", "西風凜凜鵬空摶，朔雪飄飄雁亦寒。", "正恐中原消息斷，問誰曾到五陵間。"]'),
('22b6a570-e38d-4373-add2-8a9de39236f7','碧泉九日有感  其二','胡宏','宋','宋诗','song-poetry','','[]','雲日韜光山水幽，亭亭風送雁來秋。',64,'全唐诗/poet.song.115000.json','["雲日韜光山水幽，亭亭風送雁來秋。", "當時祓禊千華好，今日登臨萬葉愁。", "刻蠟桂香環遠路，縷金蓮色亂方舟。", "丹青妙處身知在，不作浮鷗信浪流。"]'),
('1a977681-258d-4a47-8d24-5a05eb79acda','吳承遠譏登山','胡宏','宋','宋诗','song-poetry','','[]','胸中無滯是神仙，行止由來各有天。',64,'全唐诗/poet.song.115000.json','["胸中無滯是神仙，行止由來各有天。", "洞裏道人心快快，雲間遊子自翩翩。", "塵懷已逐山風掃，好意都從梅蕊傳。", "回首七香車上客，大家歸去莫流連。"]'),
('c6dea9a0-f306-40f0-a698-4d897c77896b','和王師中  其一','胡宏','宋','宋诗','song-poetry','','[]','誰驚河凍履秋霜，今日金湯古壞牆。',64,'全唐诗/poet.song.115000.json','["誰驚河凍履秋霜，今日金湯古壞牆。", "未見主人來北道，但聞羣盜去南塘。", "憂時我不嗟留滯，訪道公能適莽蒼。", "絳帳早移收歲晚，吟風弄月動衡湘。"]'),
('9d025b7a-9e6d-4ef7-97fd-c37fb0187e49','和王師中  其二','胡宏','宋','宋诗','song-poetry','','[]','衡陽一带飛清霜，梅李爭春開出牆。',64,'全唐诗/poet.song.115000.json','["衡陽一带飛清霜，梅李爭春開出牆。", "萱草亂生封遠岸，柳梢摇影澹回塘。", "午從三徑春光動，晚看千峰冥色蒼。", "一止一行皆自得，憤時堪笑屈沉湘。"]'),
('5a8ecbfa-2de5-4df2-b23e-e915b088b39d','和王師中  其三','胡宏','宋','宋诗','song-poetry','','[]','歲寒孤節厲冰霜，汲古門開數仞牆。',64,'全唐诗/poet.song.115000.json','["歲寒孤節厲冰霜，汲古門開數仞牆。", "朔塞烟雲封赤縣，陽關盃酒絕青塘。", "無才空自憂當世，不宰應難怨彼蒼。", "獨坐獨行求伴侶，澗蒪山蕨願同湘。"]'),
('34625491-34d6-4de8-ac20-a29cb0da0f9a','和人','胡宏','宋','宋诗','song-poetry','','[]','天柱新詩缺嗣音，幾回開卷靜披尋。',64,'全唐诗/poet.song.115000.json','["天柱新詩缺嗣音，幾回開卷靜披尋。", "眇綿今古乾坤大，盤亙華夷海岳深。", "每愛躊躇興事意，不將勉强會天心。", "中原未必生涯盡，只恐吾人老自侵。"]'),
('d5d8f10b-81d2-4dbb-b95a-f2051aa7055e','謁虞帝祠','胡宏','宋','宋诗','song-poetry','','[]','有姚心妙賛乾坤，堯禹興亡頼兩存。',64,'全唐诗/poet.song.115000.json','["有姚心妙賛乾坤，堯禹興亡頼兩存。", "蒲坂舊都西望遠，蒼梧陳迹事難論。", "九官效職羣英聚，二女宜家聖德尊。", "萬代君王模範表，吁嗟一廟破荒村。"]'),
('508dd1a0-fb7b-46fb-a714-eae264534fc7','別吳衛道','胡宏','宋','宋诗','song-poetry','','[]','學業應須見本根，語言無用苦評論。',64,'全唐诗/poet.song.115000.json','["學業應須見本根，語言無用苦評論。", "醇醪自昔懷公瑾，藥石誰今識孟孫。", "憑仗嬉遊試功力，隄防色厲却淫昏。", "臨岐大愧無相贈，聊寫蕪詞示法門。"]'),
('c0476aec-fae4-4f3f-8c21-d8d18f60dfac','別全當可','胡宏','宋','宋诗','song-poetry','','[]','一別賢關二十年，人間萬事儘悠然。',64,'全唐诗/poet.song.115000.json','["一別賢關二十年，人間萬事儘悠然。", "堪嗟戎羯羶腥地，元是衣冠禮樂天。", "騎馬相逢南紀道，離尊同舉大江邊。", "此時景色如秋色，自古丹青妙莫傳。"]'),
('c1683786-fc88-493e-8268-d4fcb26dcab2','書院即事','胡宏','宋','宋诗','song-poetry','','[]','爲無經濟學，萬里築幽栖。',48,'全唐诗/poet.song.115000.json','["爲無經濟學，萬里築幽栖。", "波漲青冥濶，柳垂春色低。", "烟花薰小院，風竹掩丹梯。", "便是神仙宅，世人應未迷。"]'),
('67084c58-efca-4681-a9f0-7b6af78176af','碧泉獨步','胡宏','宋','宋诗','song-poetry','','[]','淅淅秋風動，前橋晚步還。',48,'全唐诗/poet.song.115000.json','["淅淅秋風動，前橋晚步還。", "小魚衝岸側，白鳥立溪灣。", "明月照秋水，淡烟籠遠山。", "此時知造物，憐我一身閒。"]'),
('3fd77598-1c23-4275-a0df-19d631788576','雙井詠水仙有妃子塵襪盈盈體素傾城之文予作臺種此花當天寒風冽草木萎盡而孤根獨秀不畏霜雪時有異香來襲襟袖超然意適若與善人君子處而與之俱化乃知雙井未嘗得水仙真趣也輒成四十字爲之刷耻所病詞不能達諸君一笑','胡宏','宋','宋诗','song-poetry','','[]','萬木凋傷後，孤叢嫩碧生。',48,'全唐诗/poet.song.115000.json','["萬木凋傷後，孤叢嫩碧生。", "花開飛雪底，香襲冷風行。", "高並青松操，堅逾翠竹真。", "挺然凝大節，誰說貌盈盈。"]'),
('ab0d2a1e-8f46-468f-8141-4dc84d9608d7','示二子  其一','胡宏','宋','宋诗','song-poetry','','[]','此心妙無方，比道大無配。',48,'全唐诗/poet.song.115000.json','["此心妙無方，比道大無配。", "妙處果在我，不用襲前輩。", "得之眉睫間，直與天地對。", "混然員且成，萬古不破碎。"]'),
('3bcc27b0-6bd9-410c-bdbb-85e6b0897daf','示二子  其二','胡宏','宋','宋诗','song-poetry','','[]','體道識泰否，涉世隨悲歡。',48,'全唐诗/poet.song.115000.json','["體道識泰否，涉世隨悲歡。", "滯迹紅塵中，情寄青雲端。", "早年勤學道，晚節懶爲官。", "心活乾坤似，機員身自安。"]'),
('eb9ecf2d-3a4e-4082-af66-397ad7442c52','泉上','胡宏','宋','宋诗','song-poetry','','[]','晨起步林丘，路經泉上頭。',96,'全唐诗/poet.song.115000.json','["晨起步林丘，路經泉上頭。", "天邊日色下，水底浪花浮。", "沙浄蒲芽綠，風牽荇带流。", "澄瀾立白鷺，細浪逐輕鷗。", "翠鳥來還去，脩魚躍更遊。", "動成春色好，愈覺道情幽。", "田舍知何處，江湖興未收。", "徘徊不忍去，暝色冷如秋。"]'),
('be208b91-f7d0-4d07-8ce2-053f96ff110b','五峯亭','胡宏','宋','宋诗','song-poetry','','[]','鑿山置亭榭，開沼放波瀾。',72,'全唐诗/poet.song.115000.json','["鑿山置亭榭，開沼放波瀾。", "松竹希微綠，菱蓮次第丹。", "風煙富清遠，氣象薄高寒。", "媚此千金軀，舍彼百慮攢。", "神嶽精靈動，人寰波浪漫。", "樂生憂亦集，徙倚徧闌干。"]'),
('feeaa403-569a-4054-9c97-ac2a3de07e2f','挽孫奇父','胡宏','宋','宋诗','song-poetry','','["\u8861\u5c71"]','英雄割據裔，少年事豪俊。',216,'全唐诗/poet.song.115000.json','["英雄割據裔，少年事豪俊。", "名勝翻然交，仁義以身徇。", "南州作吏師，西洛陪先進。", "情高尚禮樂，代季見戎陳。", "王師頻潰遯，我憤嬰疾疢。", "草廬卧江漢，僚幕資才俊。", "昭昭心自知，蹇蹇步不迅。", "乘風忽遠去，炎嶺善持慎。", "先君有願懷，丈人踐忠信。", "相從寓衡山，時許闚牆仞。", "胸中學海深，舌本詞源濬。", "老矣猶詩書，饑來只薇菣。", "馬革誓裹尸，氣凜如秦藺。", "無力獻廟堂，使得致忠藎。", "據古論孔周，及今佐堯舜。", "吁嗟民多瘼，慘戚天不憗。", "煢煢輤車行，遥遥渚宮殯。", "治命能不渝，有子孝而順。"]'),
('b288c9b6-0420-465b-827f-fdd506e6f319','寵辱','胡宏','宋','宋诗','song-poetry','','[]','寵辱無休變萬端，阿誰能向靜中看。',32,'全唐诗/poet.song.115000.json','["寵辱無休變萬端，阿誰能向靜中看。", "消磨利欲十分盡，免得臨機剖判難。"]'),
('2776fd9e-45ba-4e2f-b2b3-98f9c3bd88fc','讀王國風','胡宏','宋','宋诗','song-poetry','','[]','是誰行邁閔宗周，淚灑西風病不瘳。',32,'全唐诗/poet.song.115000.json','["是誰行邁閔宗周，淚灑西風病不瘳。", "幸對南山無盡景，眼看雲物手搔頭。"]'),
('f10a6bba-7d0e-46ea-8873-4eb4cf110e9b','蠶食','胡宏','宋','宋诗','song-poetry','','[]','蠶食人間我厚顔，命成奇數故偷閒。',32,'全唐诗/poet.song.115000.json','["蠶食人間我厚顔，命成奇數故偷閒。", "不知世上山河大，終日徘徊百水間。"]'),
('414793a0-72ce-4059-b98b-86b4ae2811ae','春事  其一','胡宏','宋','宋诗','song-poetry','','[]','橫翠橋南柳色稀，過橋春事那人知。',32,'全唐诗/poet.song.115000.json','["橫翠橋南柳色稀，過橋春事那人知。", "君如就我問消息，新種海棠開兩枝。"]'),
('dccffebf-5213-469e-befc-b448e2d4c3b3','春事  其二','胡宏','宋','宋诗','song-poetry','','[]','走馬尋春西復東，夭桃零落委殘紅。',32,'全唐诗/poet.song.115000.json','["走馬尋春西復東，夭桃零落委殘紅。", "可憐日暮天低處，但有梨花弄晚風。"]'),
('d0685e81-0566-4556-a833-db6e7cf6e44d','和伯氏','胡宏','宋','宋诗','song-poetry','','[]','風高吹散日邊雲，綠水初迴沙際春。',32,'全唐诗/poet.song.115000.json','["風高吹散日邊雲，綠水初迴沙際春。", "逝者如斯長不住，汨羅愁絕笑靈均。"]'),
('59b0bc26-3a1d-4c5c-aa9d-039a3b9fbc1a','漁子  其一','胡宏','宋','宋诗','song-poetry','','[]','瀟湘烟霧隠千重，風月磯綸在在同。',32,'全唐诗/poet.song.115000.json','["瀟湘烟霧隠千重，風月磯綸在在同。", "笑傲飛帆名利客，扣舷都入暝歌中。"]'),
('eebbccda-e6db-44f1-9f85-90d7ef628acc','漁子  其二','胡宏','宋','宋诗','song-poetry','','[]','小舟游漾占江天，家在蘆花一縷烟。',32,'全唐诗/poet.song.115000.json','["小舟游漾占江天，家在蘆花一縷烟。", "最是好風明月夜，棹謳相應亦忘筌。"]'),
