('f32655a6-6823-4dab-ace4-48fd12e9337d','偶書四首  其二','胡宏','宋','宋诗','song-poetry','','[]','青山萬古色，幾人曾賞心。',24,'全唐诗/poet.song.115000.json','["青山萬古色，幾人曾賞心。", "蕭蕭木葉下，我坐復沉吟。"]'),
('c4765fc8-9a95-443c-b4b4-ad887bd0aca7','偶書四首  其三','胡宏','宋','宋诗','song-poetry','','[]','獨坐千峯下，偶馬起徘徊。',24,'全唐诗/poet.song.115000.json','["獨坐千峯下，偶馬起徘徊。", "有誰相共笑，遥見隔溪梅。"]'),
('fb2a6f9e-8423-4d20-8434-bd971c40044a','偶書四首  其四','胡宏','宋','宋诗','song-poetry','','[]','衡嶽望嵩少，屹然河漢間。',24,'全唐诗/poet.song.115000.json','["衡嶽望嵩少，屹然河漢間。", "浮雲自來往，誰肯拓關山。"]'),
('35061c75-e622-40d3-8b76-d87c8788b1cc','題齊雲閣','胡宏','宋','宋诗','song-poetry','','[]','道人南山來，萬里青雲開。',24,'全唐诗/poet.song.115000.json','["道人南山來，萬里青雲開。", "去念見本性，聚散真悠哉。"]'),
('f4038817-b313-4673-869c-7432b65e6e5d','張良','胡宏','宋','宋诗','song-poetry','','[]','六國億萬人，誰是報讐者。',24,'全唐诗/poet.song.115000.json','["六國億萬人，誰是報讐者。", "壯哉博浪沙，一擊震天下。"]'),
('8cd7ab7e-309c-4606-b380-db0f5b342b2f','實弟以詩來督作會文又因太原姪寄聲欲作不速此文人狂客所爲非素所望也今以五絕奉寄雖小阻高興若能從而繹之則有味也  其一','胡宏','宋','宋诗','song-poetry','','[]','我病死無日，經書更窮年。',24,'全唐诗/poet.song.115000.json','["我病死無日，經書更窮年。", "少年宜若厲，詩酒勿留連。"]'),
('1d7c5dae-7326-416d-9c1a-024ee35bcf60','實弟以詩來督作會文又因太原姪寄聲欲作不速此文人狂客所爲非素所望也今以五絕奉寄雖小阻高興若能從而繹之則有味也  其二','胡宏','宋','宋诗','song-poetry','','[]','苦參道難學，放肆事容易。',24,'全唐诗/poet.song.115000.json','["苦參道難學，放肆事容易。", "入脚不可深，駸駸成自棄。"]'),
('b4cc1b9e-c586-421d-b9a1-64d33e611c5c','實弟以詩來督作會文又因太原姪寄聲欲作不速此文人狂客所爲非素所望也今以五絕奉寄雖小阻高興若能從而繹之則有味也  其三','胡宏','宋','宋诗','song-poetry','','[]','天道方愈怒，在人宜敬身。',24,'全唐诗/poet.song.115000.json','["天道方愈怒，在人宜敬身。", "望于經吏內，嚴自作工程。"]'),
('392ac0cf-4d60-411d-a4b4-9da7a28ee026','實弟以詩來督作會文又因太原姪寄聲欲作不速此文人狂客所爲非素所望也今以五絕奉寄雖小阻高興若能從而繹之則有味也  其四','胡宏','宋','宋诗','song-poetry','','[]','歲月嘆逾邁，入門事業難。',24,'全唐诗/poet.song.115000.json','["歲月嘆逾邁，入門事業難。", "戰兢曾子意，豈可遂闌珊。"]'),
('f0677d26-ce2c-4a3b-a7a7-fccbae18a44a','實弟以詩來督作會文又因太原姪寄聲欲作不速此文人狂客所爲非素所望也今以五絕奉寄雖小阻高興若能從而繹之則有味也  其五','胡宏','宋','宋诗','song-poetry','','[]','我祖生文定，傑然繼真儒。',24,'全唐诗/poet.song.115000.json','["我祖生文定，傑然繼真儒。", "門風早衰颯，吾弟意何如。"]'),
('93554a89-a7d2-4cf4-a5b4-fa4744d51108','勵學','胡宏','宋','宋诗','song-poetry','','[]','人心易汩沒，豈徒出徒入。',108,'全唐诗/poet.song.115000.json','["人心易汩沒，豈徒出徒入。", "無方□點檢，一點或□懈。", "□□□□□，彼此成亡羊。", "所以古哲人，警惕恒自將。", "動若集於木，息如繫苞桑。", "此機日就熟，庶足升高堂。", "譬如匣中鏡，拂磨吐新光。", "一塵不使留，光輝日煌煌。", "凡我讀書人，斯言佩毋忘。"]'),
('e3fe6766-ff5f-471f-b827-4010ea615dfc','放舟漫興','胡宏','宋','宋诗','song-poetry','','[]','宿雨喜初霽，湖光照人明。',72,'全唐诗/poet.song.115000.json','["宿雨喜初霽，湖光照人明。", "狂風撼林木，萬里波濤清。", "放舟東山邊，蘭菊有奇英。", "實德自不掩，清香遠相迎。", "侵晨來露布，已罷西南征。", "挺挺湖海豪，涕泗成縱橫。"]'),
('37bf388e-8bd8-4e79-934c-21563d138f13','寓梅溪即事','胡宏','宋','宋诗','song-poetry','','[]','春深暮日暖，亂落桃李花。',60,'全唐诗/poet.song.115000.json','["春深暮日暖，亂落桃李花。", "露淞白山頂，䆉穗青人家。", "微醺坐溪西，對此景物佳。", "悠悠動遐思，恨恨得長嗟。", "振衣偶回首，風吹楊柳斜。"]'),
('b8dff566-8393-48dd-b9af-b5dd3739bff5','感興  其一','胡宏','宋','宋诗','song-poetry','','[]','昨夜看梅枝，風光異昔時。',48,'全唐诗/poet.song.115000.json','["昨夜看梅枝，風光異昔時。", "感時期獻策，出語偶成詩。", "乾健將來巽，蒙昏許及離。", "啟篷凝立處，心事付誰知。"]'),
('ce63a28e-e32c-41ee-8bd3-912d5ac4c0ec','感興  其二','胡宏','宋','宋诗','song-poetry','','[]','扁舟迤邐過焦金，江闊千尋不記深。',64,'全唐诗/poet.song.115000.json','["扁舟迤邐過焦金，江闊千尋不記深。", "明月有情偏照我，好山無處不知心。", "天空一鳥驚漁火，夜靜群星落野砧。", "此處風光盡難得，朗然因復有清吟。"]'),
('d3ed88f4-4095-49b3-99dc-533f69c39cfc','雨中偶成','胡宏','宋','宋诗','song-poetry','','[]','春來連日雨沉沉，撩我襟懷轉不禁。',64,'全唐诗/poet.song.115000.json','["春來連日雨沉沉，撩我襟懷轉不禁。", "布穀蜀來知有意，長虹吳下故爲淫。", "梅香白轉千門玉，柳色黄深兩壁金。", "此景若人真會得，東風誰是不知心。"]'),
('68a57db3-ec9e-41a9-9f36-9e57faee271f','暮歸鑒湖偶成','胡宏','宋','宋诗','song-poetry','','[]','草香泉細午風輕，桃李春花夾岸明。',32,'全唐诗/poet.song.115000.json','["草香泉細午風輕，桃李春花夾岸明。", "歸棹夷猶雲水暮，柳陰深處一聲鶑。"]'),
('d4af1ad4-34e1-4bff-bdf2-413e676fab9d','觀書有感  其一','胡宏','宋','宋诗','song-poetry','','[]','一點銀蟾在碧空，千載城廓夜玲瓏。',32,'全唐诗/poet.song.115000.json','["一點銀蟾在碧空，千載城廓夜玲瓏。", "回首昔日遨游處，覺得分明是管中。"]'),
('ae139347-925c-4301-8aef-bf6d69a17c6d','觀書有感  其二','胡宏','宋','宋诗','song-poetry','','[]','今日曾知進步來，彀愚深自克多才。',32,'全唐诗/poet.song.115000.json','["今日曾知進步來，彀愚深自克多才。", "些兒不閉公門戶，盡着多才打不開。"]'),
('fb227f8c-9cfe-4ae3-987f-82df1322f83e','夜坐寄友人兼以自警','胡宏','宋','宋诗','song-poetry','','[]','滿抱春愁獨擁衾，雨聲入夜更沉沉。',32,'全唐诗/poet.song.115000.json','["滿抱春愁獨擁衾，雨聲入夜更沉沉。", "風流欲會東風面，趁取徑深綠未深。"]'),
('9edb9c80-0145-4de8-a11f-ec2419845a45','天道吟','胡宏','宋','宋诗','song-poetry','','[]','一氣安然不强爲，大强先去少强隨。',32,'全唐诗/poet.song.115000.json','["一氣安然不强爲，大强先去少强隨。", "本來把定真消息，不是迂愚却是誰。"]'),
('433bb07d-b702-4a4a-91bb-a28c8665cc6f','句','胡宏','宋','宋诗','song-poetry','','[]','唯有廩峰居第五，山前盡是宰臣家。',16,'全唐诗/poet.song.115000.json','["唯有廩峰居第五，山前盡是宰臣家。"]'),
('1be34d97-5523-421d-84b9-24fd34d09408','東湖遊山','史浩','宋','宋诗','song-poetry','','[]','四明山水天下異，東湖景物尤佳致。',384,'全唐诗/poet.song.115000.json','["四明山水天下異，東湖景物尤佳致。", "古來奇處蕪沒多，極目空餘老蒼翠。", "最稱險奧唯福泉，崒嵂萬仞摩青天。", "屹起精藍名壽聖，松風颯颯泉涓涓。", "一徑崎嶇通下水，風物人情更淳美。", "兩椽茅屋何蕭然，是即吾廬靠山起。", "吾嘗終日倚闌干，眼界峨峨碧玉攢。", "有時出戶一乘興，枯筇蠟屐隨清湍。", "攀蘿直上上水去，烟霞迤邐僧家路。", "龍藏虎蟄天地寬，陟岵欷歔空墮淚。", "次經象坎白雲庵，陰崖斷谷常青嵐。", "中有村墟號韓嶺，漁歌樵斧聲相參。", "陶公霞嶼崢嶸出，秀傑緜延數非一。", "鼈山孤立水中央，規圓不頼人鑱刻。", "地雄山壯泉源豪，七十二溪俱怒濤。", "截山突屼起六堰，百尺花蹊金石牢。", "鳴桹擲釣漁艇短，數百成羣來往欵。", "綠蓑青笠苦忘歸，細雨斜風渾不管。", "棲真蘭若唯南隅，聞是徐王舊隠居。", "蓮塘十里香風濶，鳧鷖鸂鶒時沉洳。", "一帆迅抵青山寺，丈室雲堂高贔屓。", "森森松菊蔽村祠，細讀刓碑知故事。", "云是皇朝李使君，濬濁澄清利後人。", "迄今旱歲頼實利，血食往往長秋春。"]'),
('be84f821-159d-4902-87ce-535177d4dbb6','時晉亨作小軒塊石盆池名曰趣遠真隠居士賦之','史浩','宋','宋诗','song-poetry','','[]','新晴可步履，杖策穿雲林。',72,'全唐诗/poet.song.115000.json','["新晴可步履，杖策穿雲林。", "蕭齋有達士，六合涵胸襟。", "東偏闢小窗，廣袤不盈尋。", "片石遠山意，寸池滄海心。", "乃知一芥子，可納須彌岑。", "歸鴻目不盡，爲爾發微吟。"]'),
('0a5eed71-3385-43d2-8505-9e47b532908a','次韻鮑以道天童育王道中吳體','史浩','宋','宋诗','song-poetry','','[]','逆雲佛塔金千尋，傍聳滴翠玲瓏岑。',64,'全唐诗/poet.song.115000.json','["逆雲佛塔金千尋，傍聳滴翠玲瓏岑。", "春供萬象富遠目，響答兩地紛啼禽。", "風摇野幘去復去，露浥乳竇深尤深。", "奇聲俊逸鮑夫子，蓬社不掛淵明心。"]'),
('3167b7f6-be0c-4e79-9006-07abe9d2669d','次韻楊少輔山居六詠 疊山','史浩','宋','宋诗','song-poetry','','[]','嵩山遠萬里，兒孫可邀致。',48,'全唐诗/poet.song.115000.json','["嵩山遠萬里，兒孫可邀致。", "當軒羅三峰，便有出羣意。", "不蠟謝氏屐，徜徉日游戲。", "邂逅風雨興，端可名福地。"]'),
('1f1afb70-1325-46eb-a241-b558ade2fda4','次韻楊少輔山居六詠 鑿池','史浩','宋','宋诗','song-poetry','','[]','蕭蕭足佳致，心遠地自偏。',48,'全唐诗/poet.song.115000.json','["蕭蕭足佳致，心遠地自偏。", "斫去蒼苔紋，得此清泠泉。", "湛然不容滓，於以明性天。", "肯復以童兒，見誚韓公篇。"]'),
('2e623d47-9f4a-42c2-a150-190877bb8904','次韻楊少輔山居六詠 栽松','史浩','宋','宋诗','song-poetry','','[]','童童蒿艾間，拱把力尚微。',48,'全唐诗/poet.song.115000.json','["童童蒿艾間，拱把力尚微。", "托根一得所，勢隘天四圍。", "春煙滋蒼髯，朔雪被羽衣。", "他年大夫封，風雨良足依。"]'),
('d897d273-a438-4eea-adbd-e91a8bfa1cbc','次韻楊少輔山居六詠 洗竹','史浩','宋','宋诗','song-poetry','','[]','春林藉雷驚，𧥄𧥄牛羊出。',48,'全唐诗/poet.song.115000.json','["春林藉雷驚，𧥄𧥄牛羊出。", "風月邇來稀，厭此琅玕密。", "繁柯謝一洗，挺挺歲寒質。", "終成葛陂龍，雲路騁駿逸。"]'),
('3d223a32-9ad2-40de-9a82-b7ef218acf0c','次韻楊少輔山居六詠 澆花','史浩','宋','宋诗','song-poetry','','[]','芳圃向成趣，雨澤多愆時。',48,'全唐诗/poet.song.115000.json','["芳圃向成趣，雨澤多愆時。", "花開不抱甕，花謝嗟何爲。", "潘岳興不淺，陶潛顔可怡。", "安得商家霖，萬木均嬉嬉。"]'),
('9e251c65-c4cc-4b20-bc57-783668618614','次韻楊少輔山居六詠 薙草','史浩','宋','宋诗','song-poetry','','[]','設羅門巷靜，草深山更幽。',48,'全唐诗/poet.song.115000.json','["設羅門巷靜，草深山更幽。", "何事勤誅鋤，杖屨來羊求。", "王孫未歸楚，萇弘已棄周。", "惜此年年綠，君其勿剪休。"]'),
('31c8bacc-4d7c-4ac3-a5b8-943fb082fe88','雪中三英 梅花','史浩','宋','宋诗','song-poetry','','[]','雪花大如毬，萬木方枯愁。',48,'全唐诗/poet.song.115000.json','["雪花大如毬，萬木方枯愁。", "絳衣孕珠顆，的皪枝南頭。", "風標信孤挺，游戲墮人境。", "褪白露微青，志已在金鼎。"]'),
('c5a4cc97-eb94-484e-8732-17be8c19f33d','雪中三英 蠟梅','史浩','宋','宋诗','song-poetry','','[]','蜂房釀餘滋，衆香薰蜜脾。',48,'全唐诗/poet.song.115000.json','["蜂房釀餘滋，衆香薰蜜脾。", "幻作應真面，行行排玉枝。", "相看紫檀色，風摇振金錫。", "天遣久住世，不畏高樓笛。"]'),
('e7fcfecf-66c8-4101-8c53-02bff779747c','雪中三英 瑞香','史浩','宋','宋诗','song-poetry','','[]','蕙帳萬緣空，幽人鼻觀通。',48,'全唐诗/poet.song.115000.json','["蕙帳萬緣空，幽人鼻觀通。", "破曉捫翠麓，獲此錦薰籠。", "造化本無意，芬芬隨爾類。", "不知鼻聞香，還是香浮鼻。"]'),
('0fcf4f81-0e50-458f-8e36-5bb5433297c6','次韻慈奧寂照院僧石岩花','史浩','宋','宋诗','song-poetry','','[]','谿山朔雪銷籬落，始聞花信驚梅萼。',128,'全唐诗/poet.song.115000.json','["谿山朔雪銷籬落，始聞花信驚梅萼。", "韶華一瞬掉頭去，滿眼園林成翠幄。", "誰知幽谷猶藏春，萬蔕千跗意態新。", "霞光分彩氣欲熱，露浥燕脂色未勻。", "墨工繪句謾稱好，不見此花空到老。", "子美羞看黄四蹊，退之不數紅雲島。", "天下健步吾能用，擬擘雲頭騎綵鳳。", "叫閽乞與生香歸，只許牡丹名並飛。"]'),
('1618d39f-1c6a-467c-a46c-91e7eb75212e','雪夜行舟駡鬼','史浩','宋','宋诗','song-poetry','','[]','朔風一夜吹寒雪，萬里青山變華髮。',208,'全唐诗/poet.song.115000.json','["朔風一夜吹寒雪，萬里青山變華髮。", "東湖興盡回扁舟，兩岸蘆花照天發。", "篙工撥櫂光陸離，一簑好景渡頭歸。", "忽驚波面漸幽晦，問訊歸程船復退。", "空岩有鬼鳴啾啾，鼓檝揚波如部隊。", "須臾夜朗分西東，對岸村墟指顧中。", "妖氛孽影叱咤散，人家燈火猶朦朧。", "嗚呼山鬼爾何錯，滅頂於余奚所作。", "不能隨爾作禍釁，冷炙殘盃圖咀嚼。", "我有長牋叩上真，我有健步飛如神。", "請呼雷公起霹靂，割截汝輩爲微塵。", "鳴呼山鬼聽我語，從此逍遥自游止。", "如斯攪括枉費力，生死由天不由汝。"]'),
('bfb3f14e-1dc9-4a28-ac30-321f670d86ec','宣州李漕園亭三首 控鼇亭','史浩','宋','宋诗','song-poetry','','[]','平生謝宣城，作意澄江練。',96,'全唐诗/poet.song.115000.json','["平生謝宣城，作意澄江練。", "不知煙霞間，有此巨鼇抃。", "三山沒泱漭，幾歲舞鰌鱓。", "邂逅釣竿手，一掣金背見。", "控之朝玉京，飛騰絕星漢。", "控之游絳闕，蓬萊壓諸彥。", "偉我亭中人，風雷有奇變。", "何必紫綺裘，日誦黄庭卷。"]'),
('82799103-96d7-4982-adb5-df6f263931af','宣州李漕園亭三首 吸川亭','史浩','宋','宋诗','song-poetry','','[]','百川緲鯨波，鯨背高突兀。',96,'全唐诗/poet.song.115000.json','["百川緲鯨波，鯨背高突兀。", "佳氣浮金銀，層觀可髣髴。", "中有萬頃陂，餘地納溟渤。", "咫尺三千里，驚湍讋凡骨。", "而我理煙艇，遥欲窺其窟。", "憑欄俯瀰漫，始覺到崷崒。", "涓流信污沱，晝夜徒汩汩。", "萬錢沃燥吻，何取盃中物。"]'),
('34558865-5fe8-4a9e-931b-6710b0e64b92','宣州李漕園亭三首 守道堂','史浩','宋','宋诗','song-poetry','','[]','徂徠不可倚，衡茅跡已陳。',96,'全唐诗/poet.song.115000.json','["徂徠不可倚，衡茅跡已陳。", "凜凜蓋代氣，千載日日新。", "拭眼登高堂，佳名信可人。", "向來子石子，無乃公前身。", "作頌擬清廟，未免世俗嗔。", "偃蹇百僚底，見有雙眉顰。", "公今文章伯，筆力重萬鈞。", "廟堂有夔卨，此道公當伸。"]'),
('725b5ef3-dbe1-494c-9ac1-a01b01e7ea3b','史伯魚讀書堂','史浩','宋','宋诗','song-poetry','','[]','我來嗟許晚，已失讀書堂。',96,'全唐诗/poet.song.115000.json','["我來嗟許晚，已失讀書堂。", "遺址煙焰餘，草木猶輝光。", "乃知子史子，揭名意何長。", "書冊本可好，履踐斯爲良。", "癡絕蠹萬卷，未若陶食忘。", "苟得是中趣，高可雲外翔。", "政不守螢雪，汩汩勤朱黄。", "譬如沈痾痊，安用千金方。"]'),
('9e7c8f3b-ae6f-4b31-9416-089ad40261c3','代叔父九經堂歌','史浩','宋','宋诗','song-poetry','','[]','黄冠物外士，碧眼世中兒。',186,'全唐诗/poet.song.115000.json','["黄冠物外士，碧眼世中兒。", "琅函赤軸富裒蓄，金作蛟龍盤繡栭。", "撞鐘擊鉢走聾俗，聖典寂寞令人悲。", "我登九經堂，四顧光陸離。", "畫簷散彩噴朝日，翠幌倒影摇天池。", "牙籤插架爭突兀，若有鬼物森扶持。", "使君雅意尊經術，故闢後圃披遺基。", "咄嗟土木上星漢，下視仙宮梵宇俱么微。", "我願茲堂徧寰海，共治皆以經爲師。", "一變人心至齊魯，再使風俗躋農羲。", "却向茲堂命賓友，霜藤象管唱新詩。", "東風吹到君王耳，喚取文翁歸玉墀。"]'),
('6c21343b-23de-443f-aa68-4fc152c47749','次韻沈澤夫逍遥歌','史浩','宋','宋诗','song-poetry','','[]','在昔蒙莊有至言，萬物逍遥天地間。',336,'全唐诗/poet.song.115000.json','["在昔蒙莊有至言，萬物逍遥天地間。", "大鵬斥鷃異稟賦，隨性奚假人防閑。", "怒飛未覺宇宙隘，决起那知世界寬。", "洪纖有量莫相越，智巧不用常優閒。", "默觀萬化盡如許，脫悟此理行非艱。", "但當涵養取深造，工夫祇在澄心源。", "心源澄寂固能應，視彼所寓皆居安。", "佳哉蒙莊豈誕妄，所得實自吾孔顔。", "遠則兼善非附勢，窮而獨處非左計。", "陋巷簞瓢依聖師，何殊禹稷游平世。", "脩仙欲生成大幻，佞佛欲死是乾慧。", "死生之說本同歸，原始當求一言契。", "了知吾道出世間，學渚深流不思濟。", "遂令前輩薄後人，直謂軻死真無繼。", "此生造化曷可輕，勿爲名利思營營。", "吹噓呼吸勤吐納，導引致壽先熊經。", "後枯正藉一溉力，且使既老身康寧。", "向上更須觀一著，一之所起猶未形。", "從渠海岱自更貌，何止一閲三千齡。", "守一還期守真一，真一誠通能事畢。", "吾之所取進乎技，解牛中得養生術。"]'),
('0f1f002d-e95e-4f2a-a2e5-b295b88f7bf1','次韻沈高卿雜言','史浩','宋','宋诗','song-poetry','','[]','讀書正其遠大者，莫爲蟛蜞專爾雅。',276,'全唐诗/poet.song.115000.json','["讀書正其遠大者，莫爲蟛蜞專爾雅。", "儻從紙上覓筌蹄，當識升高必自下。", "富貴不來將奈何，豈作求食思毀瓦。", "富貴適來無容心，處以恬然寧滿假。", "仕官要須得若人，是爲學足美其身。", "萬方思治徯康濟，當吏立政頻咨詢。", "從容風俗到淳古，坐可堯舜吾君民。", "昂頭引頸不愧慚，奚必翰墨誇清新。", "吁嗟二者理非各，俗儒妄分誠臆度。", "學成用我鶚在天，不用聊復龜藏殻。", "名利寵辱尚如許，死生之變良足託。", "沈子才雄敵萬夫，聲華合與前賢符。", "君看昔人可炙手，行若市井真屠沽。", "敝袍陋巷世不如，往往胸次多良圖。", "廼知富貴本餘事，窮達有命吾生俱。", "君詩卓絕了無和，我復感激重揚揄。", "難逢臭味同，勉子謹厥初，毋待桑榆補東隅。"]'),
('5516e172-c3e2-4a62-a838-c0384af16875','代上孫仲益尚書生日','史浩','宋','宋诗','song-poetry','','[]','吳山高兮江水長，江山鬰鬰蟠光芒。',192,'全唐诗/poet.song.115000.json','["吳山高兮江水長，江山鬰鬰蟠光芒。", "上帝靳固鍾俊良，數千百歲誰可當。", "西徐老人鬢眉蒼，身着秋碧雲錦裳。", "馭風騎氣下大荒，帝命錦繡裹肺腸。", "天門賜之龍虎章，下爲人間除不祥。", "主盟吾道承素王，向來斯文病膏肓。", "公於此時氣堂堂，道配歐蘇力相望。", "朝游蓬壺暮扶桑，黼黻河漢回輝光。", "臨流拯溺爲舟航，人生廢置不可量。", "萬里放逐蛇虺鄉，翦翎籠中看鵰翔。", "小儒願公如子房，不願公貴如六郎。", "玉烈石髓請飽嘗，不須更待龍宮方。"]'),
('983da923-4ea9-457e-b8e1-a318960315b7','題陳天予國正借軒','史浩','宋','宋诗','song-poetry','','[]','子猷昔借宅，餘地著霜筠。',120,'全唐诗/poet.song.115000.json','["子猷昔借宅，餘地著霜筠。", "君今地無隙，乃復借諸鄰。", "開窗羅萬箇，傾蓋如相親。", "輕風韻蕭瑟，密雪乘珠珍。", "行當享清絕，寧問誰主賓。", "人生空洞間，千畝納渭濱。", "胡爲徇目力，咫尺分參辰。", "便當混物我，一視無越秦。", "還以賞君軒，借與不借均。", "比意識者會，君無語俗人。"]'),
('000d7ac5-ab49-4eae-aff3-1947558c380a','贈天童英書記','史浩','宋','宋诗','song-poetry','','[]','學禪見性本，學詩事之餘。',240,'全唐诗/poet.song.115000.json','["學禪見性本，學詩事之餘。", "二者若異致，其歸豈殊途。", "方其空洞間，寂默一念無。", "感物賦萬象，儒懸鏡太虛。", "不將亦不迎，其應常如如。", "向非悟本性，未免聲律拘。", "英師箇中人，以詩隠浮圖。", "桃紅柳青青，翠竹黄花俱。", "誤落世間耳，脫畧公卿徒。", "昨朝得東風，打包過江湖。", "胡爲來帝鄉，叫閽徹宸居。", "堂堂老阿師，道價東西徂。", "住山垂一世，學子紛雲趨。", "寒潭風靜練，皎月天心孤。", "邇來隻屨輕，片雪銷洪爐。", "願言立强名，故事臣敢誣。", "事成明當發，長吟入春蕪。", "從茲窣堵波，山雪閟天書。", "顧我坐學省，兀兀如守株。", "因君聽篷雨，爲謝故溪魚。"]'),
('c0d004a3-b208-4dd0-b4cb-45ba5d1d33d1','次韻遊西湖','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生林處士，一葉老波光。',120,'全唐诗/poet.song.115000.json','["平生林處士，一葉老波光。", "坐令西湖名，千古磨蒼蒼。", "邇來子李子，掉鞅出柴桑。", "官閒到休日，清淺尋幽香。", "金風度林麓，野艇生微凉。", "竹間寄登覽，孤岑水中央。", "拂石辨奇蹟，哦詩味遺芳。", "歸來筆不停，醉墨翻淋浪。", "他時三賢亭，合著君在旁。", "只恐作霖雨，幽夢通商王。"]'),
('4d839cb5-34e9-485b-ba6e-cc4ddd86156a','次韻馮圓中酴醾  其一','史浩','宋','宋诗','song-poetry','','[]','東風滿架吹寒玉，慣逐園丁供菜束。',64,'全唐诗/poet.song.115000.json','["東風滿架吹寒玉，慣逐園丁供菜束。", "瀛洲一見眼偏明，縹渺霓裳舞仙曲。", "紛紛桃李俱蒼苔，冰壺着此真幽獨。", "更須釀取甕頭春，醉倒莫看蠻與觸。"]'),
('24441232-6606-4240-9c2c-5b5babc90584','次韻馮圓中酴醾  其二','史浩','宋','宋诗','song-poetry','','[]','碧雲堆裏顔如玉，紅紫便應高閣束。',64,'全唐诗/poet.song.115000.json','["碧雲堆裏顔如玉，紅紫便應高閣束。", "千尋結架上青冥，山外水邊隨詰曲。", "飄然來及牡丹時，潔白自知吾步獨。", "道人儻置枕屏前，第一莫教纖手觸。"]'),
('f905c157-2054-4829-9213-2ad7a336c0ae','次韻馬德駿贈劉韶美','史浩','宋','宋诗','song-poetry','','[]','迢迢弱水環蓬山，山在虛無縹渺間。',98,'全唐诗/poet.song.115000.json','["迢迢弱水環蓬山，山在虛無縹渺間。", "子有仙風彌八極，雲烟爲爾一開關。", "却欲管城邀四友，寫出嘉模看匠手。", "功名不掛達者心，未比即時一杯酒。", "夫君胸次非不活，就使口占須腕脫。", "惟其不欲世人誇辯洽，漢董唐劉顔如甲。"]'),
('ce0df473-cdb4-44e3-979f-2a82d1c51b2f','次韻王龜齡贈韶美','史浩','宋','宋诗','song-poetry','','[]','奎壁忽墮地，晁董喧炎劉。',96,'全唐诗/poet.song.115000.json','["奎壁忽墮地，晁董喧炎劉。", "公生百世後，掉鞅從之游。", "仙桂滿月窟，何事玉斧修。", "亭亭看直上，高壓百花頭。", "昔我登麟閣，正喜挹風流。", "參辰曳裾日，心旌倍悠悠。", "紉闌作春佩，采菊供晨羞。", "相期有義路，歲晚俱能由。"]'),
('fc479498-34ff-4f7d-813c-d87589129706','和建王雨中聞戒酒之什','史浩','宋','宋诗','song-poetry','','[]','簇雲行太虛，作霖自天意。',168,'全唐诗/poet.song.115000.json','["簇雲行太虛，作霖自天意。", "凉氣入郊坰，通宵喜不寐。", "鼕鼓喧銅駝，鯨鐘韻蕭寺。", "遲明上層樓，羽扇端可棄。", "萬象奔空來，攬之入詩思。", "七椀有餘清，一觴成徑醉。", "倒着白接䍦，飄蕭新出笥。", "客有可人姿，終規聊見志。", "樂飲雖及辰，沈酣非所恣。", "主人雲夢胸，綽有容物智。", "溫顔起謝客，博哉斯言利。", "平生千金軀，於此肯嘗試。", "逡巡掃鉅篇，華衮酬一字。", "觀者嗟賢王，不以儒爲戲。"]'),
('66c1fa06-544e-4d25-a153-1fe6940ebf77','上建王生辰  其一','史浩','宋','宋诗','song-poetry','','[]','上帝昌我宋，高目視所以。',48,'全唐诗/poet.song.115000.json','["上帝昌我宋，高目視所以。", "天子亶聰明，亦既受多祉。", "慶澤渺夢圖，班衣有元嗣。", "茲辰甫誕辰，想見龍顔喜。"]'),
('08237341-1c47-456f-9e69-7aa84be87d87','上建王生辰  其二','史浩','宋','宋诗','song-poetry','','[]','子孝與臣忠，二者有大戒。',48,'全唐诗/poet.song.115000.json','["子孝與臣忠，二者有大戒。", "王今得兼隆，無乃神所介。", "晨昏奉赤墀，腰圍白玉带。", "堂堂真天人，驕吝蔑纖芥。"]'),
('b3e4d232-516f-4515-a272-b58bff485e43','上建王生辰  其三','史浩','宋','宋诗','song-poetry','','[]','中使曉飛鞚，下拜金屈巵。',48,'全唐诗/poet.song.115000.json','["中使曉飛鞚，下拜金屈巵。", "門既却賀賓，宴不侈曲眉。", "玉爐浄棐几，但誦天保詩。", "在我有古制，在彼俱弗爲。"]'),
('49140b0c-1349-41dd-a0f7-f3eac5f01045','上建王生辰  其四','史浩','宋','宋诗','song-poetry','','[]','下客曳長裾，薄技奚所奏。',48,'全唐诗/poet.song.115000.json','["下客曳長裾，薄技奚所奏。", "唯有六經腴，王心本研究。", "方瞳秋月明，綠髮寒松茂。", "天子歷無疆，王亦千萬壽。"]'),
('cee29e07-412a-49e7-a403-b03393a7cacb','遊西湖分韻得要字','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','儒生紙上爭攻剽，傳癖書癡等貽誚。',320,'全唐诗/poet.song.115000.json','["儒生紙上爭攻剽，傳癖書癡等貽誚。", "不然利海競錐刀，或向名場羨華要。", "紛紛臧穀兩亡羊，說以西湖却頭掉。", "西湖自倚傾城姿，肯與西施角年少。", "品題定價有前賢，陳迹班班猶可弔。", "試因休沐許尋盟，浄洗緇塵一登眺。", "身疑孤星破浮雲，心逐驚猱走空嶠。", "野竹萬箇秋聲虛，敗荷十里香風妙。", "凌霄金剎梵仙居，怪石嶙峋餘萬竅。", "高敷桂子浥新黄，好傍長枝發清嘯。", "老禪林外熟蹲鴟，雙耳不聞天使召。", "行行欲問處士橋，路轉忽逢水仙廟。", "未羞菊蕊薦芳馨，一盞寒泉敢先釂。", "翩翩沙鳥沒蒼烟，紅蓼丹楓舞斜照。", "急呼艇子汎漪漣，正欲渡間狎漁釣。", "同行磊落三數公，嘉此襟期非素料。", "襞牋吟寫樂遊詩，愈使西湖有光耀。", "伊余同賦却忘言，了知造物工相撩。", "千古遊人安在哉，城郭山林歸一窖。", "會須象罔得玄珠，可免小兒輕侮笑。"]'),
('3aee68d7-fdf7-4be0-bc1a-7393c637ba74','次韻洪景盧雪','史浩','宋','宋诗','song-poetry','','[]','瑶臺迥物表，地脈誰解縮。',192,'全唐诗/poet.song.115000.json','["瑶臺迥物表，地脈誰解縮。", "一朝天門開，跬步即瓊屋。", "靄靄行簇雲，霏霏忽瞇目。", "初疑蛺蝶驚，故遣兒曹撲。", "須臾大如席，幾車飛鸞鵠。", "化工信巧妙，花卉千林足。", "潔白皎奇姿，光芒渺地軸。", "清垂寒江釣，靜折空岩竹。", "唯人在宇內，太倉一粒粟。", "俯仰得真賞，四坐列羣玉。", "錦繡張軒牖，珠翠輝華燭。", "鉢擊筆下成，杯催甕頭熟。", "檀板襯紅綃，更殢新裁曲。", "寧知冰氏子，窮歲無半斛。", "裘褐欲蔽膚，尚待春苗綠。", "爲瑞豈宜多，晛消胡不速。"]'),
('da38dc22-3451-49ce-b6df-29f1d2ddd4d8','聽阮','史浩','宋','宋诗','song-poetry','','[]','水晶宮殿黄金闕，玉斧修成大圓月。',160,'全唐诗/poet.song.115000.json','["水晶宮殿黄金闕，玉斧修成大圓月。", "漆光照膽毛髮寒，依約峰巒見林樾。", "誰人於此安四絃，流水高山寄清越。", "初如孤鶴唳藍田，漸若羣鸞舞丹穴。", "踈踈夜雨滴秋階，忽然雪竹空岩折。", "世間萬態不可窮，絃中有口俱能說。", "錦瑟華年過眼休，枯桐已爲伯牙絕。", "是間真意亙千古，千古仲容名不滅。", "人生俯仰天地內，瞬息百年同一閲。", "請君姑置是非事，來憑雲窗聽高潔。"]'),
('e53e527f-6abe-49a8-869a-06482f2c2cf2','寄題勝金閣','史浩','宋','宋诗','song-poetry','','[]','黄金委糞壤，六籍垂日星。',48,'全唐诗/poet.song.115000.json','["黄金委糞壤，六籍垂日星。", "茲焉論勝負，無乃未知經。", "雲林倚傑閣，楚楚羅汗青。", "寄與閣上人，移之置中扃。"]'),
('2ed5ee9d-f418-45cc-b0a6-771264fe9653','古風四首 頤真','史浩','宋','宋诗','song-poetry','','[]','門外長安道，紛紛名利人。',48,'全唐诗/poet.song.115000.json','["門外長安道，紛紛名利人。", "誰知方寸許，有地可頤真。", "真能了萬象，亦復冥諸塵。", "不離虛幻境，舉目見全身。"]'),
('804e2f1f-7b2c-48ff-aa95-02678a82670f','古風四首 雲壑','史浩','宋','宋诗','song-poetry','','[]','壺天眇巨壑，微雲映脩林。',48,'全唐诗/poet.song.115000.json','["壺天眇巨壑，微雲映脩林。", "英英從何來，膚寸忽千尋。", "早歲驟爲雨，春空輕作陰。", "會須搔首聽，中有老龍吟。"]'),
('22cd6945-f786-404d-a936-e431cf7de499','古風四首 月巖','史浩','宋','宋诗','song-poetry','','[]','青山吐白玉，團欒光萬頃。',48,'全唐诗/poet.song.115000.json','["青山吐白玉，團欒光萬頃。", "何時飛來峰，著此破昏暝。", "料想清夜闌，主人深自領。", "安得招歡伯，三人成對影。"]'),
('3533ab8f-fd89-457b-8732-fa0c65b133d7','古風四首 善淵','史浩','宋','宋诗','song-poetry','','[]','觀水須觀瀾，監水必監止。',48,'全唐诗/poet.song.115000.json','["觀水須觀瀾，監水必監止。", "清漪不受觸，風定畧無滓。", "時以喻方寸，太虛融衆理。", "客來如問津，須君親指似。"]'),
('f8f72fb2-386b-4e26-8c5c-91f1c367b968','送王嘉叟編修倅洪州','史浩','宋','宋诗','song-poetry','','[]','男兒抱經綸，動必爲時利。',288,'全唐诗/poet.song.115000.json','["男兒抱經綸，動必爲時利。", "姑置俗儒談，盍各言爾志。", "匹馬從軍游，叫閽上封事。", "秦王不能坑，漢祖不敢戲。", "不溺蠻粵頭，當斷匈奴臂。", "雍容奏凱還，禮樂格天地。", "化工泯無迹，君隆堯舜治。", "此志倘蕭條，五湖資一醉。", "釣竿拂滄波，藜杖倚烟寺。", "采菊秋薦馨，紉蘭春及衣。", "作詩以遣懷，把酒以適意。", "隨處是道場，其樂叵思議。", "公乎箇中人，出處洞茲義。", "彈冠下七閩，簉迹中都吏。", "學士如堵牆，爭欲挽之試。", "公曰平生心，科目非所覬。", "我有活國謀，囊封徹天視。", "九重一夜闌，拊髀爲歔欷。", "遲明未報可，襆被秣歸騎。", "帝曰予汝嘉，予憂在閫寄。", "南昌古名藩，咨汝往其貳。", "畫棟曉飛雲，珠簾暮雨墜。", "要當軫民癘，豈獨覽佳致。", "公清衡重輕，內外匪殊異。"]'),
('827834d7-afc9-49c3-895d-ea39e4dec9fa','送王時亨舍人帥蜀二十韻','史浩','宋','宋诗','song-poetry','','[]','文翁上岷江，風化亟飛揚。',240,'全唐诗/poet.song.115000.json','["文翁上岷江，風化亟飛揚。", "峩峩當代間，輩出王馬揚。", "挽彼石室流，濯此錦繡腸。", "遂令蜀士夫，至今能文章。", "武侯隠偏地，雲龍適相值。", "純誠革斯俗，三代可立致。", "千載凜如生，老栢猶英氣。", "遂令蜀士夫，至今抱忠義。", "乖崖一專城，四海喧嘉名。", "發奸照幽伏，世仰如神明。", "蠹弊跡已去，靈祠俎猶腥。", "遂令蜀士夫，至今有能聲。", "清獻鎮南嶠，餘風弭貪暴。", "琴鶴適自隨，薏苡雅非好。", "熙朝慶登崇，深仁格穹燾。", "遂令蜀士夫，至今秉清操。", "英英王紫微，橫金擁旌麾。", "五十四州地，和氣濛烟霏。", "兼美數君子，士夫得其依。", "行行報政成，天子竚公歸。"]'),
('903627cd-1a43-42b4-b802-add2ee090f5d','次韵姚令威郎中九日部宿','史浩','宋','宋诗','song-poetry','','[]','堂堂老詩匠，持被入星省。',48,'全唐诗/poet.song.115000.json','["堂堂老詩匠，持被入星省。", "烏帽不衝風，青綾怯餘冷。", "豈無菊蕊杯，莫洗寸心耿。", "却呼短檠來，共此良夜永。"]'),
('f196b18a-30f6-474e-92e0-1928501e6269','上建王生辰  其一','史浩','宋','宋诗','song-poetry','','[]','高穹祚明德，聖主歷無疆。',48,'全唐诗/poet.song.115000.json','["高穹祚明德，聖主歷無疆。", "談笑復境土，穆穆游岩廊。", "一定天下本，忠孝資元良。", "願言千萬壽，玉立侍清光。"]'),
('31cac479-2272-44e6-b0ed-9a5ef662e145','上建王生辰  其二','史浩','宋','宋诗','song-poetry','','[]','椒殿靄葱蒨，瑞霧濛烟霏。',48,'全唐诗/poet.song.115000.json','["椒殿靄葱蒨，瑞霧濛烟霏。", "有子不必多，一夔燦斑衣。", "天地久覆載，日月長光輝。", "願言千萬壽，怡色奉庭闈。"]'),
('d0263af3-fdc5-49ff-8eb2-3b079d1bd578','上建王生辰  其三','史浩','宋','宋诗','song-poetry','','[]','太史仰乾象，光芒見前星。',48,'全唐诗/poet.song.115000.json','["太史仰乾象，光芒見前星。", "森然拱帝所，無乃趨過庭。", "道德粹金玉，詞華渺滄溟。", "願言千萬壽，聲聞炳丹青。"]'),
('e554c1ea-485b-41ec-9c16-04e0c0851fd6','上建王生辰  其四','史浩','宋','宋诗','song-poetry','','[]','炎圖亙無極，吾王今中興。',48,'全唐诗/poet.song.115000.json','["炎圖亙無極，吾王今中興。", "銀潢注瀰漫，及是歌繩繩。", "金龜曜玉砌，芝蘭香始升。", "願言千萬壽，頷首觀雲仍。"]'),
('082cf95b-43bb-4e86-8397-e9265b253843','辛巳臘月休日絕江至瓜洲觀戰地與馬德駿馮圓中二郎中會舟回焦山德駿令嗣始來侍行某偶留金山不獲與此游輒和三詩以寄懷時駕至鎮江 德駿瘞字韻','史浩','宋','宋诗','song-poetry','','[]','天地一郛郭，陰陽司啟閉。',216,'全唐诗/poet.song.115000.json','["天地一郛郭，陰陽司啟閉。", "大江蟠其中，滔滔每東詣。", "瀰漫萬頃寬，源委衆流細。", "經營到楊子，詎可以里計。", "頗聞神禹功，設此限地勢。", "羣龍沸波浪，風雨雜吞噬。", "稍非濟川手，未免魚腹瘞。", "三國取漢鼎，英雄馳亂世。", "交朋若弟昆，反眼或背戾。", "各取天一方，巢穴自株柢。", "唯於阿堵中，快心咸底滯。", "曹丕亦時傑，弭節悸無際。", "胡爲稱干戈，狂酲倚微毳。", "笑指鐵甕城，不韙欲睥睨。", "皇穹佐有德，奪鑑俾昏翳。", "烟塵一時平，兵威即衰替。", "我來弔瓜洲，與子若宿契。", "焦山空在望，我實媿牽制。"]'),
('a48076c8-169c-4c56-a631-06e359ae76d2','辛巳臘月休日絕江至瓜洲觀戰地與馬德駿馮圓中二郎中會舟回焦山德駿令嗣始來侍行某偶留金山不獲與此游輒和三詩以寄懷時駕至鎮江 圓中鶴字韻','史浩','宋','宋诗','song-poetry','','[]','輕舠艤江滸，欲作揚州鶴。',168,'全唐诗/poet.song.115000.json','["輕舠艤江滸，欲作揚州鶴。", "翩然下中流，隠隠片帆落。", "兩岸阨海口，焦乃居上齶。", "呀呷受滄溟，餘地著萬壑。", "碧瓦差龍鱗，浮圖峙麟角。", "潮回露灘舂，礧砢出堅确。", "仆碑蒼蘚餘，琬琰在山脚。", "玉氣薰林巒，風煙不蕭索。", "何年王右軍，大書此鑱鑿。", "遂令衛永輩，千古束高閣。", "嗟予咫尺許，來往誠大錯。", "頼有三公詩，時時資咀嚼。", "唯憂赤地旱，茲石或流爍。", "用汝作霖雨，王言非戲謔。"]'),
('6a32f1ff-cf31-4ff1-a9f1-9bccfeda3f4a','德駿賢郎銘字韻','史浩','宋','宋诗','song-poetry','','[]','老鳳鳴阿閣，有雛燦丹青。',120,'全唐诗/poet.song.115000.json','["老鳳鳴阿閣，有雛燦丹青。", "相將上浮玉，有翼垂南溟。", "惟實在竹頭，香霧風泠泠。", "惟泉似清醴，漱作甘露零。", "滿胸飲冰雪，終日翔禪扃。", "摩娑古斷碑，顰頞嗟天刑。", "覓句寫真賞，豈只誇一能。", "後生正可畏，之子乃妙齡。", "使我讀數四，爽氣生襟靈。", "飛書寄豚犬，俾作座右銘。"]'),
('6f7fd418-598a-4257-8273-d240fcf1da99','陪洪景盧左司馬德駿薛季益馮圓中三郎中汪中嘉總幹游蔣山以三十六陂春水分韻得三字','史浩','宋','宋诗','song-poetry','','[]','大江洶澎湃，風靜星斗涵。',240,'全唐诗/poet.song.115000.json','["大江洶澎湃，風靜星斗涵。", "截然當地險，界限天東南。", "金陵帝王都，窟宅何耽耽。", "龍虎爭負恃，盤踞昔所談。", "我適訪陳迹，策馬衝煙嵐。", "蔣山上疊翠，秦淮俯拖藍。", "寶公道場主，貌像堅瞿曇。", "千年窣堵波，倒影落寒潭。", "共知勝絕處，即是彌勒龕。", "舂春足佳致，慨想聊停驂。", "六朝互興廢，較德同朝三。", "中原文武境，久困兵貪婪。", "曾無混一志，溥施鴻恩覃。", "區區守覇圖，跼束令人慙。", "豈若吾主聖，坐遣兇渠戡。", "長驅翔灞上，垂拱受朝參。", "回觀茲奧區，脫去如遺簪。", "小臣執羈靮，喜釋心如惔。", "再拜觴萬壽，愷樂將屢酣。", "却來尋故棲，了此七不堪。"]'),
('e94070ad-2906-421e-b100-c963943d9f7e','次韻馮圓中雪','史浩','宋','宋诗','song-poetry','','[]','東風巧醖寒，吹雨作飛雪。',48,'全唐诗/poet.song.115000.json','["東風巧醖寒，吹雨作飛雪。", "酒面不成春，獸炭何曾熱。", "墮空遠飄飄，入簾輕瞥瞥。", "功歸大有年，誰道軍儲闕。"]'),
('c43fdec9-b7dd-4d28-a15f-025bb6f94db9','餞馮圓中郎中守邛州','史浩','宋','宋诗','song-poetry','','[]','岷峨秀多士，照乘輝連城。',240,'全唐诗/poet.song.115000.json','["岷峨秀多士，照乘輝連城。", "夫君挺奇瑞，梯棧來神京。", "殿前策三道，光焰摩九精。", "甲科雄鷺序，四海馳文名。", "一朝坐璧水，緩轡登蓬瀛。", "二年作銓總，談笑流品清。", "陛對本故事，中間俄一鳴。", "黼座固色喜，無乃羣邪驚。", "堂堂頗牧論，萬古追家聲。", "胡爲忽掉頭，解組尋歸程。", "帝曰邛筰民，撫字宜煩卿。", "汝其下膏澤，癯瘠均豐盈。", "上方寶環賜，遲汝襦袴氓。", "承平二千石，倚任誰云輕。", "况復近鄉井，正晝錦方榮。", "過家仍上冢，鉦鼓喧雙旌。", "男兒貴行志，豈俟腰金橫。", "風雲儻際會，衮繡居槐庭。", "別酒置客邸，伊嗟未忍傾。", "所嗟君子外，何獨傷離情。"]'),
('d660dd88-e675-458b-80fb-3c37b83f07b4','途中即事  其一','史浩','宋','宋诗','song-poetry','','[]','巾車向東南，御者欲西北。',48,'全唐诗/poet.song.115000.json','["巾車向東南，御者欲西北。", "西北信繁華，豈若吾故國。", "有泉可洗心，有含可休僕。", "御者契我言，欣然亦轉轂。"]'),
('f77d683c-4802-462b-a343-ab3e3bed92be','途中即事  其二','史浩','宋','宋诗','song-poetry','','[]','四山俱荒茅，松竹不露穎。',48,'全唐诗/poet.song.115000.json','["四山俱荒茅，松竹不露穎。", "清絕一株梅，依依秀孤嶺。", "輕風引餘馨，淡月露寒影。", "東君蚤催實，待此薦金鼎。"]'),
('ab24e0bb-3b2a-45e4-b16e-7eb88a79c37a','途中即事  其三','史浩','宋','宋诗','song-poetry','','[]','春水漲波縠，畫鷁爭先馳。',48,'全唐诗/poet.song.115000.json','["春水漲波縠，畫鷁爭先馳。", "一夜風如許，持此將焉之。", "小艤俟風息，居然無險巇。", "紛紛彼朝涉，欣吾來解維。"]'),
('447b176b-bfc2-48fc-a6b1-f722dc5be22c','次韻潘德鄜山行','史浩','宋','宋诗','song-poetry','','[]','學佛以佛魔，學儒爲儒縛。',252,'全唐诗/poet.song.115000.json','["學佛以佛魔，學儒爲儒縛。", "胡不朝隠几，嗒焉似南郭。", "是非風過耳，名利束高閣。", "回視平生心，無乃亦大錯。", "便當息萬緣，擺去如斧削。", "神遊八極表，笑傲有餘樂。", "山水得勝處，一攬襟量廓。", "杖錫羣峰顛，宮殿浮碧落。", "下瞰徐符岩，居然在山脚。", "衆水會一澗，頹波瀉珠箔。", "奔放出中塗，隠潭鍾萬壑。", "轟如破蟄雷，急似晴空雹。", "或復地中行，鳶飛魚自躍。", "躋攀至飛電，乳竇知誰鑿。", "向來因風絮，句法誠軟弱。", "六花傾萬倉，千古無鎖鑰。", "濛潤遍寰海，何止灑林薄。", "憑欄眼欲眩，頓洗眵昏濁。", "翻身上妙高，愈覺吟魂矍。", "鑿齒對彌天，相視兩無怍。", "祇恐星軺登，蕙帳聞怨鶴。"]'),
('5d7cf01e-81ec-41bd-b1af-496731412624','次韻潘德鄜詠曇老四窗','史浩','宋','宋诗','song-poetry','','[]','石窗兀太虛，四顧蔽雲幄。',96,'全唐诗/poet.song.115000.json','["石窗兀太虛，四顧蔽雲幄。", "朝看爽氣浮，暮送紅日落。", "主人宅是間，結茅侶猿鶴。", "平生丘壑姿，肯內謝康樂。", "客有子潘子，登臨富佳作。", "筆發天地秘，靈光動寥廓。", "長謠萬峰頂，世事俱脫畧。", "回頭睨俗士，機巧費穿鑿。"]'),
('e304c59d-fa5c-40a2-8a53-8b7455053e14','上賜御製新秋過雨書懷詩且令屬和','史浩','宋','宋诗','song-poetry','','[]','畏暑却餘威，飆馭臨寰海。',72,'全唐诗/poet.song.115000.json','["畏暑却餘威，飆馭臨寰海。", "一雨濯寥空，晴光露精彩。", "乾坤陟清凉，居然神觀改。", "俯聽林麓間，萬彙喧天籟。", "便當置蒲葵，暍者得自在。", "此恩夷夏均，聖德如天大。"]'),
('a4ce216c-502f-4c18-b598-debda0f05308','進錫宴澄碧殿詩','史浩','宋','宋诗','song-poetry','','[]','季秋中澣日，淳熙隆四禩。',288,'全唐诗/poet.song.115000.json','["季秋中澣日，淳熙隆四禩。", "朝回攬轡間，中使俄傳旨。", "少須日轉申，宣名陪宴喜。", "預令掃玉堂，深夜備棲止。", "悚懼跪承命，走騶亟穿市。", "絳闕聳皇居，非煙常靡靡。", "入自東華門，熊羆森爪士。", "詔許乘肩輿，安徐無跛倚。", "復古距選德，相望幾數里。", "修廓接雲漢，岧嶤燦珠蕊。", "中途敞金扉，恍若蓬壺裏。", "羣山擁蒼壁，四顧環弱水。", "山既日夕佳，水亦湛無滓。", "冰簾映綺疏，瓊殿中央峙。", "澄碧曜宸奎，神龍爭守視。", "舞蹈上丹墀，天威不違咫。", "奉觴祈萬壽，時蒙一啟齒。", "餘波丐鼠腹，酒行不知幾。", "徘徊下瑶席，緩步煩玉趾。", "從游至清激，錫坐談名理。", "泉聲韻瑟琴，一洗箏笛耳。", "皇云萬幾暇，觀書每來此。", "論道及帝王，直欲齊其軌。", "堯舜禹湯文，前身無乃是。"]'),
('2e74d672-7dee-4394-91aa-1b08e37cd461','次韻程泰之尚書','史浩','宋','宋诗','song-poetry','','[]','程王二夫子，聽履上甘泉。',240,'全唐诗/poet.song.115000.json','["程王二夫子，聽履上甘泉。", "咳唾妙一世，萬斛明珠圓。", "官居季孟間，風義帝相先。", "每當持論許，聞者殆欲仙。", "蛟龍縱巨壑，鷹隼橫寥天。", "坐令膾炙餘，枵腹猶便便。", "程方秋欲半，金波照觥船。", "追想昔年日，高會有由緣。", "親故持吉語，置酒家東偏。", "今年玉堂直，對此宜無眠。", "夜色凉如水，冰輪吐層顛。", "顧影還自慰，身冠六卿聯。", "巍巍太平基，聖主樂得賢。", "作句紀茲夕，所喜期不愆。", "藏之在巾笥，未肯露其全。", "王於退食際，髣髴知云然。", "求之既愈力，璀璨出長編。", "荆潭佇唱酬，凡目一洗湔。", "我生亦何幸，披味如擊鮮。", "明朝問紙價，都下已爭傳。"]'),
('52476805-d12a-480c-888b-d4639cdc83a4','又依前韻','史浩','宋','宋诗','song-poetry','','[]','混沌既開闢，溥博分淵泉。',240,'全唐诗/poet.song.115000.json','["混沌既開闢，溥博分淵泉。", "其中具明眼，來往類跳圓。", "惟有詩工夫，可探造化先。", "研摩到極致，換骨如得仙。", "上以美教化，下以明性天。", "元白愧重濁，鮑謝羞輕便。", "佩劍雖相笑，沈迷乃同船。", "未登風雅域，爲問何因緣。", "無非警策句，各在詩一偏。", "我欲窺其奧，晏食宵不眠。", "觀舞悟深旨，曾不及張顛。", "清新乏奇妙，局束猶拘聯。", "習氣未能斷，爲之乎猶賢。", "寫出多瑕疵，未免拙慈愆。", "公詩百篇內，浩然志帥全。", "愈出力愈促，即之俱自然。", "熟讀已成誦，寧待三絕編。", "如澡銀潢水，塵氛俱盡湔。", "敬當珍此賜，墨蹟令常鮮。", "更許示餘帙，泚筆吾須傳。"]'),
('82bc0d78-c38b-497b-a34a-ffb00f1e99fa','次韻李光祖瑞香','史浩','宋','宋诗','song-poetry','','[]','石蹊萬折凍欲裂，兩岸梅英照天發。',288,'全唐诗/poet.song.115000.json','["石蹊萬折凍欲裂，兩岸梅英照天發。", "於中更有錦薰籠，芳菲不待勾萌達。", "奇姿苒苒來仙源，從此橫枝不直錢。", "東風零亂委泥土，只爲山家作玉田。", "豈若夫君有真色，紫葩碧葉從初得。", "幾將消息露人間，紛紛塵俗誰能識。", "晚居盧阜聲名飛，蕙帳悠悠春夢遲。", "起來鼻觀猶馥鬰，杖藜便覺香風隨。", "夭桃謾說燕脂染，落絮徒云白氈糝。", "品題一著佳客稱，併使丁香風味減。", "藍溪夫子誠好事，贈我此花良有爲。", "平生巖壑在胸中，培殖根荄年不記。", "故應謂我知花譜，千夫綵綷來吾圃。", "拜嘉歡喜不敢當，直欲美芹羞帝所。", "昔扈龍輿白石川，回鑾小憩玉津園。", "曾見此花千百本，較量今者端無前。", "若居御苑逢膏澤，車載盆栽惟所適。", "吾王顧盼即生春，不費陽和些子力。"]'),
('0af5261a-ad45-4fce-8c28-c86b30f662ad','恭和御製長春花詩  其一','史浩','宋','宋诗','song-poetry','','[]','玉殿萬幾閒，宸章燦珠蕊。',84,'全唐诗/poet.song.115000.json','["玉殿萬幾閒，宸章燦珠蕊。", "俯念簪履舊，恩光來太紫。", "禁籞玩長春，嫣然異羣卉。", "羣卉固亦佳，時過逐流水。", "獨此供清遊，餘香襲芳芷。", "一經聖品題，貴名何日已。", "再拜體皇情，感深銘諸几。"]'),
('fa291d71-1832-47a4-930f-dc429c2ac431','恭和御製長春花詩  其二','史浩','宋','宋诗','song-poetry','','[]','帝予四時春，著花無浪蕊。',84,'全唐诗/poet.song.115000.json','["帝予四時春，著花無浪蕊。", "殖本在蓬壺，非烟籠翠紫。", "雪裏友寒梅，芳辰領繁卉。", "每蒙天一笑，睿思湧泉水。", "霑丐及老臣，芬薌勝荃芷。", "况復屢褒嘉，載賡寧但已。", "第愧狂斐辭，不足溷瓊几。"]'),
('bd0591f1-8bbc-48f3-8528-acb174da5295','恭和御製長春花詩  其三','史浩','宋','宋诗','song-poetry','','[]','玉帝富雲章，寶匣鎸琅蕊。',84,'全唐诗/poet.song.115000.json','["玉帝富雲章，寶匣鎸琅蕊。", "六丁謹緘縢，芝彤燕泥紫。", "龍銜下碧虛，端爲詠嘉卉。", "咫尺不違顔，何曾隔弱水。", "炷薰啟天藏，椒蘭和白芷。", "光焰萬丈餘，光臨殊未已。", "敬須營傑閣，敢只留棐几。"]'),
('ca78e7c7-95a5-4234-a0de-9d6a9a7af532','恭和御製翠寒堂詩','史浩','宋','宋诗','song-poetry','','[]','禁蘌葱葱擁瑞雲，雄樓傑閣環金碧。',128,'全唐诗/poet.song.115000.json','["禁蘌葱葱擁瑞雲，雄樓傑閣環金碧。", "花光草色媚芳辰，鳳輦舂容惟所適。", "中有虛堂玉作楹，冰雪玲瓏周四壁。", "不知跬步是瑶臺，何須八駿殷勤覓。", "青松萬箇拱簷牙，生香不減芝蘭室。", "更欲相看飽歲寒，踈梅瘦竹爲三益。", "吾皇土木未嘗興，爲詢此景從何得。", "神運元從德壽來，天成豈假人工役。"]'),
('79ad0fc4-d475-47c7-98fc-d9b1ca888652','次韻楊醇中','史浩','宋','宋诗','song-poetry','','[]','昔年居處雖同里，止識荆州面而已。',355,'全唐诗/poet.song.115000.json','["昔年居處雖同里，止識荆州面而已。", "朅來蝸舍細論文，始向靈臺見吾子。", "夜闌相與哦新詩，珠璣璀璨皆英辭。", "野塘轉月梅影瘦，深院風靜簾旌垂。", "策杖園林窮勝事，心遠尤驚塵世異。", "豈唯得助有江山，更却紅裙愛文字。", "金盤磊落百果裝，玉壺嘉醑浮清光。", "坐上風流俱鮑謝，况乃有子無他腸。", "酒行無算不可數，便欲飛身到仙府。", "忽然巨軸出長篇，媿我無言參也魯。", "笑呼適意談交情，共聽夜鶴鳴空庭。", "良辰美景賞心處，喜遂四者之難并。", "却將健句徐推拓，三歎餘音見依約。", "約去辭榮歸故鄉，贊我紛華滋味薄。", "次言奎畫在蓬門，乞與龍章照眼根。", "茲我謝氏如獲寶，報以瓊瑶未足論。", "我慙輔相初無補，偶爾逢時遇真主。", "但能奉此翰墨珍，庶若商那因考父。", "林間稚子獻殷勤，只爲君知愛厥親。", "遺羹美意見方冊，今此一舉如千鈞。", "君不見皇家已視金鑾草，趣君徑上長安道。", "忠臣須取孝子門，空谷行歌駒皎皎。"]'),
('20315f4a-3f15-4841-b0ee-b80b8face1a7','題蝸室','史浩','宋','宋诗','song-poetry','','[]','平生喜善類，遇之以青目。',108,'全唐诗/poet.song.115000.json','["平生喜善類，遇之以青目。", "廣厦千萬間，帡幪未渠足。", "唯予自棲身，三椽乃蝸縮。", "問之何爲然，知足常不辱。", "人生天地間，渺然如一粟。", "侈心纔動摇，曷厭溪壑欲。", "紙帳煖有餘，蒲團眠易熟。", "神遊萬物表，不慮此局促。", "門外競軒冕，卑哉蠻與觸。"]'),
('f058ed0c-b2a7-4fe8-8802-7ed838a3c4c3','次韻曇師以某焚三代贈黄所示長句','史浩','宋','宋诗','song-poetry','','[]','霽天破曉嚴清霜，宿具贈帛羅豆觴。',248,'全唐诗/poet.song.115000.json','["霽天破曉嚴清霜，宿具贈帛羅豆觴。", "旌旗蔽野氣軒昂，夾岸更復飛舟航。", "金爐細爇百和香，絳籠然蠟影交光。", "問予何事出柴桑，爲指白雲山中央。", "岩岩雙表鶴翅張，松楸靄靄摩青蒼。", "漸登幽域至饗堂，向來百物陳滿床。", "錦囊綸誥列前行，奠酌器皿皆琳琅。", "祝言小子心不遑，幾年恤典篋笥藏。", "抵今方獲燔贈黄，覬靈來兮染指嘗。", "潛德既拜天褒揚，後嗣感激兩淚滂。", "帝恩欲報方思量，忽睹健句如栢梁。", "葩華盈軸艷春陽，建安七子誰可當。", "何止李杜萬丈長。", "再四披閲予敢忘，同來親賓皆在旁。", "共詫粲可能文章，其中一客起鳴吭。", "衆駭何爲色不康，未甘釋子侵予疆。"]'),
('b7eaa75a-f24b-4090-a94a-9667da68de60','走筆次韻寄平元衡禪老','史浩','宋','宋诗','song-poetry','','[]','年來管城不脫帽，只羨夫君詩法好。',96,'全唐诗/poet.song.115000.json','["年來管城不脫帽，只羨夫君詩法好。", "怡雲剝啄到雲寮，始知春風屬此老。", "憶昔代匱持鈞衡，紅塵瘦馬太忙生。", "自從得請歸吾里，常與鹿豕爲羣行。", "有時片月隨杖屨，飄飄灑灑欲仙去。", "去尋杖錫四明中，聽取怡雲末後句。"]'),
('c472bb4f-b977-4500-ba1a-f377575c3e2e','次韻戲酬張以道','史浩','宋','宋诗','song-poetry','','[]','新詩韻清越，宛若泗濱磬。',48,'全唐诗/poet.song.115000.json','["新詩韻清越，宛若泗濱磬。", "呼兒誦終篇，悠揚久無定。", "渾欲挽斯人，歲晚共三徑。", "爛飲煙蘿間，不知夕陽暝。"]'),
('4c1973bc-9366-477a-8e29-f329695901e5','次韻張漢卿夢庵十八詠 夢庵','史浩','宋','宋诗','song-poetry','','[]','茲庵路何許，雲深不知處。',24,'全唐诗/poet.song.115000.json','["茲庵路何許，雲深不知處。", "夢覺兩俱忘，始可驀直去。"]'),
('8ecd6d9c-9342-4e01-a3dd-8dced30033c8','次韻張漢卿夢庵十八詠 勤齋','史浩','宋','宋诗','song-poetry','','[]','默豈交摩詰，談何事阿戎。',24,'全唐诗/poet.song.115000.json','["默豈交摩詰，談何事阿戎。", "時行百物生，不息唯天工。"]'),
('2c15f3e3-72e0-4d94-8906-111dfb8123c2','次韻張漢卿夢庵十八詠 妙用寮','史浩','宋','宋诗','song-poetry','','[]','空中一物無，於焉生萬有。',24,'全唐诗/poet.song.115000.json','["空中一物無，於焉生萬有。", "向此求神通，杯棬即非柳。"]'),
('7949ec1b-4b6d-4038-9c2d-f2a165ca67f3','次韻張漢卿夢庵十八詠 玉沼','史浩','宋','宋诗','song-poetry','','[]','一泓湛無滓，遶砌如天成。',24,'全唐诗/poet.song.115000.json','["一泓湛無滓，遶砌如天成。", "鬚眉徹底見，風浪何曾生。"]'),
('d6915cb3-a8d2-4745-b8c2-8e86b7170ef9','次韻張漢卿夢庵十八詠 碧溪庵','史浩','宋','宋诗','song-poetry','','[]','煙嵐染秋黛，潺潺逕大空。',24,'全唐诗/poet.song.115000.json','["煙嵐染秋黛，潺潺逕大空。", "平疇藉光及，比屋饒千鍾。"]'),
('926145ce-7735-4b9e-932e-cd03316db203','次韻張漢卿夢庵十八詠 山房','史浩','宋','宋诗','song-poetry','','[]','平生安樂地，不受利名煎。',24,'全唐诗/poet.song.115000.json','["平生安樂地，不受利名煎。", "其中一空洞，寥寥無色天。"]'),
('c53aeaed-3e8e-48e9-92af-56032486cc1e','次韻張漢卿夢庵十八詠 喜老堂','史浩','宋','宋诗','song-poetry','','[]','生處本恬淡，得失誠酸辛。',24,'全唐诗/poet.song.115000.json','["生處本恬淡，得失誠酸辛。", "婆娑鬢漸秋，天地一閒人。"]'),
('e461d2eb-a6bb-44b0-9545-7f9b77cb9bcf','次韻張漢卿夢庵十八詠 宴默庵','史浩','宋','宋诗','song-poetry','','[]','法門建章富，法幢空處成。',24,'全唐诗/poet.song.115000.json','["法門建章富，法幢空處成。", "於此下一則，浮雲涴太清。"]'),
('20fa6b99-4af2-4f51-90f0-b67ff91d3f68','次韻張漢卿夢庵十八詠 衆香堂','史浩','宋','宋诗','song-poetry','','[]','穠薰知見林，燕坐觀物化。',24,'全唐诗/poet.song.115000.json','["穠薰知見林，燕坐觀物化。", "鼻孔如撩天，可聞不可畫。"]'),
('763a4854-d273-4bd4-a5d9-905d8117ba48','次韻張漢卿夢庵十八詠 禪窟','史浩','宋','宋诗','song-poetry','','[]','胸中炯明月，一照萬緣空。',24,'全唐诗/poet.song.115000.json','["胸中炯明月，一照萬緣空。", "蟬蛻雲霄表，墮地爲儒宗。"]'),
('d973a47b-3bde-42fb-b7fd-b70534ed5472','次韻張漢卿夢庵十八詠 隠山巖','史浩','宋','宋诗','song-poetry','','[]','夫君活國手，愛此隠仙字。',24,'全唐诗/poet.song.115000.json','["夫君活國手，愛此隠仙字。", "行再出刀圭，可使民久視。"]'),
('717f6c7e-de82-48b2-aa9d-1ffd8fb18df5','次韻張漢卿夢庵十八詠 霞外','史浩','宋','宋诗','song-poetry','','[]','注目眇無際，彤雲燦晚暾。',24,'全唐诗/poet.song.115000.json','["注目眇無際，彤雲燦晚暾。", "心融八極表，欲辯已忘言。"]'),
('b590bd70-544b-4771-a211-9efb186ec291','次韻張漢卿夢庵十八詠 駐屐','史浩','宋','宋诗','song-poetry','','[]','緩步一徙倚，細數新條枚。',24,'全唐诗/poet.song.115000.json','["緩步一徙倚，細數新條枚。", "悠然得真趣，獨立遲誰來。"]'),
('8ca46b7c-fbca-471c-b91c-3db85cf02227','次韻張漢卿夢庵十八詠 月林','史浩','宋','宋诗','song-poetry','','[]','蟾窟有奇芳，殖根此茂密。',24,'全唐诗/poet.song.115000.json','["蟾窟有奇芳，殖根此茂密。", "人間萬種香，企之不可及。"]'),
('e8e21ea6-ca76-4356-a3d2-4c74bb19dc3e','次韻張漢卿夢庵十八詠 積翠','史浩','宋','宋诗','song-poetry','','[]','萬疊互團繞，風煙朝夕俱。',24,'全唐诗/poet.song.115000.json','["萬疊互團繞，風煙朝夕俱。", "三穴已掃竟，無復藏妖狐。"]'),
('7a0319a5-bc38-41b3-a1b8-db5af987acbd','次韻張漢卿夢庵十八詠 醉宜','史浩','宋','宋诗','song-poetry','','[]','何人過三徑，共此麴糱春。',24,'全唐诗/poet.song.115000.json','["何人過三徑，共此麴糱春。", "月下倩人扶，花影鋪滿身。"]'),
('10023e7a-cff0-46a7-bd91-733eec81fdf4','次韻張漢卿夢庵十八詠 澄漪','史浩','宋','宋诗','song-poetry','','[]','濯纓與濯足，均是滄浪水。',24,'全唐诗/poet.song.115000.json','["濯纓與濯足，均是滄浪水。", "箇裏不勝清，渭神爽應泚。"]'),
('cbbbeee0-78e5-4aa5-a700-5e16422927fe','次韻張漢卿夢庵十八詠 聽松','史浩','宋','宋诗','song-poetry','','[]','灑然清泠吹，過我十八公。',24,'全唐诗/poet.song.115000.json','["灑然清泠吹，過我十八公。", "颼飀喧宇宙，可奈此孤叢。"]'),
('219dddb9-a074-4c00-ae6e-b082e37f9413','走筆次韻張以道 石窗','史浩','宋','宋诗','song-poetry','','[]','嘗聞皮陸句，未覩心先降。',48,'全唐诗/poet.song.115000.json','["嘗聞皮陸句，未覩心先降。", "于今煩鬼工，徙置排金釭。", "蕙帳擁猿鶴，石磴來旌幢。", "月明風亦靜，篆煙浮四窗。"]'),
('337eddc3-2d6d-4082-ac5c-70f8131a0403','走筆次韻張以道 過雲','史浩','宋','宋诗','song-poetry','','[]','雲埋路欲迷，獨許幽人過。',48,'全唐诗/poet.song.115000.json','["雲埋路欲迷，獨許幽人過。", "時從客子來，更尋深處坐。", "抵掌到幽眇，萬事俱識破。", "茫茫名利人，糠粃不足簸。"]'),
('859ccfae-c8c0-412b-b36a-e477e0b25648','走筆次韻張以道 雲南','史浩','宋','宋诗','song-poetry','','[]','空洞遠萬里，佳景萃其南。',48,'全唐诗/poet.song.115000.json','["空洞遠萬里，佳景萃其南。", "縠紋波似染，螺髻花羣簪。", "紫芝鮮最馥，青櫺堅直甘。", "解召羨門侶，雙鸞聊與驂。"]'),
('feb3504e-4380-427e-a400-3915699163bf','走筆次韻張以道 雲北','史浩','宋','宋诗','song-poetry','','[]','幽巖列仙貌，陰雪如粉撲。',48,'全唐诗/poet.song.115000.json','["幽巖列仙貌，陰雪如粉撲。", "矧當摇落時，宛見沙漠北。", "朔風吹不動，中有難凋木。", "吾嘗愛此景，小駐葛陂竹。"]'),
('af6a07b7-8de0-4316-9a1f-c530df4c56de','走筆次韻張以道 鹿亭','史浩','宋','宋诗','song-poetry','','[]','雙鹿處岩隈，似有人性靈。',48,'全唐诗/poet.song.115000.json','["雙鹿處岩隈，似有人性靈。", "山童自馴擾，俗客必心驚。", "循除水濈濈，竹暗藏幽亭。", "有時带露歸，濈濈身有青。"]'),
('75f0f635-b7e8-4d7f-9cdf-569a671083cd','走筆次韻張以道 樊榭','史浩','宋','宋诗','song-poetry','','[]','何年樊仙翁，踞此作雲榭。',48,'全唐诗/poet.song.115000.json','["何年樊仙翁，踞此作雲榭。", "境勝唯清凉，寒燠匪冬夏。", "俯觀塵世人，杳在萬仞下。", "漸次入真境，還如倒食蔗。"]'),
('f5f891bf-bc99-46c9-81f3-1e3c29cd6397','走筆次韻張以道 潺湲洞','史浩','宋','宋诗','song-poetry','','[]','萬派漱寒玉，及此猶潺湲。',48,'全唐诗/poet.song.115000.json','["萬派漱寒玉，及此猶潺湲。", "臨流覿毛髮，體粟生輕寒。", "餘波蕩塵氛，一洗清塵寰。", "觀瀾得妙理，用處心常閒。"]'),
('8b8ee212-3b3f-4ffc-991b-8b3ece172c03','走筆次韻胡中方賞丹桂之什','史浩','宋','宋诗','song-poetry','','[]','粟蕊摶金葉凝碧，獨在秋林逞顔色。',256,'全唐诗/poet.song.115000.json','["粟蕊摶金葉凝碧，獨在秋林逞顔色。", "豈知東溟史氏居，別有奇標人不識。", "嫦娥侍女盈萬千，一一姿貌皆無前。", "爲厭此花忒淡薄，渥丹乞與春爭妍。", "媒滋燕脂霜染蒨，殖根只向廣寒殿。", "幾塵俗韻不可干，清凉唯許金風扇。", "何年移到蓬萊鄉，鉅萬索直誰敢償。", "盤紆欄檻久不曜，一日名飛羣國香。", "豪貴爭看期縮地，載酒遲來煩鼓吹。", "園丁聞之競采擷，夜深不使花神睡。", "接枝換骨離四明，飄飄爽氣排妖氛。", "遂令禁篽成真賞，餘馨賸馥常氤氳。", "芙蓉寒菊不足數，包羞正似無鹽女。", "從渠摇落動秋聲，獨步唯茲徧寰宇。", "我嘗對此傾葵金，却思四海狀元心。", "殷勤勸花宜且住，寒士人人折得去。"]'),
('4342f306-d0f1-47bc-b849-1c63c5cb4e40','贈別王虛中平江贍軍','史浩','宋','宋诗','song-poetry','','[]','愛子詩無敵，清新日造微。',48,'全唐诗/poet.song.115000.json','["愛子詩無敵，清新日造微。", "解顔方一笑，折柳遽成歸。", "蘇館凝香重，松江膾玉肥。", "是中如得句，無惜寄柴扉。"]'),
('3db0cb99-c6ff-4e99-a23a-3b83aea2fb4d','次韻趙若拙酴醾','史浩','宋','宋诗','song-poetry','','[]','春去雪又在，夜寒風自香。',48,'全唐诗/poet.song.115000.json','["春去雪又在，夜寒風自香。", "娉婷白玉面，縹緲碧雲裳。", "露下已侵袂，月明初度牆。", "婆娑光影下，老子坐胡床。"]'),
('22ac92bc-157c-4d79-ae4d-83c41c4d14e9','次韻劉國正立春','史浩','宋','宋诗','song-poetry','','[]','百歲今强半，逢春却怕春。',48,'全唐诗/poet.song.115000.json','["百歲今强半，逢春却怕春。", "趁時三盞酒，轉眼一年人。", "車馬繁華地，江湖漫浪身。", "茅簷擁殘雪，清夢到家頻。"]'),
('11619308-fff6-4916-ae40-729babfebfbc','秋荷十韻','史浩','宋','宋诗','song-poetry','','[]','漲碧湖方迥，嬌紅藕競芳。',120,'全唐诗/poet.song.115000.json','["漲碧湖方迥，嬌紅藕競芳。", "已疑星斗下，仍訝錦雲張。", "脈脈初離立，盈盈忽綴行。", "煙藏何限思，雨送不勝香。", "解佩皋臨漢，聞弦浦近湘。", "向來便看此，欲去未渠央。", "葉好嗔兒摘，蓬新喚客嘗。", "更禁和月淡，直思付風狂。", "得載平生酒，閒鳴盡日榔。", "甘將百詩詠，恣弄水仙鄉。"]'),
('cc50dd35-653d-4d76-ac85-5591cc2a98a8','次韻恩平郡王','史浩','宋','宋诗','song-poetry','','[]','彤庭秋晚宴，和氣與春同。',48,'全唐诗/poet.song.115000.json','["彤庭秋晚宴，和氣與春同。", "壽酒千鍾綠，宮化萬疊紅。", "金羈鸞仗底，赤舄玉階中。", "歸路聞人語，關雎誦國風。"]'),
('e4773544-0e23-4fa8-ab79-5c7e9b1f90b7','次韻恩平郡王游山登寺中小閣','史浩','宋','宋诗','song-poetry','','[]','天邊倚蕭寺，小閣翠微中。',48,'全唐诗/poet.song.115000.json','["天邊倚蕭寺，小閣翠微中。", "煙靄三峯秀，松杉一徑通。", "潮音從耳悟，塵慮轉頭空。", "堪笑林間弋，猶思落塞鴻。"]'),
('61420e89-dbbb-4b4f-b7b4-3dfd9b79cf7d','和建王明遠樓','史浩','宋','宋诗','song-poetry','','[]','天闕移樓觀，來供帝子親。',96,'全唐诗/poet.song.115000.json','["天闕移樓觀，來供帝子親。", "明光扶日域，遠勢接星津。", "瑞靄常濛潤，清風每拂塵。", "圖書惟左右，脂粉却參辰。", "覓句多詩髓，開談即道真。", "槐陰瞻五學，芸馥見三神。", "雨露恩方渥，江山景倍新。", "願言增萬柱，寒士並棲身。"]'),
('74d612fa-7b75-4f57-b9b3-46184ee12dae','送杜殿院出守遂寧','史浩','宋','宋诗','song-poetry','','[]','萬里徠西蜀，聲華振士林。',48,'全唐诗/poet.song.115000.json','["萬里徠西蜀，聲華振士林。", "匪躬無近援，聖主作知音。", "已破姦邪膽，方勞撫字心。", "政成須趣駕，天下仰爲霖。"]'),
('d8991a8b-af40-4437-ab21-8705910c68c0','次韻姚令威郎中從駕早行  其一','史浩','宋','宋诗','song-poetry','','[]','姚馬真人傑，英標貫伏犀。',48,'全唐诗/poet.song.115000.json','["姚馬真人傑，英標貫伏犀。", "脩途隨上下，軟語雜高低。", "扈蹕俱多士，揚鞭過萬蹄。", "伊余茲濫吹，所喜發鵾雞。"]'),
('e90b241f-9f8d-4024-a806-0096097325a1','次韻姚令威郎中從駕早行  其二','史浩','宋','宋诗','song-poetry','','[]','蔌蔌長空雪，霏霏似粉犀。',48,'全唐诗/poet.song.115000.json','["蔌蔌長空雪，霏霏似粉犀。", "色同無路險，野闊見山低。", "玉葆隨鸞仗，銀杯逐馬蹄。", "催班何太早，夜白悞晨雞。"]'),
('1246827d-d614-4631-af7d-a845e072021a','次韻姚令威郎中從駕早行  其三','史浩','宋','宋诗','song-poetry','','[]','大駕遐方國，熊羆間象犀。',48,'全唐诗/poet.song.115000.json','["大駕遐方國，熊羆間象犀。", "風嚴知令正，雲重覺天低。", "夾道瞻芝表，中原逐獸蹄。", "定宣恢復赦，拭目看金雞。"]'),
('8cb7fdba-df3f-44a5-af02-cec2350c546b','次韻姚令威郎中從駕早行  其四','史浩','宋','宋诗','song-poetry','','[]','聖主披英俊，公才是擢犀。',48,'全唐诗/poet.song.115000.json','["聖主披英俊，公才是擢犀。", "班揚俱氣懾，屈宋亦眉低。", "健鶻摩天翼，真媒歷塊蹄。", "回眸看賤子，下駟與鵾雞。"]'),
('e74d4bc2-284b-4e51-b0d5-2ac5ec756f9d','次韻姚令威郎中從駕早行  其五','史浩','宋','宋诗','song-poetry','','[]','有美風騷將，詞鋒利更犀。',48,'全唐诗/poet.song.115000.json','["有美風騷將，詞鋒利更犀。", "胸吞雲夢小，氣壓斗牛低。", "鷙鳥常舒翼，名駒豈鑿蹄。", "不能勝百戰，渾欲介吾雞。"]'),
('5e8ad201-4a9d-4b78-8ae5-c27564815125','曉起用前韻','史浩','宋','宋诗','song-poetry','','[]','破曉窮幽眺，端知翫月犀。',48,'全唐诗/poet.song.115000.json','["破曉窮幽眺，端知翫月犀。", "雪消青嶂近，天淡玉繩低。", "出塞三春翼，嘶風萬里蹄。", "男兒弧矢志，何事飯籠雞。"]'),
('7e55a15c-e777-4257-89de-7af0eb67642b','晨興懷寺中用前韻','史浩','宋','宋诗','song-poetry','','[]','薛公言慷慨，端可諷馴犀。',48,'全唐诗/poet.song.115000.json','["薛公言慷慨，端可諷馴犀。", "器廣蜃江小，名高雁嶺低。", "宸居清瑣闥，禁路紫騮蹄。", "揆德宜長處，何因夢白雞。"]'),
('7d7cda1a-6df1-4bcd-ada0-f6bc4342637c','同遊賞心亭用前韻  其一','史浩','宋','宋诗','song-poetry','','[]','古堞高千雉，危亭屹巨犀。',48,'全唐诗/poet.song.115000.json','["古堞高千雉，危亭屹巨犀。", "雲霄知路近，星斗入簷低。", "山繚龍盤脊，江涵虎踞蹄。", "相携倚秋閣，得失付蟲雞。"]'),
('151d1ba5-e520-44dd-a635-468d0a675ed0','同遊賞心亭用前韻  其二','史浩','宋','宋诗','song-poetry','','[]','賞心多樂事，快目喜聯犀。',48,'全唐诗/poet.song.115000.json','["賞心多樂事，快目喜聯犀。", "雪浪翻空急，江雲過眼低。", "天寒風着袂，興盡馬旋蹄。", "歸路仍泥滑，林間語竹雞。"]'),
('0ad256df-dba4-44e2-98e3-c87c5ebf966b','次韻洪景盧右司問梅','史浩','宋','宋诗','song-poetry','','[]','東皇榮萬木，首倡屬江梅。',48,'全唐诗/poet.song.115000.json','["東皇榮萬木，首倡屬江梅。", "得地應先發，須時不受催。", "可堪連日冷，未忍一樽開。", "竹外摇殘雪，知君到幾回。"]'),
('ab31eacc-26bf-4649-a639-5b2d98f3e5ca','次韻皇孫所和二詩  其一','史浩','宋','宋诗','song-poetry','','[]','錦繡環清蹕，祥雲捧日華。',48,'全唐诗/poet.song.115000.json','["錦繡環清蹕，祥雲捧日華。", "千官鵷鷺集，萬騎虎貔誇。", "餘孽皇威遠，中原望眼賒。", "遥憐太液水，波煖欲生花。"]'),
('349fe289-74be-474c-b807-8e466109f741','次韻皇孫所和二詩  其二','史浩','宋','宋诗','song-poetry','','[]','歲晚垂弧旦，雍容從北征。',48,'全唐诗/poet.song.115000.json','["歲晚垂弧旦，雍容從北征。", "龍舟瞻日表，兔苑足詩情。", "况有流霞美，何辭醉玉傾。", "祝君無限壽，煙閣寄功名。"]'),
('18487a82-c0e1-4026-8960-4ebd536092b1','餞馮圓中吏部出守','史浩','宋','宋诗','song-poetry','','[]','蚤歲登巍第，即潛正黑頭。',48,'全唐诗/poet.song.115000.json','["蚤歲登巍第，即潛正黑頭。", "一封憂國慮，五馬便鄉州。", "筆底平生學，胸中康濟謀。", "勝須勤蓄積，聖主欲兼收。"]'),
('31b08173-a4c8-4ef4-bb26-575299c0b9fa','進明堂慶成詩','史浩','宋','宋诗','song-poetry','','[]','六閲淳熙禩，秋高日仲辛。',168,'全唐诗/poet.song.115000.json','["六閲淳熙禩，秋高日仲辛。", "大君敷渙號，重屋薦明禋。", "玉輅興清廟，龍旂亙紫宸。", "雲陰連夜解，霽色一朝新。", "周禮樽罍備，虞韶樂舞陳。", "合宮天地並，侑席祖宗均。", "峻墄登三獻，脩楹秩百神。", "肅祗伸睿意，肸蠁降高旻。", "宣室宜膺福，慈闈亟拱宸。", "簪花馳萬騎，歸胙見雙親。", "釐事超隆古，年齡肇億春。", "蓼蕭覃有截，成命播無垠。", "惠餕頒羣后，恩波逮老臣。", "祝堯非健筆，徒學華封人。"]'),
('0a806e59-c70b-4ff1-b996-4f76020739fd','經筵讀正說終篇恭進謝恩感遇詩','史浩','宋','宋诗','song-poetry','','[]','帝祚隆三葉，仁風被九垠。',132,'全唐诗/poet.song.115000.json','["帝祚隆三葉，仁風被九垠。", "泥金封禪後，汗簡典墳新。", "祖訓敷皇極，奎星耀紫宸。", "儒家尊首志，文論歉前塵。", "好生兵遂偃，崇儉俗還淳。", "傳寶參河洛，重光待聖神。", "求講深紬繹，退訪極諮詢。", "治紹堯稽古，歡諧舜事親。", "披編茲有獲，徹卷豈辭頻。", "錫予恩波浹，榮華宴俎陳。", "奏詩無傑句，拜手愧名臣。"]'),
('91f8c0f7-54a2-4e7c-970b-4c6397e3a82a','次韻孫季和東湖二詩  其一','史浩','宋','宋诗','song-poetry','','[]','出郭乘清興，扁舟一迅風。',48,'全唐诗/poet.song.115000.json','["出郭乘清興，扁舟一迅風。", "山光真黛比，水色與天同。", "宿鷺班班白，寒楓處處紅。", "誰知吾勝槩，名冠甬勾東。"]'),
('3fc44ab7-3320-4b9a-bc8a-d84351b33eb3','次韻孫季和東湖二詩  其二','史浩','宋','宋诗','song-poetry','','[]','水拭雙鸞鏡，山環六曲屏。',48,'全唐诗/poet.song.115000.json','["水拭雙鸞鏡，山環六曲屏。", "雲端迸朝日，木杪見踈星。", "梅塢春長在，柴門夜不扃。", "援琴誰寫景，思得與君聽。"]'),
('20133179-8ac6-4f9e-a54c-4a158684b4a8','送安之往依沈叔晦師席','史浩','宋','宋诗','song-poetry','','[]','吾孫年甫冠，抗志在青冥。',48,'全唐诗/poet.song.115000.json','["吾孫年甫冠，抗志在青冥。", "重趼輕千里，求師爲一經。", "功名適來去，器識是丁寧。", "既得賢模範，歸歟喜過庭。"]'),
('dceac525-50e2-414d-8e1f-1f719aab48ab','蟻王得知字','史浩','宋','宋诗','song-poetry','','[]','蠢蠢稱螻蟻，尊王世所知。',48,'全唐诗/poet.song.115000.json','["蠢蠢稱螻蟻，尊王世所知。", "峻臺存主禮，環穴受臣儀。", "依戰如揚武，排行似出師。", "南柯雖一夢，治國得良規。"]'),
('404b0e7a-9a1c-4186-bce5-06f09f1f8249','蜃樓得生字','史浩','宋','宋诗','song-poetry','','[]','青蘋風乍息，巨浸欲潮平。',48,'全唐诗/poet.song.115000.json','["青蘋風乍息，巨浸欲潮平。", "毒霧方看吐，層樓忽已成。", "憑欄無海若，吞鳥類羅生。", "安得揮長劍，驅除致永清。"]'),
('d3e6c261-00e8-40d6-8722-2ec8b0da0bd1','蛩吟得時字','史浩','宋','宋诗','song-poetry','','[]','蟲唯蜻蛚類，近漸實知時。',48,'全唐诗/poet.song.115000.json','["蟲唯蜻蛚類，近漸實知時。", "露重哦寒曉，更深攬夜思。", "堂中譏晉什，床下誦幽詩。", "唧唧俱成詠，何曾撚斷髭。"]'),
('9555e39a-d96c-49fe-b955-cd2167a8d9d3','花鬚得中字','史浩','宋','宋诗','song-poetry','','[]','花有千跗萼，藏鬚向箇中。',48,'全唐诗/poet.song.115000.json','["花有千跗萼，藏鬚向箇中。", "怒張擎曉日，笑翦寄春風。", "蚪捲香絲亂，龍掀膩粉叢。", "露霑尤的皪，唾玉在髼鬉。"]'),
('8e8ed5b5-2d3a-4220-9e20-7caaf67c656b','柳带得歸字','史浩','宋','宋诗','song-poetry','','[]','渭水亭亭柳，春柔可綰衣。',48,'全唐诗/poet.song.115000.json','["渭水亭亭柳，春柔可綰衣。", "煙添染黛色，風束舞腰圍。", "對影同心在，攀條解賜歸。", "行人繫不住，結綬上王畿。"]'),
('d7218ab0-27b7-4667-8f0b-1ee7b01739f9','雪消得寒字','史浩','宋','宋诗','song-poetry','','[]','同雲收萬里，愛日已三竿。',48,'全唐诗/poet.song.115000.json','["同雲收萬里，愛日已三竿。", "見睍將潛迹，無風特地寒。", "晴簷如下雨，槁澗忽鳴湍。", "漸覺山河復，方知世界寬。"]'),
('91acbe6a-1083-4f6b-b203-eba76a56084d','雨絲得秋字','史浩','宋','宋诗','song-poetry','','[]','千絲棼不亂，細雨忽盈眸。',48,'全唐诗/poet.song.115000.json','["千絲棼不亂，細雨忽盈眸。", "密密如機捲，踈踈豈繭抽。", "紉裳難作縫，欲釣不勝鈎。", "霢霂知何事，收功在有秋。"]'),
('b6b7413b-2529-49e6-9063-eb6813d24ffe','豆粥得容字','史浩','宋','宋诗','song-poetry','','[]','殘臘風霜勁，嘉賓嘉會逢。',48,'全唐诗/poet.song.115000.json','["殘臘風霜勁，嘉賓嘉會逢。", "清泉雲子滑，熟末桂香濃。", "金谷咄嗟具，蕪蔞倉猝供。", "爭如金雅宴，樽酒共舂容。"]'),
('5dfe9c64-c21e-4c94-ad15-97faa61816c5','水仙花得看字','史浩','宋','宋诗','song-poetry','','[]','奇姿擅水仙，長向雪中看。',48,'全唐诗/poet.song.115000.json','["奇姿擅水仙，長向雪中看。", "翠碧瑶簪盍，鵝黄粉袂攢。", "夜闌香苒苒，風過珮珊珊。", "著在冰霜裏，姮娥御廣寒。"]'),
('78a770a2-7b75-4d84-8558-b5be4faf16ea','鍾馗圖得人字','史浩','宋','宋诗','song-poetry','','[]','虬鬚張怒目，藍綬嚲烏巾。',48,'全唐诗/poet.song.115000.json','["虬鬚張怒目，藍綬嚲烏巾。", "抃舞身無定，驅除夢有神。", "收功祛瘧鬼，流詠起唐人。", "圖畫高懸處，明朝慶履新。"]'),
('2a943631-7057-4788-948d-7e0997b22ded','椒盤得多字','史浩','宋','宋诗','song-poetry','','[]','有美椒盤獻，三朝慶始和。',48,'全唐诗/poet.song.115000.json','["有美椒盤獻，三朝慶始和。", "靈莖叢玉敦，醖酒滿金荷。", "不向湯銘見，其如晉頌何。", "欲知勤祝處，功在歷年多。"]'),
('b945a040-d0f0-497d-8f78-af3abc5fa1d1','詩社得神字','史浩','宋','宋诗','song-poetry','','[]','今宵文會友，作句擅清新。',48,'全唐诗/poet.song.115000.json','["今宵文會友，作句擅清新。", "始也詩言志，終焉筆有神。", "既無折角者，寧有面牆人。", "只待逢真主，艱難七月陳。"]'),
('be42b6c9-074f-4931-87f8-8c13e5173b2b','叔父知縣慶宅并章服','史浩','宋','宋诗','song-poetry','','[]','芝檢熒熒金縷黄，拜恩初捧鵲爐香。',64,'全唐诗/poet.song.115000.json','["芝檢熒熒金縷黄，拜恩初捧鵲爐香。", "花籠麗日暉朱綬，燕啄新泥上畫梁。", "歌遏行雲鶑睍睆，舞飄回雪蝶輕狂。", "一巵競祝雙椿老，佇看于飛到玉堂。"]'),
('ce92a0f2-11f2-416a-ad3a-8f2e8a683451','次韻權郡錢直閣鹿鳴宴','史浩','宋','宋诗','song-poetry','','[]','去去無材策治安，全資風力助輕翰。',64,'全唐诗/poet.song.115000.json','["去去無材策治安，全資風力助輕翰。", "欲平紫氣頻侵斗，當倩中書爲脫冠。", "香入梅梢春意近，德將鯨飲玉杯殘。", "珠璣更復傳華衮，榮比青霄駕綵鸞。"]'),
('dbe7271d-567e-479d-8709-4bca02424ab1','次韻錢直閣和呂支鹽梅花','史浩','宋','宋诗','song-poetry','','[]','隠隠仙安迥出羣，朅來還是一番春。',64,'全唐诗/poet.song.115000.json','["隠隠仙安迥出羣，朅來還是一番春。", "山牆倚雪凝姑射，水國臨風詠洛神。", "清洗嬌腮全惡粉，快飛幽馥去朝真。", "直交別浦停三弄，羞作高樓欲墜人。"]'),
('b3d2d589-4659-4e3f-85ef-f64c839e96ba','次韻汪元舉以詩覓時季和海棠花栽','史浩','宋','宋诗','song-poetry','','[]','一紙淋漓醉墨鮮，錦囊連夜到溪邊。',64,'全唐诗/poet.song.115000.json','["一紙淋漓醉墨鮮，錦囊連夜到溪邊。", "搜求仙種寧辭遠，惱亂花神不使眠。", "弄影未看妃子態，補亡先得少陵篇。", "明年應向東風裏，百遶雕欄玉步連。"]'),
('c417961e-a416-426e-b1ed-0022d4d413d6','次韻王正之驚蟄有感言歸','史浩','宋','宋诗','song-poetry','','[]','聞說天家起阿香，攬桃催杏臉無央。',64,'全唐诗/poet.song.115000.json','["聞說天家起阿香，攬桃催杏臉無央。", "夜蟾不解照仙李，朝雨何妨夢楚王。", "知買扁舟成折柳，賸哦佳句作甘棠。", "故園風物雖云好，何必歸程遽許忙。"]'),
('720cd77f-f15b-4477-bbcb-acb793c02409','次韻范經幹昆季昌國雜詠 酴醾花','史浩','宋','宋诗','song-poetry','','[]','滿架猶煩雪作英，年年嚮此眼偏明。',64,'全唐诗/poet.song.115000.json','["滿架猶煩雪作英，年年嚮此眼偏明。", "春遲故欲牡丹伴，韻勝還馳雅客名。", "縹緲碧裳留夜月，娉婷玉面起朝酲。", "却嫌梅蕊無才思，零落蒼苔爲笛聲。"]'),
('b5dd90b3-58f8-4ffa-bcb7-4ab93fed4b63','江倅出家樂','史浩','宋','宋诗','song-poetry','','[]','沈沈春酌話綢繆，花月行船看拍浮。',64,'全唐诗/poet.song.115000.json','["沈沈春酌話綢繆，花月行船看拍浮。", "手束柔荑調雁柱，袖翻紋錦出香毬。", "未攀青子猶如豆，欲膾赬鱗始上鈎。", "蓬島古來無覓處，我曹今此得真游。"]'),
('cd45ca38-64ea-4dc9-9056-d576aad31e4f','范幹招兄顯道','史浩','宋','宋诗','song-poetry','','[]','片帆落處是三山，絕景塵居了不關。',64,'全唐诗/poet.song.115000.json','["片帆落處是三山，絕景塵居了不關。", "夢草池塘如有得，對床風雨亦非艱。", "騎鯨渡海風生腋，揮麈談玄笑滿顔。", "從此清名追二陸，錦囊賡和不容閒。"]'),
('70197e61-9f00-4f6e-a9ef-6d5526789d08','雜興  其一','史浩','宋','宋诗','song-poetry','','[]','人言銓選異堂除，我笑茲言亦太迂。',64,'全唐诗/poet.song.115000.json','["人言銓選異堂除，我笑茲言亦太迂。", "四海九州均一治，六曹三省豈殊途。", "春風到處林無槁，夏雨通時物盡濡。", "會得只將忠實報，門生恩府漫稱呼。"]'),
('ada80637-5d01-4150-9d81-1af5dee95048','雜興  其二','史浩','宋','宋诗','song-poetry','','[]','世間諛佞枉求多，忠實由來曷可磨。',64,'全唐诗/poet.song.115000.json','["世間諛佞枉求多，忠實由來曷可磨。", "謀寢兩淮須仗汲，亂消六館獨由何。", "當年烏府心無撓，今日鸞臺道不頗。", "若也隨時效諛佞，豈能功業許巍峩。"]'),
('f763022f-9146-405a-96b0-27f220801f8d','雜興  其三','史浩','宋','宋诗','song-poetry','','[]','人材莫謂世全無，用則賢良棄則愚。',64,'全唐诗/poet.song.115000.json','["人材莫謂世全無，用則賢良棄則愚。", "孔聖既生顔閔在，周家纔起甫申俱。", "歸恩報德還忠實，附熱趨炎屬佞諛。", "散盡田文門下客，獨餘馮子是名儒。"]'),
('d6e8b44c-d6dc-43d6-860e-02db17c34bcc','雜興  其四','史浩','宋','宋诗','song-poetry','','[]','世間無處是堅牢，富貴功名亦謾勞。',64,'全唐诗/poet.song.115000.json','["世間無處是堅牢，富貴功名亦謾勞。", "一昃一盈天外月，再生再汐海中潮。", "紅塵衮衮知何補，白髮駸駸誰得饒。", "加我數年專讀易，定須輕舉到煙霄。"]'),
('3d01fe54-4af9-4fce-bd5f-e057fe6502f5','送商築叟赴南省','史浩','宋','宋诗','song-poetry','','[]','少微燁燁瑞光開，壯士昂頭出草萊。',64,'全唐诗/poet.song.115000.json','["少微燁燁瑞光開，壯士昂頭出草萊。", "健筆佇傾三峽水，晴空爭聽一聲雷。", "恩承淡墨金門啟，宴錫奇花玉女栽。", "預想春風掉歸鞅，西郊翠靄上衣來。"]'),
('5b543aad-5ac9-4130-9886-e8602f3ae347','次韻商築叟雪','史浩','宋','宋诗','song-poetry','','[]','風威雲勢兩徘徊，故遣瑶花撲面來。',64,'全唐诗/poet.song.115000.json','["風威雲勢兩徘徊，故遣瑶花撲面來。", "兔苑芳菲談笑得，玉京門闕等閒開。", "光浮編簡渾疑月，香入杯觴始認梅。", "爲報寒鄉幾冰室，功成却擬放春回。"]'),
('70d31c0a-8ce6-4c26-a6ff-a56117c16497','上平江守徐侍郎生日  其一','史浩','宋','宋诗','song-poetry','','[]','翼軫騰光萬代尊，地靈人傑萃侯門。',64,'全唐诗/poet.song.115000.json','["翼軫騰光萬代尊，地靈人傑萃侯門。", "紫芝秀宇塵無染，黄憲澄波撓不渾。", "泥濕丹書雙彩鳳，香凝畫戟兩朱輪。", "生朝有客成飄泊，猶寄巢蓮碧玉樽。"]'),
('094b5ed4-58bb-49dc-8bea-f56e8bb6f4f2','上平江守徐侍郎生日  其二','史浩','宋','宋诗','song-poetry','','[]','時節文章與盛衰，我公端合振中微。',64,'全唐诗/poet.song.115000.json','["時節文章與盛衰，我公端合振中微。", "玉鋒修滿姮娥月，天巧分殘織女機。", "正始風流回治世，豫章宗派得傳衣。", "知音久矣煩牙頰，一瓣爐熏心所歸。"]'),
('e5966fcd-ce5f-4978-b1b7-bd404d12b534','上紹興守俞閣學生日  其一','史浩','宋','宋诗','song-poetry','','[]','扶輿光氣擁清苕，竦記真儒載誕朝。',64,'全唐诗/poet.song.115000.json','["扶輿光氣擁清苕，竦記真儒載誕朝。", "天令聿新青帝律，王正初御紫宸朝。", "已開師幕居東陝，行握臺符侍九霄。", "春醑如澠介眉壽，亦應兼喜頌陳椒。"]'),
('38b01fd4-8fa0-4b10-819d-73f2ec4c5cc1','上紹興守俞閣學生日  其二','史浩','宋','宋诗','song-poetry','','[]','試向黄堂壽我公，龐眉齯齒氣沖融。',64,'全唐诗/poet.song.115000.json','["試向黄堂壽我公，龐眉齯齒氣沖融。", "烏飛會看三松老，鯨飲何辭百榼空。", "的皪方瞳曜遲日，扶踈綠鬢受春風。", "摩挲銅狄長安道，肉眼它年記此翁。"]'),
('27c4a704-2ea8-4fa9-9952-0c6bba512653','上紹興守俞閣學生日  其三','史浩','宋','宋诗','song-poetry','','[]','自從㦸鉞臨東閫，戀戀車塵拜紫芝。',64,'全唐诗/poet.song.115000.json','["自從㦸鉞臨東閫，戀戀車塵拜紫芝。", "排霧已逢回阮眼，持蠡誰解測黄陂。", "知音不借一人譽，走驛聊馳千歲詩。", "桃李從今滿天下，月明烏鵲得依枝。"]'),
('9a697dae-e2c7-4c3a-aee6-a4cae20113a2','次韻高宰謝朱倅惠酒','史浩','宋','宋诗','song-poetry','','[]','仙廬深倚翠微間，酬答風煙肯暫閒。',64,'全唐诗/poet.song.115000.json','["仙廬深倚翠微間，酬答風煙肯暫閒。", "不遣長須干美政，却馳雙榼破愁顔。", "句高飯顆人應瘦，醉著河陽鬢未班。", "楚客秋情正無頼，併須乞取展眉山。"]'),
('889915d7-1d60-4120-91f3-9075c70e775d','上曹守徽猷生日  其一','史浩','宋','宋诗','song-poetry','','[]','東皇縹仗下層雲，來駕和風再浹辰。',64,'全唐诗/poet.song.115000.json','["東皇縹仗下層雲，來駕和風再浹辰。", "勳閥此時生鸑鷟，天家滿意抱麒麟。", "方瞳的皪輝遲日，綠鬢扶踈受早春。", "太史談公甚奇異，老人星即是前身。"]'),
('3f93f6e3-ed75-4a2e-8cd8-7aba6fff8c2d','上曹守徽猷生日  其二','史浩','宋','宋诗','song-poetry','','[]','天聖陰功天下母，慶源重此毓英髦。',64,'全唐诗/poet.song.115000.json','["天聖陰功天下母，慶源重此毓英髦。", "政區賢否澄冰鑑，詩得江山妙淚毫。", "已使列城歌既醉，可無衆口賦崧高。", "油幢誰道容溫席，行從君王宴碧桃。"]'),
('ceba76bf-5c4e-4c5a-95ed-a880191bb705','上高提舉生日  其一','史浩','宋','宋诗','song-poetry','','[]','淡蕩春光二月餘，鬰葱佳氣靄扶輿。',64,'全唐诗/poet.song.115000.json','["淡蕩春光二月餘，鬰葱佳氣靄扶輿。", "杏園高萼紅千顆，銀漢新蟾玉一梳。", "控鶴暫辭仙府籍，觀風聊擁使星車。", "香縈畫㦸簪裾盍，贏得長生幾卷書。"]'),
('eaba068c-b852-4c69-8a9a-9654194ba0ed','上高提舉生日  其二','史浩','宋','宋诗','song-poetry','','[]','聖主龍飛念故人，侯門雨露一番新。',64,'全唐诗/poet.song.115000.json','["聖主龍飛念故人，侯門雨露一番新。", "登瀛已寵皇華貴，被綵專榮白髮親。", "好語舊聞千歲鶴，仁風今扇七州春。", "定知福壽無邊際，坐看雲來舞繡茵。"]'),
('c8006846-67b8-4f98-b960-394ed1a80aee','擬進講筵尚書終篇錫宴詩  其一','史浩','宋','宋诗','song-poetry','','[]','煌煌典誥炳丹青，聖主于今集大成。',64,'全唐诗/poet.song.115000.json','["煌煌典誥炳丹青，聖主于今集大成。", "已究商周真灝噩，固知堯禹本聰明。", "神馳帝樂翔雲海，恩逐天香到酒觥。", "下拜龍威瞻咫尺，羣臣始覺倍光生。"]'),
('14c08704-00f3-431c-99a8-6bd595990227','擬進講筵尚書終篇錫宴詩  其二','史浩','宋','宋诗','song-poetry','','[]','蚤朝論道沃宸聰，更許經生侍九重。',64,'全唐诗/poet.song.115000.json','["蚤朝論道沃宸聰，更許經生侍九重。", "萬卷精微歸一覽，小儒糟粕受三冬。", "明兼舜目超唐漢，宴錫需雲法祖宗。", "愧乏涓塵裨海嶽，今辰亦得奉舂容。"]'),
('0824ffaa-80fa-4ad7-bc92-b0d95fab2b60','寄題蔣學正三徑庵  其一','史浩','宋','宋诗','song-poetry','','[]','浮名兩角競蝸牛，舉世誰人肯罷休。',64,'全唐诗/poet.song.115000.json','["浮名兩角競蝸牛，舉世誰人肯罷休。", "鼻祖獨能輕漢魏，耳孫寧不慕羊求。", "似聞竹外三家市，猶占溪頭十里秋。", "安得枯藤破煙暝，細尋佳處賦清幽。"]'),
('4b210aa0-69dc-4397-a1f9-abb98923040e','寄題蔣學正三徑庵  其二','史浩','宋','宋诗','song-poetry','','[]','紛紛俗子信么麽，過眼何須問唯阿。',64,'全唐诗/poet.song.115000.json','["紛紛俗子信么麽，過眼何須問唯阿。", "三徑固知皆坦路，一庵聊復障頹波。", "陶潛彭澤思松菊，賀老鑑湖吟芰荷。", "聞說與君同得道，月明風靜每相過。"]'),
('81912fca-f855-4b5a-aa45-68c5704193ce','次韻陳春卿眇雲軒  其一','史浩','宋','宋诗','song-poetry','','[]','脩竹叢中屋半楹，坐來天際數峯青。',32,'全唐诗/poet.song.115000.json','["脩竹叢中屋半楹，坐來天際數峯青。", "定知俗物不掛眼，只許飛雲過短櫺。"]'),
('ff6f4f72-42b1-470c-878d-6e2cef41219f','次韻陳春卿眇雲軒  其二','史浩','宋','宋诗','song-poetry','','[]','油然膚寸起巖巒，縈抱山腰玉带寬。',32,'全唐诗/poet.song.115000.json','["油然膚寸起巖巒，縈抱山腰玉带寬。", "會作旱天三日雨，莫將空濶等閒看。"]'),
('942ee86f-be26-445c-89fa-f482cdf98055','下水庵曉望偶題','史浩','宋','宋诗','song-poetry','','[]','踈樹梢頭露曉星，薄寒侵榻睡初醒。',32,'全唐诗/poet.song.115000.json','["踈樹梢頭露曉星，薄寒侵榻睡初醒。", "沙鷗何處驚飛起，點破遥山一抹青。"]'),
('21311b62-6b4d-45f0-8f61-cc5e200a5c87','次韻范幹聞畫眉鳥聲','史浩','宋','宋诗','song-poetry','','[]','春風著意舞長楊，中有珍禽口尚黄。',32,'全唐诗/poet.song.115000.json','["春風著意舞長楊，中有珍禽口尚黄。", "曾聞章臺看眉嫵，故應學得漢家粧。"]'),
('f0b1125b-d708-4054-ae96-a1c13a64a84c','題左舉善郊居四絕 草堂','史浩','宋','宋诗','song-poetry','','[]','莫隨朝叩合休休，萬里今誰沒白鷗。',32,'全唐诗/poet.song.115000.json','["莫隨朝叩合休休，萬里今誰沒白鷗。", "付與幽人幾椽屋，不須吳詠憶扁舟。"]'),
('298444f2-2ef9-46ce-965c-616afc470db7','題左舉善郊居四絕 聽松','史浩','宋','宋诗','song-poetry','','[]','不吟柳綠與桃紅，久要論交十八公。',32,'全唐诗/poet.song.115000.json','["不吟柳綠與桃紅，久要論交十八公。", "想得階前月如翦，獨將雙耳立西風。"]'),
('6c04812c-b66d-48ec-bef5-a075b4e16f5c','題左舉善郊居四絕 浮香','史浩','宋','宋诗','song-poetry','','[]','橫枝靚立碧山傍，噴得幽香度短牆。',32,'全唐诗/poet.song.115000.json','["橫枝靚立碧山傍，噴得幽香度短牆。", "更欲移筇約和靖，小風吹月咏滄浪。"]'),
('78ee596e-48ca-4674-9433-8c8bdc25a05c','題左舉善郊居四絕 總相宜堂','史浩','宋','宋诗','song-poetry','','[]','自倚傾城綽約娘，不爭時世作新粧。',32,'全唐诗/poet.song.115000.json','["自倚傾城綽約娘，不爭時世作新粧。", "若將西子相唐突，正恐蓮花似六郎。"]'),
('6a235c5f-323f-43c9-89fc-62fac616b4b4','題處州錄參廳平遠樓','史浩','宋','宋诗','song-poetry','','[]','山川著意吐幽奇，穠淡風煙總令姿。',32,'全唐诗/poet.song.115000.json','["山川著意吐幽奇，穠淡風煙總令姿。", "大似鵝谿垂數幅，飽看摩詰畫中詩。"]'),
('171191e1-0cc0-4143-bf3f-a75da52f3f1d','次韻恩平郡王晚步','史浩','宋','宋诗','song-poetry','','[]','步履蘅皋取次游，日華清淡雨雲浮。',32,'全唐诗/poet.song.115000.json','["步履蘅皋取次游，日華清淡雨雲浮。", "天公不喜燒銀燭，乞與歸途玉一鈎。"]'),
('7600fd02-6cba-4364-8d97-b5ef49ef9977','次韻館中秋香  其一','史浩','宋','宋诗','song-poetry','','[]','庭前高下碧玉樹，秋日奈茲風露何。',32,'全唐诗/poet.song.115000.json','["庭前高下碧玉樹，秋日奈茲風露何。", "兩度開花君莫問，爲渠天近得香多。"]'),
('e85215af-0923-4bfb-b0be-3876376bf8dd','次韻館中秋香  其二','史浩','宋','宋诗','song-poetry','','[]','亭亭萬葉翦青羅，豈爲冰霜便改柯。',32,'全唐诗/poet.song.115000.json','["亭亭萬葉翦青羅，豈爲冰霜便改柯。", "滿著珠璣間金粟，倩誰纖手剖天鵝。"]'),
('893b1f1e-c2fd-4a69-b8f5-45c2ba08adda','分題得花露雙字韻','史浩','宋','宋诗','song-poetry','','[]','凝紅濕翠媚春江，殘月幽香度曉窗。',32,'全唐诗/poet.song.115000.json','["凝紅濕翠媚春江，殘月幽香度曉窗。", "正恐枝頭珠作顆，冷驚宿蝶去雙雙。"]'),
('999dbab0-f6f2-4070-bcf7-158e45e40eaa','題雪竇隨鳬岩','史浩','宋','宋诗','song-poetry','','[]','紛紛飛雪墮青天，窮徹隨鳬信有源。',32,'全唐诗/poet.song.115000.json','["紛紛飛雪墮青天，窮徹隨鳬信有源。", "想得王喬之帝所，每來巖下滌潺湲。"]'),
('5250adba-ddef-4d1f-a59b-6fb9de7793ed','因見父老云東湖九百九十頃七十二谿故有是作','史浩','宋','宋诗','song-poetry','','[]','東湖九百九十頃，七十二谿攢翠波。',32,'全唐诗/poet.song.115000.json','["東湖九百九十頃，七十二谿攢翠波。", "乞我扁舟任飄泊，却敲明月叫漁歌。"]'),
