('85b14b48-c0a2-430e-b910-efabae0462b8','和楊柳','史浩','宋','宋诗','song-poetry','','[]','綠衣濯濯紅粧靚，春半園林露未晞。',32,'全唐诗/poet.song.115000.json','["綠衣濯濯紅粧靚，春半園林露未晞。", "正似佳人與才子，倚窗深處淡相宜。"]'),
('201ea02c-1827-471b-b470-764fd9500638','和鍾山晚步','史浩','宋','宋诗','song-poetry','','[]','幽谿細雨落輕花，無限舂鋤立岸沙。',32,'全唐诗/poet.song.115000.json','["幽谿細雨落輕花，無限舂鋤立岸沙。", "苦竹黄蘆迷望眼，孤煙起處是人家。"]'),
('04a6268f-fca0-4d44-8777-1d5a06938f05','和道傍大松人取以爲明','史浩','宋','宋诗','song-poetry','','[]','夭矯龍鱗衆欲攀，肯隨蒿艾老空山。',32,'全唐诗/poet.song.115000.json','["夭矯龍鱗衆欲攀，肯隨蒿艾老空山。", "便教不受棟梁用，猶作光明滿世間。"]'),
('ab710f23-f657-430f-8ee8-4ec0b4231860','和同熊伯通自定林過悟真','史浩','宋','宋诗','song-poetry','','[]','欲尋雲屋煮新茶，領客行尋一徑斜。',32,'全唐诗/poet.song.115000.json','["欲尋雲屋煮新茶，領客行尋一徑斜。", "遐想當時掛紗帽，笑看碗面白浮花。"]'),
('3490753c-2de5-47d7-a1ee-0bd4d41801da','和城北','史浩','宋','宋诗','song-poetry','','[]','春溫初褪鶴綾袍，已覺東風綻小桃。',32,'全唐诗/poet.song.115000.json','["春溫初褪鶴綾袍，已覺東風綻小桃。", "搘策城陰無限景，秦淮波濶蔣山高。"]'),
('4ce8aa52-9fba-4d7c-98a7-01c2190d0dc9','和答東流頓令罷官阻風','史浩','宋','宋诗','song-poetry','','[]','解印今朝去有期，何須更勒北山移。',32,'全唐诗/poet.song.115000.json','["解印今朝去有期，何須更勒北山移。", "了知風伯懇留意，正是攀轅卧轍時。"]'),
('3840382b-9ae0-427a-89a2-020f32a94a27','和斜徑','史浩','宋','宋诗','song-poetry','','[]','風拂繁陰開曲徑，雲移寸碧出遥岑。',32,'全唐诗/poet.song.115000.json','["風拂繁陰開曲徑，雲移寸碧出遥岑。", "柳枝濯濯嫌煙淡，荷葉田田怯水深。"]'),
('6a965617-8c2c-4925-9a5b-817c49775416','和雨晴','史浩','宋','宋诗','song-poetry','','[]','不管狂風橫雨催，小園日日有花開。',32,'全唐诗/poet.song.115000.json','["不管狂風橫雨催，小園日日有花開。", "羣仙恐濕凌波襪，戲蹴香紅襯綠苔。"]'),
('14b3bd7a-1273-4822-94c0-03eb2098bb7f','和烏石','史浩','宋','宋诗','song-poetry','','[]','梅花一徑萬重山，岡外浮雲去住間。',32,'全唐诗/poet.song.115000.json','["梅花一徑萬重山，岡外浮雲去住間。", "莫恨尋幽無侶伴，世途能有幾人閒。"]'),
('2a68d47c-7c29-44e1-ad28-a7e509637e2f','和烏塘','史浩','宋','宋诗','song-poetry','','[]','雲遶青山水遶隄，遊人陌上手同携。',32,'全唐诗/poet.song.115000.json','["雲遶青山水遶隄，遊人陌上手同携。", "遺簪墜珥歡方洽，只恐樓頭日欲西。"]'),
('0567842d-6ef7-4c12-8a57-f15ff5dbf0e0','和奉和嚴公軍城早秋','史浩','宋','宋诗','song-poetry','','[]','金飇獵獵受降旌，虎帳纍纍細柳營。',32,'全唐诗/poet.song.115000.json','["金飇獵獵受降旌，虎帳纍纍細柳營。", "坐屈遐荒三百萬，何須掠地與屠城。"]'),
('caf91511-572a-4756-a354-01d39c4982a5','和從韋明府覓綿竹','史浩','宋','宋诗','song-poetry','','[]','縣以竹名佳致在，令君節與竹俱高。',32,'全唐诗/poet.song.115000.json','["縣以竹名佳致在，令君節與竹俱高。", "何妨乞取千竿翠，月影翻風似碧濤。"]'),
('f01ab2af-ab8a-4c39-ac9e-6fa69e605da7','和杜中書九日','史浩','宋','宋诗','song-poetry','','[]','佳人通夕賞重陽，醉盡樓邊白玉缸。',32,'全唐诗/poet.song.115000.json','["佳人通夕賞重陽，醉盡樓邊白玉缸。", "莫遣飛霜到叢菊，恐驚宿蝶去雙雙。"]'),
('403cdb10-7dd4-492b-9ec4-c6bbf2a848bd','和春晚題韋家亭子','史浩','宋','宋诗','song-poetry','','[]','馬蹄輕蹙落花香，三月芳菲墮渺茫。',32,'全唐诗/poet.song.115000.json','["馬蹄輕蹙落花香，三月芳菲墮渺茫。", "正好留春開雅宴，危亭羣幕已高張。"]'),
('64e7d145-988f-4ad6-8f6d-494cd23cbcd6','和朱坡絕句','史浩','宋','宋诗','song-poetry','','[]','芳華三月只些兒，生怕春林鳥喚歸。',32,'全唐诗/poet.song.115000.json','["芳華三月只些兒，生怕春林鳥喚歸。", "寄與東君須久住，勿容一片落花飛。"]'),
('72e3666c-7228-48f9-aa98-61d96e7c0d9f','和重送國棋王逢','史浩','宋','宋诗','song-poetry','','[]','前身應是奕秋徒，自謂人間敵手無。',32,'全唐诗/poet.song.115000.json','["前身應是奕秋徒，自謂人間敵手無。", "君去尚留邊角勢，爲君題作爛柯圖。"]'),
('736aa0e4-de10-46cf-bc0a-bd79b11b08a3','和題水口草市','史浩','宋','宋诗','song-poetry','','[]','飯裹綠荷朝趁市，香浮青甕晚登樓。',32,'全唐诗/poet.song.115000.json','["飯裹綠荷朝趁市，香浮青甕晚登樓。", "憑誰寫入鵝溪絹，一簇人煙古渡頭。"]'),
('cf194c1a-f8c7-452f-a980-01d886ecee4f','和泊秦淮','史浩','宋','宋诗','song-poetry','','[]','一葉輕舠倚岸沙，沙邊燈火幾人家。',32,'全唐诗/poet.song.115000.json','["一葉輕舠倚岸沙，沙邊燈火幾人家。", "夜來江闊天無際，唯見銀蟾輥浪花。"]'),
('4b5ab49f-15e9-430a-8457-9b11aa4ab731','即席賦木芙蓉','史浩','宋','宋诗','song-poetry','','[]','盈盈佇立傲秋霜，露染臙脂作靚粧。',32,'全唐诗/poet.song.115000.json','["盈盈佇立傲秋霜，露染臙脂作靚粧。", "正似瑶池見金母，醉歸未脫綠雲裳。"]'),
('a3c60a75-db4e-4fbd-9718-e315a943a198','彌堅小圃小春見梅','史浩','宋','宋诗','song-poetry','','[]','孤根十月已先溫，不待青春入燒痕。',32,'全唐诗/poet.song.115000.json','["孤根十月已先溫，不待青春入燒痕。", "冷艷一枝何處看，竹邊池閣水邊村。"]'),
('0946637c-2463-4e4b-86ff-cca81d86c152','棠陰得明字','史浩','宋','宋诗','song-poetry','','[]','蔽芾甘棠遶訟庭，日高碎影更縱橫。',32,'全唐诗/poet.song.115000.json','["蔽芾甘棠遶訟庭，日高碎影更縱橫。", "直教憩處無人迹，始信康公教化明。"]'),
('b3583dc8-90f8-4b91-a0fb-f5e721c9bbbb','硯紋得明字','史浩','宋','宋诗','song-poetry','','[]','歙水端溪各擅名，刷絲鸜鵒眼分明。',32,'全唐诗/poet.song.115000.json','["歙水端溪各擅名，刷絲鸜鵒眼分明。", "不因守黑談玄輩，奇璞緣何見管城。"]'),
('cdde504d-3136-497b-be3d-78d6328a5fdd','阿育王山有松萬株乞亭名於真隠居士榜曰松風陸務觀作詩因次韻','史浩','宋','宋诗','song-poetry','','[]','颼颼萬峰頂，宇宙盡聞聲。',24,'全唐诗/poet.song.115000.json','["颼颼萬峰頂，宇宙盡聞聲。", "會得真消息，知予是强名。"]'),
('c4768b21-21b7-4b8c-aa3c-bb258f97107a','瓜州渡頭六言','史浩','宋','宋诗','song-poetry','','[]','竹葉舟中漁父，瓜州渡口人家。',28,'全唐诗/poet.song.115000.json','["竹葉舟中漁父，瓜州渡口人家。", "占得煙波活計，全勝富貴生涯。"]'),
('8dcb6480-28a3-48a8-9597-5ba079c33b62','餞徽州李守  其一','史浩','宋','宋诗','song-poetry','','[]','當年仗策扣軍戲，已有昌言簡帝知。',64,'全唐诗/poet.song.115000.json','["當年仗策扣軍戲，已有昌言簡帝知。", "目見飛龍升白水，手扶赫日上咸池。", "飄萍一世其如命，剖竹專城會得時。", "三十六峰方秀發，可無佳致付新詩。"]'),
('771bf061-4b57-4cd6-b496-94f9db0fec31','餞徽州李守  其二','史浩','宋','宋诗','song-poetry','','[]','九重翔鳳舞絲綸，聖主臨朝見故人。',64,'全唐诗/poet.song.115000.json','["九重翔鳳舞絲綸，聖主臨朝見故人。", "德友再生洙水上，客星今起釣臺濱。", "紫荷欲待明光曉，紅旆先行澤國春。", "祖帳豈須懷別思，來年馬首向城闉。"]'),
('f7a3c3d9-bce3-428e-9be9-8b7644cfe5af','次韻周祭酒所和館中雪詩  其一','史浩','宋','宋诗','song-poetry','','[]','不作當年行路難，平明下馬趨朝班。',64,'全唐诗/poet.song.115000.json','["不作當年行路難，平明下馬趨朝班。", "歡聲漸入玉連鎖，瑞氣先凝金博山。", "曾說歲穰占臘裏，更傳天喜見顔間。", "歸來乞與新詩句，清絕何人許共攀。"]'),
('0b70248d-53d1-45d4-ba2a-c767aa57d0e5','次韻周祭酒所和館中雪詩  其二','史浩','宋','宋诗','song-poetry','','[]','造化工夫正不難，幻成梅柳已班班。',64,'全唐诗/poet.song.115000.json','["造化工夫正不難，幻成梅柳已班班。", "清吟且可對冰柱，爛醉未應頹玉山。", "鶴冷風亭來砌下，雁迷煙渚駐雲間。", "不移跬步居銀闕，仙馭何勞著手攀。"]'),
('fd890976-123c-4934-8196-f1b70b486636','次韻周祭酒所和館中雪詩  其三','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風急何辭上閣難，且來共住玉京班。',64,'全唐诗/poet.song.115000.json','["風急何辭上閣難，且來共住玉京班。", "一蓑已得詩中畫，萬疊休傳海外山。", "未放微陽穿日脚，少留清影在窗間。", "莫嗔愛入西湖社，夫子龍鱗正許攀。"]'),
('8419dc43-4f7a-4798-983d-9b17b84312fa','梅花借喜雪韻  其一','史浩','宋','宋诗','song-poetry','','[]','老去風光報答難，樹頭春律喜新班。',64,'全唐诗/poet.song.115000.json','["老去風光報答難，樹頭春律喜新班。", "忽驚斷岸一番雪，便憶故園千疊山。", "斜日淡煙茅舍外，冷香幽韻竹籬間。", "玉壺虛佐寒窗靜，不敢呼童取次攀。"]'),
('dffded9b-f38b-4a7f-a838-ed057dac8db5','梅花借喜雪韻  其二','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','看花容易詠花難，自古何人立首班。',64,'全唐诗/poet.song.115000.json','["看花容易詠花難，自古何人立首班。", "東閣五言還水部，西湖一徑指孤山。", "度牆野月黄昏後，啄雪幽禽去住間。", "冷定識渠真面目，從茲桃李不須攀。"]'),
('cae17b79-6239-4901-94e0-0ada958640e3','梅花借喜雪韻  其三','史浩','宋','宋诗','song-poetry','','[]','謾取山樊作二難，祇今風味若爲班。',64,'全唐诗/poet.song.115000.json','["謾取山樊作二難，祇今風味若爲班。", "斜窺淺碧洛神賦，瘦怯輕寒姑射山。", "小輟殊杯清影下，競留新絕翠微間。", "枝邊青子垂垂出，金鼎成時試一攀。"]'),
('f57f47e3-7b5c-435a-9d5c-8dd0ffe34a99','次韻劉國正再賦','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去臘尋幽良獨難，杖藜何處見斕斑。',64,'全唐诗/poet.song.115000.json','["去臘尋幽良獨難，杖藜何處見斕斑。", "江村籬落雪晴路，水月池臺春近山。", "紙帳朦朧來醉裏，人家依約在林間。", "西湖處士君今是，月曉多應獨自攀。"]'),
('b4948204-6885-4723-8b90-725501ffb902','次韻何國博春日隔年','史浩','宋','宋诗','song-poetry','','[]','嶰琯灰飛又一年，綵幡聊復映皤然。',64,'全唐诗/poet.song.115000.json','["嶰琯灰飛又一年，綵幡聊復映皤然。", "香催元日椒花酒，星點千家爆竹煙。", "未分風光銷老裏，擬追歡賞到春邊。", "憑誰爲向東君說，莫遣寒英趁野泉。"]'),
('f18f4b63-0869-4b7d-8157-4a00a302f973','次韻唐太博重過西湖','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紅塵汩汩解窮年，試說西湖思豁然。',64,'全唐诗/poet.song.115000.json','["紅塵汩汩解窮年，試說西湖思豁然。", "上下層樓涵倒影，聯翩飛鳥沒寒煙。", "未須梅萼催詩興，長有春風在日邊。", "安得扁舟去招隠，雲窗相對聽鳴泉。"]'),
('45f604ad-13ae-43b4-baba-6959b08cd09e','少卿楊公雅喜士左舉善又東南之秀假樓居爲丹壺以濟人既謝以詩因出示輒次其韻','史浩','宋','宋诗','song-poetry','','[]','煙柳葱葱鎖玉欄，樓頭偉觀熟窺斑。',64,'全唐诗/poet.song.115000.json','["煙柳葱葱鎖玉欄，樓頭偉觀熟窺斑。", "不因置酒垂青目，安得開窗面北山。", "塵市故知容隠者，聲名無奈落人間。", "胸中賸有安民術，且把丹壺與駐顔。"]'),
('11c2eb64-443a-484c-9c29-85648768c18a','和普安郡王桂子','史浩','宋','宋诗','song-poetry','','[]','嫦娥屑玉醖旃檀，乞與人間秋後看。',64,'全唐诗/poet.song.115000.json','["嫦娥屑玉醖旃檀，乞與人間秋後看。", "已向水邊吟月曉，却來花下立更殘。", "西風把酒休催菊，南國行歌不賦蘭。", "何必穠香千萬斛，鼻端須此百憂寬。"]'),
('9be09281-b508-4f53-93d5-0682a7163388','次韻恩平郡王丹桂','史浩','宋','宋诗','song-poetry','','[]','銀潢滾滾碧流長，洗出清秋百種芳。',64,'全唐诗/poet.song.115000.json','["銀潢滾滾碧流長，洗出清秋百種芳。", "著蕊半殷生桂子，離羣獨立有天香。", "仙人剝啄遥相過，野老婆娑日在傍。", "正喜奇姿媚霜露，不隨時世學新妝。"]'),
('4a919fc4-099c-4462-8bd9-32ef5f3e03c9','送任秘監龍圖知洪府','史浩','宋','宋诗','song-poetry','','[]','夫子胸中萬頃寬，照人英采玉峰寒。',64,'全唐诗/poet.song.115000.json','["夫子胸中萬頃寬，照人英采玉峰寒。", "難蟠凜凜虹蜺氣，易捨峩峩獬豸冠。", "秋在石渠同過鴈，春回江渚却鳴鸞。", "由來內外俱行道，達者何曾異轍看。"]'),
('9c0dcad9-d3e5-4393-b8b3-627ac9506ec4','代恩平郡王賦董氏園亭','史浩','宋','宋诗','song-poetry','','[]','怪底王生願卜隣，巖前有月對頤真。',64,'全唐诗/poet.song.115000.json','["怪底王生願卜隣，巖前有月對頤真。", "夜深清影頻侵戶，日永虛堂不著塵。", "能向箇中參妙旨，却於忙裏作閒身。", "朝回試解黄金带，即是毗耶彼上人。"]'),
('2762ac17-4fe3-4a29-bbc4-690c7eb07138','次韻任龍圖留別','史浩','宋','宋诗','song-poetry','','[]','挂席桅檣倚數尋，小風吹飽思難禁。',64,'全唐诗/poet.song.115000.json','["挂席桅檣倚數尋，小風吹飽思難禁。", "三千奏牘曾醫國，十萬兵屯已屬心。", "江路踈梅春意近，楚天孤鶩曉煙沈。", "是中秀句應無限，著眼歸鴻遲好音。"]'),
('4f58ae44-d83d-4cac-8927-7813c0eddead','上普安郡王生辰  其一','史浩','宋','宋诗','song-poetry','','[]','朔風吹律醖霜嚴，帝遣神仙下斗南。',64,'全唐诗/poet.song.115000.json','["朔風吹律醖霜嚴，帝遣神仙下斗南。", "闕月遡弦金作縷，非煙效瑞錦成嵐。", "平生漫吹欣相遇，一瓣濃薰已徧參。", "欲向今朝伸善頌，世間唯有達尊三。"]'),
('089e1ffd-81cc-4640-bb3d-e84f96ea1a47','上普安郡王生辰  其二','史浩','宋','宋诗','song-poetry','','[]','銀潢雙派毓諸昆，始信閒平不足論。',64,'全唐诗/poet.song.115000.json','["銀潢雙派毓諸昆，始信閒平不足論。", "畫㦸森嚴韜虎豹，玉階芬馥藹蘭蓀。", "明光殿下紆萊服，命衮叢中上壽樽。", "長立首班扶帝社，是爲天下爵之尊。"]'),
('bb17624e-dbf5-4cd5-b9d0-cf915c760c3d','上普安郡王生辰  其三','史浩','宋','宋诗','song-poetry','','[]','壽鄉日月緩征轅，箕翼光芒萬古存。',64,'全唐诗/poet.song.115000.json','["壽鄉日月緩征轅，箕翼光芒萬古存。", "龜上碧蓮波蕩漾，鶴歸華表影翩翻。", "笑看曼倩三偷果，坐閲劉晨七世孫。", "綠髮扶踈受修日，是爲天下齒之尊。"]'),
('4f405571-219d-47f0-815b-ff0b14e86e4f','上普安郡王生辰  其四','史浩','宋','宋诗','song-poetry','','[]','堂堂玉立冠宗藩，中有澄波撓不渾。',64,'全唐诗/poet.song.115000.json','["堂堂玉立冠宗藩，中有澄波撓不渾。", "彩筆英辭追電影，黄鐘和氣散春溫。", "不言自是行天運，獨智何妨入聖門。", "忠孝一心唯戴主，是爲天下德之尊。"]'),
('d4a71793-48cc-4ee4-b64e-f270f5ab523a','次韻林寺簿立冬日齋祠精進寺','史浩','宋','宋诗','song-poetry','','[]','籃輿忽得到林間，飛鳥翩翩相與還。',64,'全唐诗/poet.song.115000.json','["籃輿忽得到林間，飛鳥翩翩相與還。", "俎豆欲嚴來日祭，軒窗聊共此時閒。", "芬敷殘菊添秋色，摇落蒼梧見遠山。", "夫子肝腸真錦繡，歸途新句已班班。"]'),
('7c184bd1-651c-4e90-826d-a1b5614a5167','次韻王龜齡校書梅花  其一','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','底處衝寒欲放梅，柴門雪壓爲伊開。',64,'全唐诗/poet.song.115000.json','["底處衝寒欲放梅，柴門雪壓爲伊開。", "酸風不管欹紗帽，冷豔終朝粲玉盃。", "尚覺西湖三徑遠，先吹東閣五言來。", "一枝入眼君須惜，莫遣高樓怨笛催。"]'),
('4f34a679-fd34-496c-aee3-57e94058049c','次韻王龜齡校書梅花  其二','史浩','宋','宋诗','song-poetry','','[]','朔風吹雪障江梅，不著詩攻不解開。',64,'全唐诗/poet.song.115000.json','["朔風吹雪障江梅，不著詩攻不解開。", "正恐與花無半面，胡然有意及三杯。", "清凉怕逐炎炎去，澹泊曾參的的來。", "祇向茅簷露消息，華堂虛費管絃催。"]'),
('62d6a6ea-3345-411f-a1ef-0aef28e79aa2','贈楊都運持節夔路','史浩','宋','宋诗','song-poetry','','[]','帝城祖帳溢千夫，又遣星軺下蜀都。',64,'全唐诗/poet.song.115000.json','["帝城祖帳溢千夫，又遣星軺下蜀都。", "春晝預知看衣錦，秋風可但爲思鱸。", "北方泉貨須留地，他日車輪賸結蒲。", "萬里未應懷別恨，與君元不隔江湖。"]'),
('f0ce47ba-d6d4-4f89-a23c-2dc8d3f7ad05','次韻張臺法元日書事','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','好事東君不憚勞，點妝梅柳見才高。',64,'全唐诗/poet.song.115000.json','["好事東君不憚勞，點妝梅柳見才高。", "盡輸好景資元日，故遣清齎屬我曹。", "錦繡忽貽新筆墨，瓊瑶無以報瓜桃。", "春風染徧西湖綠，且滌金杯共漱醪。"]'),
('4ada3bf0-fe58-4f09-85cf-2fed32357acc','次韻黄虛中春懷','史浩','宋','宋诗','song-poetry','','[]','杏園桑陌草連空，點點殘紅濺晚風。',64,'全唐诗/poet.song.115000.json','["杏園桑陌草連空，點點殘紅濺晚風。", "籬落喜聞營細柳，煙塵徒爾隘新豐。", "不因宣室咨梁傅，安得朝廷知弱翁。", "他日淮肥驚鶴唳，金龜似斗合須公。"]'),
('498a1a0e-c4c9-4989-9f43-5bd0d136242c','和建王雪','史浩','宋','宋诗','song-poetry','','[]','春風剪水出雲來，著處爲花是有才。',64,'全唐诗/poet.song.115000.json','["春風剪水出雲來，著處爲花是有才。", "柳絮壓鹽知句麗，銀杯逐馬看朝回。", "已開謝砌俱堆玉，不信何郎只詠梅。", "梁苑詞華萃文傑，笑渠楚國賦陽臺。"]'),
('a931b383-c5e5-4fe4-9089-983b94080cf5','和建王頤真庵','史浩','宋','宋诗','song-poetry','','[]','夫君錦繡裹肝腸，思湧秋濤溢海塘。',64,'全唐诗/poet.song.115000.json','["夫君錦繡裹肝腸，思湧秋濤溢海塘。", "曾向囊中明的礫，却來句裏得清凉。", "妙因目擊初無語，神與天通自發光。", "欲識至音還太古，湖江道術兩相忘。"]'),
('4319ebe2-e488-41ec-bbe4-dffe86b54162','次韻陳察平望有作','史浩','宋','宋诗','song-poetry','','[]','白旄黄鉞擬親麾，勝氣俄周天四圍。',64,'全唐诗/poet.song.115000.json','["白旄黄鉞擬親麾，勝氣俄周天四圍。", "犬豕聞風先獸駭，狼狐見月已星稀。", "鬰葱非霧中原在，岌嶪神京大駕歸。", "讜議更須頻啟沃，間無容髮是投機。"]'),
('a86ad13c-2fd9-46f1-b1d8-90c6e204d462','再次韻馬德駿郎中  其一','史浩','宋','宋诗','song-poetry','','[]','父老駢肩不可麾，鑪煙爭遶御班圍。',64,'全唐诗/poet.song.115000.json','["父老駢肩不可麾，鑪煙爭遶御班圍。", "共瞻帝所天光近，更識淮壖馬跡稀。", "丹扆預傳雄算去，元樞先奏凱歌歸。", "由來干舞苗民格，即是姚虞上上機。"]'),
('b43f8e8c-e759-4151-ac1a-bcfd3d0c480f','再次韻馬德駿郎中  其二','史浩','宋','宋诗','song-poetry','','[]','戈鋋掣電萬人麾，無霸空矜大十圍。',64,'全唐诗/poet.song.115000.json','["戈鋋掣電萬人麾，無霸空矜大十圍。", "關外羽書長踵至，路旁烽火覺煙稀。", "已聞異域離心久，行見名王稽首歸。", "箇是吾皇用神武，小臣寧能洩天機。"]'),
('8a5ac353-16f2-4e13-b70e-ca1a68e97d88','又次韻  其一','史浩','宋','宋诗','song-poetry','','[]','當年複被乞州麾，敢意今朝扈禁圍。',64,'全唐诗/poet.song.115000.json','["當年複被乞州麾，敢意今朝扈禁圍。", "光閃雪矛情益壯，聲傳玉漏夢全稀。", "已無馬向清淮飲，端有龍從白水歸。", "倚柁預思歌凱後，却尋鷗鳥共忘機。"]'),
('2677e8a6-d769-479d-a742-1b5f563ca43b','又次韻  其二','史浩','宋','宋诗','song-poetry','','[]','健筆如椽不輟麾，瘦生端復減腰圍。',64,'全唐诗/poet.song.115000.json','["健筆如椽不輟麾，瘦生端復減腰圍。", "昔人句法今誰在，當代文雄似子稀。", "光焰故應侵斗去，葩華直欲挽春歸。", "鑪香一瓣真消得，擬向君家覓錦機。"]'),
('4631cf39-b3e6-4088-be93-c3ef9bd36ade','游雨花臺','史浩','宋','宋诗','song-poetry','','[]','試扶鳩策上煙霞，尚想當年天雨花。',64,'全唐诗/poet.song.115000.json','["試扶鳩策上煙霞，尚想當年天雨花。", "潮熟野航歸別浦，雪乾宿鷺點晴沙。", "高連西竺三千界，俯眺南陽十萬家。", "更欲雲開窮遠目，鬰葱起處認中華。"]'),
('37f101c9-508a-40f4-8235-b0b3e999b605','次韻馮圓中郎中游甘露寺','史浩','宋','宋诗','song-poetry','','[]','試憑古剎俯江城，追思孫權共孔明。',64,'全唐诗/poet.song.115000.json','["試憑古剎俯江城，追思孫權共孔明。", "三國有人成底事，六朝何代不交兵。", "中原天子今懨復，北塞胡兒始削平。", "附翼攀鱗真際會，小臣亦解說功名。"]'),
('7e5bf034-e8a1-4590-977c-cc429f145c22','喜到鎮江復用前韻','史浩','宋','宋诗','song-poetry','','[]','試於京口駐旌麾，仰覘清光在日圍。',64,'全唐诗/poet.song.115000.json','["試於京口駐旌麾，仰覘清光在日圍。", "浮玉林巒隨指顧，平山欄檻尚依稀。", "煙塵已逐胡奴去，城郭空驚丁令歸。", "摩撫正須煩愷悌，進攻初不礙乘機。"]'),
('aea13ddc-016e-466b-abe2-f786835259a5','次韻建王秦府有感','史浩','宋','宋诗','song-poetry','','[]','世間誰不有興亡，堪歎伊人事最彰。',64,'全唐诗/poet.song.115000.json','["世間誰不有興亡，堪歎伊人事最彰。", "詩禮未聞傳似續，樓臺先欲芘淫荒。", "自從冠履歸泉下，無復輪蹄塞柳行。", "富貴由來保勤儉，高危滿溢豈能長。"]'),
('b0dc57ae-96ce-468f-88fe-129131cf5635','次韻梁諫議吳殿院二詩 江皋晚望','史浩','宋','宋诗','song-poetry','','[]','煙銷晴日淡籠沙，佇立江皋望眼賒。',64,'全唐诗/poet.song.115000.json','["煙銷晴日淡籠沙，佇立江皋望眼賒。", "金剎倚空知梵宇，青蓑著艇見漁家。", "時平喜聽三京復，亂定還拚兩鬢華。", "丘壑滿胸隨處好，不妨旌旆過雲涯。"]'),
('c2bb3bdb-35c0-4518-baa6-d15e4d325b1d','次韻梁諫議吳殿院二詩 阻雨未到金焦','史浩','宋','宋诗','song-poetry','','[]','萬古金焦浪拍沙，隔江雖邇到何賒。',64,'全唐诗/poet.song.115000.json','["萬古金焦浪拍沙，隔江雖邇到何賒。", "頗聞敵馬輕千里，未省瓜州今幾家。", "陰雨連宵舟懶動，好風吹曉日方華。", "會須急作登連計，建鄴明朝在一涯。"]'),
('c42a75ba-3d27-427e-a360-c30935cd0c1e','恭和御製秋晚曲宴詩','史浩','宋','宋诗','song-poetry','','[]','清時睿澤浸函生，和氣熏陶萬寶成。',64,'全唐诗/poet.song.115000.json','["清時睿澤浸函生，和氣熏陶萬寶成。", "迺即上林開特宴，更容廣樂奏新聲。", "奉觴劍履風雲合，立仗旌旗日月明。", "興國舊儀欣再讀，願觀混一致昇平。"]'),
('b01a2302-0f0c-4e2a-90b2-c13739d46d67','恭和聖製秋日秘閣觀圖書宴羣臣詩','史浩','宋','宋诗','song-poetry','','[]','舜承堯治煥有章，祥開東壁正騰光。',64,'全唐诗/poet.song.115000.json','["舜承堯治煥有章，祥開東壁正騰光。", "天臨廣內朝班肅，宴欵僊山午漏長。", "已慶車書同薄海，行看琛贄盡名王。", "由來服遠先文德，不待將軍出定襄。"]'),
('06d92fe2-d8a0-4b2f-8eae-04f0c456cf74','送曾原伯大卿赴江東漕運','史浩','宋','宋诗','song-poetry','','[]','濶步駸駸上要津，忽求補外爲寧親。',64,'全唐诗/poet.song.115000.json','["濶步駸駸上要津，忽求補外爲寧親。", "不貪農扈登卿月，正喜秦淮擁使輪。", "相就二男真孝子，益尊八座太夫人。", "臨岐勿復深言別，看即斑衣侍紫宸。"]'),
('c637c55f-7be0-44c8-b3a2-274c5c3c13e1','與謝守殿撰','史浩','宋','宋诗','song-poetry','','[]','乞得閒身欲自由，便當尋壑更經丘。',64,'全唐诗/poet.song.115000.json','["乞得閒身欲自由，便當尋壑更經丘。", "力除驕志期爭席，盡洗機心爲狎鷗。", "兵衛旌旗真冗長，門迎車馬謾諠啾。", "賢侯幸得同聲臭，此禮從今合罷休。"]'),
('e00e4ded-97ba-4f63-8e2f-ad353c67e257','山間偶成','史浩','宋','宋诗','song-poetry','','[]','乘興籃輿竟出關，故園重見一開顔。',64,'全唐诗/poet.song.115000.json','["乘興籃輿竟出關，故園重見一開顔。", "鏡鸞瑩徹氷中水，僧衲斕斑雪後山。", "已許梅花供勝賞，更邀酒子伴清閒。", "明朝未忍爲歸計，猿鶴方茲喜我還。"]'),
('cf26ce15-5f94-4b7d-a7fa-0f402c7d3dc4','次韻務觀遊四明洞天','史浩','宋','宋诗','song-poetry','','[]','風煙偶爾屬吾邦，箇箇松筠聳碧幢。',64,'全唐诗/poet.song.115000.json','["風煙偶爾屬吾邦，箇箇松筠聳碧幢。", "奎畫百函龍作衛，雲岑四面石爲窗。", "水邊自喜陪振鷺，籬外從渠有吠厖。", "多謝故人迂五馬，清談剔盡幾銀釭。"]'),
('85d8a95c-0fa5-4812-98c7-1caadb065291','與東湖壽老','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','乞得西湖養病身，小園真隠謾頤真。',64,'全唐诗/poet.song.115000.json','["乞得西湖養病身，小園真隠謾頤真。", "已將竹院舍幽客，更築鄉畦招可人。", "茗碗晝看花墜影，吟窗夜與月爲隣。", "清凉境界天家予，自是全無一點塵。"]'),
('483d5de4-12fb-4783-ba55-d0bb5604bac2','走筆次韻吳判院','史浩','宋','宋诗','song-poetry','','[]','世態螳螂謾捕蟬，誰知富貴本由天。',64,'全唐诗/poet.song.115000.json','["世態螳螂謾捕蟬，誰知富貴本由天。", "但令冊府荷氷鑑，何必熏爐擁燧煙。", "一曲賜來成別墅，百杯贏得吸晴川。", "可人過我談名理，月到紗窗興欲仙。"]'),
('7172c3e1-6d43-4b3b-803d-fe85ccf82a94','竹院曇老病目寄詩索和走筆次韻','史浩','宋','宋诗','song-poetry','','[]','平生雙眼只觀書，今日休分紫奪朱。',64,'全唐诗/poet.song.115000.json','["平生雙眼只觀書，今日休分紫奪朱。", "青白泯然從客至，席階及也要人扶。", "丹砂佇使清明在，金屑應嫌計策踈。", "幸有鑠迦全透頂，不妨洞見混元初。"]'),
('7d7e7cda-4f6e-4d6c-81a6-e64d08933e9a','次韻劉廷佐','史浩','宋','宋诗','song-poetry','','[]','道林袖裏出清新，珠玉離離光照隣。',64,'全唐诗/poet.song.115000.json','["道林袖裏出清新，珠玉離離光照隣。", "知是謫仙尋麗句，寄來真隠是陳人。", "幾年卜築成三徑，今日聲名重萬鈞。", "汀草岸花增意氣，從茲日月是青春。"]'),
('eaef50a2-37fa-4f81-8206-46aac998fe39','顯仁皇太后挽辭  其一','史浩','宋','宋诗','song-poetry','','[]','白水神龍躍，蒼梧繢翟歸。',48,'全唐诗/poet.song.115000.json','["白水神龍躍，蒼梧繢翟歸。", "八紘瞻壽母，二紀御慈闈。", "春酒霞方爛，秋陽露已稀。", "傷心老萊服，不上赭黄衣。"]'),
('ff881d4d-8e62-44fb-906e-05da47f04cc9','顯仁皇太后挽辭  其二','史浩','宋','宋诗','song-poetry','','[]','霜曉東朝路，鳴笳素葆飜。',48,'全唐诗/poet.song.115000.json','["霜曉東朝路，鳴笳素葆飜。", "龍輴菆禹穴，魚鑰閟堯門。", "助奠風雲合，纏哀海嶽昏。", "唯餘慈儉寶，垂裕九重尊。"]'),
('aa180449-4c20-471e-853d-e18727cf2702','高宗聖神武文憲孝皇帝挽辭  其一','史浩','宋','宋诗','song-poetry','','[]','赤伏膺符日，皇圖若綴旒。',48,'全唐诗/poet.song.115000.json','["赤伏膺符日，皇圖若綴旒。", "配天期祀夏，復古果興周。", "再造承三統，維新敘九疇。", "世方知藝祖，燕翼有貽謀。"]'),
('6973ae0b-ac42-42f9-8473-b5b9b95f8049','高宗聖神武文憲孝皇帝挽辭  其二','史浩','宋','宋诗','song-poetry','','[]','宸謨先自治，鄰壤憺威稜。',48,'全唐诗/poet.song.115000.json','["宸謨先自治，鄰壤憺威稜。", "翼翼慈寧殿，峩峩永祐陵。", "朔南兼覆冒，遐邇悉豐登。", "陰德順陽報，真人嗣中興。"]'),
('64d94189-96ef-4dcf-bd42-46d27709935c','高宗聖神武文憲孝皇帝挽辭  其三','史浩','宋','宋诗','song-poetry','','[]','郟鄏年方永，崆峒道益隆。',48,'全唐诗/poet.song.115000.json','["郟鄏年方永，崆峒道益隆。", "憂勤三紀外，揖遜一言中。", "堯屋心非有，虞琴養正豐。", "乘雲帝鄉去，率土動悲風。"]'),
('1a1339c0-4e73-4f97-9437-7148b739923e','高宗聖神武文憲孝皇帝挽辭  其四','史浩','宋','宋诗','song-poetry','','[]','北內笳聲咽，旛幢蔽九關。',48,'全唐诗/poet.song.115000.json','["北內笳聲咽，旛幢蔽九關。", "龍輴菆禹穴，馬鬣等秦山。", "會奠風雲慘，垂洟雨露潛。", "傷心未央殿，時節玉巵間。"]'),
('4984ddb6-5a1e-4387-b34f-029bb7787f0a','高宗聖神武文憲孝皇帝挽辭  其五','史浩','宋','宋诗','song-poetry','','[]','念昔延英對，皇心眷瑣材。',48,'全唐诗/poet.song.115000.json','["念昔延英對，皇心眷瑣材。", "飜身辭璧水，舉武上蓬萊。", "日轂扶今聖，槐庭上亞臺。", "大恩無路報，淚血濺餘哀。"]'),
('61c8831c-eeba-444f-add0-c4e1e3a6a93b','姑夫王知錄挽辭','史浩','宋','宋诗','song-poetry','','[]','聞說先生效一官，清風已自迫人寒。',64,'全唐诗/poet.song.115000.json','["聞說先生效一官，清風已自迫人寒。", "功名未究黄粱夢，雲漢先成白玉棺。", "潤屋何妨藏萬卷，過庭咸喜得雙鸞。", "武陵仙窟君歸去，落莫桃花淚不乾。"]'),
('973ac26c-077f-4349-935f-58a75fb66205','豐必强母郭氏挽辭','史浩','宋','宋诗','song-poetry','','[]','汾陽遺澤渺千春，來配名家德有鄰。',64,'全唐诗/poet.song.115000.json','["汾陽遺澤渺千春，來配名家德有鄰。", "蟾窟初看攀桂子，萱堂忽失斷機人。", "秀眉影屬霜縑浄，斜日風開丹旐新。", "錦軸已聞生命誥，贈黄從此踵松筠。"]'),
('a3988b69-178d-4915-aed7-c1d9f55faadd','林通判妻挽辭','史浩','宋','宋诗','song-poetry','','[]','夕郎凜凜餘風烈，有女猶爲世婦師。',64,'全唐诗/poet.song.115000.json','["夕郎凜凜餘風烈，有女猶爲世婦師。", "處己幽閨推德厚，相夫賢路已名馳。", "秋天零露銘旌濕，曉月沈光獨鶴悲。", "他日贈黄頻錫寵，冢前羊虎石纍纍。"]'),
('03d41961-19d3-41c2-8366-dcd94ce44ef9','致政王宣義挽辭  其一','史浩','宋','宋诗','song-poetry','','[]','聖世尊遺逸，先生道最優。',48,'全唐诗/poet.song.115000.json','["聖世尊遺逸，先生道最優。", "浮名付詩酒，高論屈公侯。", "方綰新荷綬，俄隨夜壑舟。", "唯餘義方訓，歲晚欲興周。"]'),
('d82b2b9f-1e4b-4531-892f-ac6e1cbc103a','致政王宣義挽辭  其二','史浩','宋','宋诗','song-poetry','','[]','天大于門報，人歌竇氏芳。',48,'全唐诗/poet.song.115000.json','["天大于門報，人歌竇氏芳。", "諍臣登冢嗣，聖德在吾皇。", "栢慘方廬墓，琴祥定趣裝。", "他年疏大國，錦軸屢燔黄。"]'),
('70abd578-67c8-4309-bf61-0ea2a135a3ec','趙開府衛國夫人宋氏挽辭','史浩','宋','宋诗','song-poetry','','[]','生居宅相寵無倫，來蔭金枝德有隣。',64,'全唐诗/poet.song.115000.json','["生居宅相寵無倫，來蔭金枝德有隣。", "夫擁齋旄儀上宰，身兼郡主國夫人。", "方看十子翻丹鳳，忽憶三山駕紫麟。", "霜潔蘭薰全懿美，史官秉筆正誾誾。"]'),
('3eefb618-0cd3-4c59-b9f0-50e413cc0d19','吳明可閣學挽辭','史浩','宋','宋诗','song-poetry','','[]','持橐甘泉日，英聲聳縉紳。',48,'全唐诗/poet.song.115000.json','["持橐甘泉日，英聲聳縉紳。", "循良六郡守，蹇諤一臺臣。", "德亞耕萃叟，年同釣渭人。", "設施渾未盡，識者爲眉顰。"]'),
('d8cf8b39-30a8-43fc-b9bc-fd788603177a','虞好古挽辭','史浩','宋','宋诗','song-poetry','','[]','躡屩擔簦不厭頻，治安有策上嚴宸。',64,'全唐诗/poet.song.115000.json','["躡屩擔簦不厭頻，治安有策上嚴宸。", "朝爲逆旅馬助教，暮作南昌梅子真。", "豈是天教亡寸祿，祇應身欲到三神。", "從今遂泯凌雲氣，挂劍寒松淚滿巾。"]'),
('f7c3eee8-ae5b-45ef-9859-008759749bd9','樓予善使君挽辭  其一','史浩','宋','宋诗','song-poetry','','[]','游夏淵源鮑謝才，聲名雖泯思無涯。',64,'全唐诗/poet.song.115000.json','["游夏淵源鮑謝才，聲名雖泯思無涯。", "人間一葉靈芝落，地下千年玉葉埋。", "彭澤素琴塵自滿，茂陵遺藁志全乖。", "惜君多少凌雲氣，挂劍青松祇愴懷。"]'),
('1591aa56-fc00-4c46-b0b5-674dff6a609d','樓予善使君挽辭  其二','史浩','宋','宋诗','song-poetry','','[]','壯年方喜脫塵埃，便把州麾上釣臺。',64,'全唐诗/poet.song.115000.json','["壯年方喜脫塵埃，便把州麾上釣臺。", "冰鑑已明消健訟，民膏不取却餘財。", "官箴信爾無遺恨，家學端知有自來。", "欲識邦人思愷悌，水聲山色亦興哀。"]'),
('9233e689-6bc5-4181-9367-5a74a0dcf537','丞相魏大觀文挽辭','史浩','宋','宋诗','song-poetry','','[]','姚江得尉是公先，鳳沼居慙我在前。',64,'全唐诗/poet.song.115000.json','["姚江得尉是公先，鳳沼居慙我在前。", "退處對栽三徑柳，追歡時共五湖船。", "尚嗟鄰好無多日，何遽歸程隔九泉。", "苒苒衰遲易傷感，送違陡覺淚潸然。"]'),
('350803ae-6088-45f7-8057-a92b43e0336e','趙叔達侍郎挽辭  其一','史浩','宋','宋诗','song-poetry','','[]','山東真相種，邂逅處鄞川。',48,'全唐诗/poet.song.115000.json','["山東真相種，邂逅處鄞川。", "折桂丹猶渥，持荷紫更鮮。", "清談誇衆口，大筆炳遺編。", "無限凌雲氣，沈埋向九泉。"]'),
('2432bac0-101a-4b28-8e76-c0c1fe466d2f','趙叔達侍郎挽辭  其二','史浩','宋','宋诗','song-poetry','','[]','江外昔分符，人皆詠袴襦。',48,'全唐诗/poet.song.115000.json','["江外昔分符，人皆詠袴襦。", "有書充棟宇，無屋遠庖厨。", "容膝淵明舍，飲瓢顔氏徒。", "莫言太清儉，本是列僊儒。"]'),
('2215c4de-983b-427f-98d7-9e0aeb915c8d','錢師魏參政挽辭','史浩','宋','宋诗','song-poetry','','[]','冠歲踵英游，橋門雋逸流。',48,'全唐诗/poet.song.115000.json','["冠歲踵英游，橋門雋逸流。", "文章唐杜老，事業漢留侯。", "未旨黄金鼎，先成白玉樓。", "經綸展不盡，識者爲時憂。"]'),
('42fce906-f9f4-441f-9cf5-67cac82ac760','王季海丞相挽辭','史浩','宋','宋诗','song-poetry','','[]','寶歷隆興記，張羅獵鉅公。',48,'全唐诗/poet.song.115000.json','["寶歷隆興記，張羅獵鉅公。", "斗南人傑用，塞北馬羣空。", "紫橐論思績，黄扉造化功。", "祇今收實效，四海暢淳風。"]'),
('7cba6086-7508-412f-9339-12a108c2569f','胡長文閣學挽辭','史浩','宋','宋诗','song-poetry','','[]','聖主當年側席求，一時獻替盡嘉謀。',64,'全唐诗/poet.song.115000.json','["聖主當年側席求，一時獻替盡嘉謀。", "刑名不作漢晁錯，忠義有如唐馬周。", "夕闥未酬懷鼎志，坤臣徒起袴襦謳。", "忽乘鶴馭凌雲去，應與叢宵造物遊。"]'),
('bae934be-0d21-4abe-986a-fe4da58a578a','袁和叔父宣義挽詞','史浩','宋','宋诗','song-poetry','','[]','學子摳衣三鱣堂，芝蘭鬰鬰苞芬香。',64,'全唐诗/poet.song.115000.json','["學子摳衣三鱣堂，芝蘭鬰鬰苞芬香。", "古人用器列彜鼎，前輩遺編充棟梁。", "事業未容傳信史，功名端合付賢良。", "佳城他日祥光聚，知是幾番焚贈黄。"]'),
('2101086a-0813-4221-8567-9510696e01d6','童丱須知 君臣篇','史浩','宋','宋诗','song-poetry','','[]','渾沌判天地，高卑未相親。',288,'全唐诗/poet.song.115000.json','["渾沌判天地，高卑未相親。", "三才欲通貫，中間須有人。", "人最靈於物，民至愚而神。", "天地寄聰明，動靜必相因。", "飽食無用心，蚩蚩禽獸均。", "逸居苟不教，焉能敘彜倫。", "天地憫此類，是故立君臣。", "君以聖居上，發政先施仁。", "臣以賢作輔，法度期持循。", "聖賢適際會，利澤漸無垠。", "君或肆酷虐，百姓皆顰呻。", "君或用忠恕，四海熙如春。", "臣或進諂諛，陂僻正路堙。", "臣或善諫諍，君子之道伸。", "所以委質者，恭敬日恂恂。", "權倖不敢附，賄賂不足珍。", "窮達自有命，烏可毀天真。", "挺然秉中正，于以奉咨詢。", "言必稱堯舜，孟氏醇乎醇。", "從容引當道，納誨每諄諄。", "君如語好貨，公劉道可遵。", "居行有積裹，王業肇於豳。", "君如語好色，太王愛妃嬪。", "當時無怨曠，後效應騶麟。"]'),
('eb4d0e67-ae73-4797-b238-e1f03cb44ffd','童丱須知 父子篇','史浩','宋','宋诗','song-poetry','','[]','太易本空空，空中有太極。',288,'全唐诗/poet.song.115000.json','["太易本空空，空中有太極。", "太極判二儀，萬物斯生植。", "天地爲父母，萬物爲子息。", "人居萬物羣，最曰具靈識。", "兩家各生子，匪媒其可得。", "合禮成夫妻，相共孕英特。", "方當姙娠初，疾嘔不納食。", "妻既日呻吟，夫亦日憂惻。", "辛勤彌十月，存亡未可測。", "暨及震夙時，痛楚千萬億。", "稍或失調護，淪胥在頃刻。", "幸爾見嬰兒，歡色動顔色。", "乳哺更携持，幾年先用力。", "母實鍾愛憐，父亦思誨飭。", "資稟尚凡庸，視之如岐嶷。", "驕慢不率教，巧計爲藏匿。", "一語或中理，誇揚其肯默。", "葆養覬成人，庶幾供子職。", "提孩知愛親，此情何可抑。", "冬溫而夏凊，未足酬其德。", "昏定而晨省，未足酬其德。", "三牲滋美味，未足酬其德。", "四序紉華衣，未足酬其德。", "竭身至老死，未足酬其德。"]'),
('602a10c9-1f5f-47ea-8c5a-b1ee8744160d','童丱須知 夫婦篇','史浩','宋','宋诗','song-poetry','','[]','天地生萬物，陰陽相配偶。',264,'全唐诗/poet.song.115000.json','["天地生萬物，陰陽相配偶。", "兩家因媒妁，是以爲夫婦。", "男貴有器識，不問財薄厚。", "女貴有賢行，不問色妍醜。", "二者既相值，家肥得長久。", "二者儻不然，舉動多掣肘。", "夫無婦承順，何以事父母。", "婦無夫應援，何以事姑舅。", "外或專放蕩，薄游酗樽酒。", "內或資悍厲，爭競恣紛糾。", "儻信牝雞晨，長舌肆讒口。", "離間骨肉親，敗亂廉潔守。", "居官鮮德操，居家失孝友。", "漸漬不覺知，頓使初心負。", "故須礪剛方，循循常善誘。", "使其良心生，悔恨能自咎。", "若也縱沉迷，一切俱聽受。", "冥然在世間，禽獸而牝牡。", "堂堂六尺軀，方足俱圓首。", "聰明不下人，何乃畏仇偶。", "子孫則象之，餘殃貽厥後。", "吾言誠伐病，宜以銘座右。"]'),
('6585eda4-c1fb-4902-9310-765c27b91624','童丱須知 長幼篇','史浩','宋','宋诗','song-poetry','','[]','父母有男女，兄良必弟悌。',192,'全唐诗/poet.song.115000.json','["父母有男女，兄良必弟悌。", "天性所稟賦，初不煩法制。", "如何中道間，鬩牆成背戾。", "蓋由結婚姻，異姓以女妻。", "妻不嫻教訓，夫不恤苗裔。", "怨隙由愛惜，紛爭爲財計。", "浸潤日已久，同惡遂相濟。", "昆季若仇敵，長幼絕交際。", "孤然離索身，何以異狗彘。", "當思父母心，喜得賢子繼。", "爲彼慵懦兒，清陰均映蔽。", "如何我自賢，了不念同蔕。", "宜罄友于情，金蘭彰夙契。", "推心更及遠，落地皆魯衛。", "祥覽何人哉，高風馳萬世。", "俚言雖不文，將以助棠棣。"]'),
('fe393be5-72ff-464b-9dcd-391e190b5440','童丱須知 朋友篇','史浩','宋','宋诗','song-poetry','','[]','先王德澤深，士民皆修睦。',192,'全唐诗/poet.song.115000.json','["先王德澤深，士民皆修睦。", "琢磨貴取友，爲學不應獨。", "分寧非君臣，嚴光蹴帝腹。", "人君尚擇交，況乃爲臣僕。", "仕宦同恩榮，庠序同誦讀。", "萍蓬偶邂逅，里閈頻追逐。", "握手出肺肝，勤渠敘寒燠。", "一旦臨利害，獰然遂反目。", "朱博先著鞭，索居歎蕭育。", "不見管夷吾，全交有鮑叔。", "蘇章太不情，恩讎在隔宿。", "不見庾公斯，孺子生可卜。", "嗟哉世間人，雲雨徒飜覆。", "得喪自有天，人豈能禍福。", "險心懷五兵，壽命多短促。", "君子坦蕩蕩，爲之歌伐木。"]'),
('adb106e2-5f0b-449e-b27c-8cc1124f5c6a','童丱須知 祭祀篇','史浩','宋','宋诗','song-poetry','','[]','文王御家邦，風化必自邇。',288,'全唐诗/poet.song.115000.json','["文王御家邦，風化必自邇。", "采繁夫人職，專言奉祭祀。", "洪惟祖先心，貴得賢後嗣。", "匪取一時孝，覬其能事死。", "蓋自平生來，功行勤積累。", "防範不敢違，貽厥作基址。", "子孫洎有室，懵不知此理。", "燕飲恣歡謔，口腹縱奢靡。", "霜降雨露濡，愴惕昧所履。", "故其臨祭時，倦色成跛倚。", "酣歌或笑呼，憤怒或笞捶。", "不恤祭如在，大似不得已。", "祖先必吐之，豈復錫繁祉。", "我勸世間人，於此莫輕視。", "春秋祭享間，齋戒先恭己。", "憂思動哀慕，虔謹具芳美。", "時物堪薦新，當如奉甘旨。", "餖飣乎自供，焉可使奴婢。", "掃除蠲穢雜，滌灌去塵滓。", "馨香出釜甑，滋味登簠簋。", "勿爲貧故約，勿爲富故侈。", "豐儉或有常，不可變其軌。", "以此奉吾先，神靈必歡喜。", "緜緜百世後，餘慶何能弭。"]'),
('cc017aac-9dc9-4c12-be1b-88f2803dbd2c','童丱須知 舅姑篇','史浩','宋','宋诗','song-poetry','','[]','女子年既笄，出適乃從夫。',288,'全唐诗/poet.song.115000.json','["女子年既笄，出適乃從夫。", "從夫始曰婦，將以事舅姑。", "舅姑生男兒，鼓舞更忻愉。", "稟受胚胎成，身體洎髮膚。", "玩之如美玉，寶之如明珠。", "覬其能立身，孝養勤朝晡。", "豈知壯有室，却使失歡娛。", "婦既恣狼戾，夫亦與之俱。", "翁嫗有憎惡，導夫起嗟吁。", "叔妹有異胞，俾夫肆欺誣。", "及其享富貴，却云夫自圖。", "珍異私帑積，貲産別籍拘。", "不念翁與嫗，生爾夫之軀。", "不念叔與妹，爾夫當友于。", "動輒生離間，豈不負心乎。", "天殃或人禍，捨爾其誰誅。", "我有爲婦法，爾其聽而孚。", "凡事舅姑禮，與事親無殊。", "唯當輔君子，相勉以相須。", "定省問安否，溫凊視衣襦。", "俎豆奉燕樂，几杖供扶持。", "出因侍坐席，入則臨庖厨。", "親意或欲與，承命惟所需。", "不作曾元養，問有必曰無。"]'),
('f3e6c62c-7bad-410c-a6b2-13c5b3cef823','童丱須知 叔妹篇','史浩','宋','宋诗','song-poetry','','[]','婦欲事舅姑，先當和叔妹。',288,'全唐诗/poet.song.115000.json','["婦欲事舅姑，先當和叔妹。", "叔妹不我和，舅姑生怨憝。", "伯叔貴依義，崇恩胡可廢。", "晨昏同問安，致敬斂身退。", "語笑不妄發，正色絕冶態。", "夜行必以燭，相遇毋盼睞。", "女妹貴親暱，唯當盡恩愛。", "椸枷混衣裳，粧奩同粉黛。", "威儀俾嫻習，紉縫勤教誨。", "其間有過差，識性須忍耐。", "伯叔各生子，嬉戲魚同隊。", "切勿分彼己，愛猶我兒輩。", "姊妹或歸寧，親戚無阻礙。", "童稚既撫存，僕妾亦下逮。", "彼於父母前，豈不知欣戴。", "遂使高堂言，吾子得賢配。", "推此厚族黨，睦婣居外內。", "心期在陰德，施惠每韜晦。", "喪葬乏資財，男女未婚對。", "稱家之有無，彼必懷感佩。", "歲時饋壺漿，燕享盍簪玳。", "貧富與貴賤，待之宜一槩。", "猗歟行此行，婦德無瑕纇。", "萬口併一談，可貽彤管載。"]'),
('bbb75cae-21c1-4b90-98bb-2d970ea19419','童丱須知 娣姒篇','史浩','宋','宋诗','song-poetry','','[]','兄弟各授室，爰歸事夫祖。',288,'全唐诗/poet.song.115000.json','["兄弟各授室，爰歸事夫祖。", "是爲叔伯姒，異姓始相聚。", "習氣或氷炭，安可一塗取。", "故當專和柔，順適無違拒。", "彼有妒嫉心，作意相狎侮。", "惟知以善誘，不異魚相與。", "彼有狼戾心，凌轢猛如虎。", "惟知以理遣，茹剛宜勿吐。", "奴媵工讒譖，間諜多簧鼓。", "嬰孩羣戯弄，叫啼負寃苦。", "恩怨霎時間，信之誠無補。", "見境勿動懷，表吾中有主。", "子姪無分別，一意思存撫。", "不見北平王，貓尚能相乳。", "財物有通無，寒溫均帛縷。", "不見柳河東，數世同門戶。", "今人有女兒，不教以規矩。", "唯與婢妾羣，曾不師保姆。", "一旦入夫門，驕橫不足數。", "長舌爲厲階，牝雞晨風雨。", "夫既無剛腸，間言遂旁午。", "兄弟若仇讎，有面不相覩。", "異爨或索居，分財或析土。", "同胞謂慈親，同氣謂嚴父。"]'),
('2095413d-643d-4b5d-b947-95d5a0d0ac30','童丱須知 臧獲篇','史浩','宋','宋诗','song-poetry','','[]','人生貴適意，安佚固有以。',216,'全唐诗/poet.song.115000.json','["人生貴適意，安佚固有以。", "便嬖足使令，臧獲皆率俾。", "婢實居深閨，奴當立階戺。", "內外儻致嚴，家法斯盡理。", "怙勢以作威，招權自豐己。", "奴或有是人，刑罰不可弛。", "銜寃恣狠傲，妒寵專負恃。", "奴或有是人，斥逐其可已。", "處衆能包容，見得思廉恥。", "守分每知足，愛主常歸美。", "忠謹輩行服，和柔姊妹喜。", "爲之有室家，周旋表終始。", "其或小瑕疪，過誤非姦宄。", "第當明戒飭，勿遽施鞭捶。", "其或肆讒間，作意生荆杞。", "第當親骨肉，不可黨奴婢。", "骨肉長聚頭，奴婢安可儗。", "凡百御下人，讀此味其旨。"]'),
('aed31335-431b-4e92-ba50-947c0e887a52','童丱須知 敬天篇','史浩','宋','宋诗','song-poetry','','[]','古者明良會，君臣必敬天。',48,'全唐诗/poet.song.115000.json','["古者明良會，君臣必敬天。", "小心常翼翼，終日自坤乾。", "雷電彰威怒，星辰是變遷。", "凌兢每寅畏，上帝必垂憐。"]'),
('00fda222-3117-46f5-a941-7ed1bfbb1639','童丱須知 傳道篇','史浩','宋','宋诗','song-poetry','','[]','帝王學有源，執中以傳道。',48,'全唐诗/poet.song.115000.json','["帝王學有源，執中以傳道。", "塞路排楊墨，逃親鄙釋老。", "大學吾所行，中庸吾所保。", "直下肯承當，後人斯有考。"]'),
('06ec881e-51db-49ed-81a5-756cfdb67e3d','童丱須知 修德篇','史浩','宋','宋诗','song-poetry','','[]','生身天地間，所貴在修德。',48,'全唐诗/poet.song.115000.json','["生身天地間，所貴在修德。", "衆善既奉行，諸惡當屏息。", "美利世同霑，陰功人不識。", "冥心契上天，享祐無紀極。"]'),
('84cdf801-49c5-4f39-a49d-9fbb6d0cc10d','童丱須知 恤民篇','史浩','宋','宋诗','song-poetry','','[]','主聖臣賢日，勤政在恤民。',48,'全唐诗/poet.song.115000.json','["主聖臣賢日，勤政在恤民。", "差徭唯務息，賦斂直須均。", "但使皆當富，何憂富却貧。", "孟公仁義說，不取利吾身。"]'),
('8282fde6-3731-4619-a3d1-26dcde380c41','童丱須知 措刑篇','史浩','宋','宋诗','song-poetry','','[]','堯舜雍熙治，成功在措刑。',48,'全唐诗/poet.song.115000.json','["堯舜雍熙治，成功在措刑。", "哀矜行法令，欽恤愛生靈。", "若使殺無罪，寧教失不經。", "于公尚陰德，何況是朝廷。"]'),
('76fec05b-cabe-4f1c-9544-250b5a8c4130','童丱須知 樂聲篇','史浩','宋','宋诗','song-poetry','','[]','樂聲表至和，在乎民共樂。',48,'全唐诗/poet.song.115000.json','["樂聲表至和，在乎民共樂。", "百姓或怨咨，八音徒振作。", "朝歌商紂擒，煖響奏嬰縛。", "四海得歡心，全勝聽弦索。"]'),
('953098c6-975c-4214-8797-65e8be0e231b','童丱須知 忠恕篇','史浩','宋','宋诗','song-poetry','','[]','君子行忠恕，報恩不報仇。',48,'全唐诗/poet.song.115000.json','["君子行忠恕，報恩不報仇。", "恩者人善意，一飯亦當酬。", "仇者被迷誤，事過何足尤。", "持之久不倦，其心乃休休。"]'),
('9d26d8da-f3b9-4a1d-ba9e-d5de6fa3a597','童丱須知 疏財篇','史浩','宋','宋诗','song-poetry','','[]','人生貴疏財，過富誠多事。',48,'全唐诗/poet.song.115000.json','["人生貴疏財，過富誠多事。", "愚固益其過，賢亦損其志。", "指廩憫人窮，揮金侈上賜。", "萬古播清名，誰云能敗類。"]'),
('1567ebe8-aead-4ecd-9215-0eaabb2de492','童丱須知 見德篇','史浩','宋','宋诗','song-poetry','','[]','凡人在世間，不曉乘除理。',48,'全唐诗/poet.song.115000.json','["凡人在世間，不曉乘除理。", "非義或得財，捫心未可喜。", "俸祿却蕭條，子孫仍委靡。", "更有禍隨身，陰譴何時已。"]'),
('cc74bca3-edf2-4349-bcb6-11a720aac2a2','童丱須知 習尚篇','史浩','宋','宋诗','song-poetry','','[]','習尚從何來，影響由先世。',48,'全唐诗/poet.song.115000.json','["習尚從何來，影響由先世。", "好禮必溫恭，收書乃文藝。", "初心儻不思，後弊必難制。", "古人約其身，所以裕苗裔。"]'),
('ce7b1d4d-2d9b-47c9-8347-c9d6b5f75ec1','童丱須知 宮室八篇 其一','史浩','宋','宋诗','song-poetry','','[]','茅茨不翦階三尺，自古唐虞是聖人。',32,'全唐诗/poet.song.115000.json','["茅茨不翦階三尺，自古唐虞是聖人。", "萬樂阿房歌舞地，只消一炬化爲塵。"]'),
('4f7c6941-fa09-4492-929f-e49dee561abd','童丱須知 宮室八篇 其二','史浩','宋','宋诗','song-poetry','','[]','大禹卑宮自一身，能令四海敘彜倫。',32,'全唐诗/poet.song.115000.json','["大禹卑宮自一身，能令四海敘彜倫。", "雕牆峻宇垂丕訓，更有遺風及後人。"]'),
('23af7911-79de-4eaf-92fc-1f4b3e10cef3','童丱須知 宮室八篇 其三','史浩','宋','宋诗','song-poetry','','[]','相國當年葺未央，欲將壯麗奉高皇。',32,'全唐诗/poet.song.115000.json','["相國當年葺未央，欲將壯麗奉高皇。", "誰知後裔求增廣，萬戶千門起建章。"]'),
('ab5e29e9-19af-48cb-b365-e6ad49cfd211','童丱須知 宮室八篇 其四','史浩','宋','宋诗','song-poetry','','[]','榱題數尺聳高堂，得志吾人正未遑。',32,'全唐诗/poet.song.115000.json','["榱題數尺聳高堂，得志吾人正未遑。", "若有賢名并德行，茅茨之下亦風光。"]'),
('8e26966e-e5b9-4c20-8894-37e1fbbb14ce','童丱須知 宮室八篇 其五','史浩','宋','宋诗','song-poetry','','[]','廣厦須增千萬間，普令寒士盡歡顔。',32,'全唐诗/poet.song.115000.json','["廣厦須增千萬間，普令寒士盡歡顔。", "少陵自處知何所，低小茅簷鷰往還。"]'),
('c564f060-6f39-42e4-8654-6967015209fd','童丱須知 宮室八篇 其六','史浩','宋','宋诗','song-poetry','','[]','數間破屋洛城中，却有高名振古風。',32,'全唐诗/poet.song.115000.json','["數間破屋洛城中，却有高名振古風。", "寄語紛紛美宅者，安居寧不愧盧仝。"]'),
