('58145a4b-0263-43ec-a44a-62f8b5e39725','童丱須知 酒醴八篇 其一','史浩','宋','宋诗','song-poetry','','[]','歡欣歌飲皆從欠，樂極悲哀自此生。',32,'全唐诗/poet.song.115000.json','["歡欣歌飲皆從欠，樂極悲哀自此生。", "不見古人成禮處，主賓百拜只三行。"]'),
('dc27dd3b-2fe1-4581-bcaf-c5374fffed31','童丱須知 酒醴八篇 其二','史浩','宋','宋诗','song-poetry','','[]','越主投醪仇可報，商家沈酗自相攻。',32,'全唐诗/poet.song.115000.json','["越主投醪仇可報，商家沈酗自相攻。", "的知此物難多飲，只爲邦家作禮容。"]'),
('bbebfdf6-1e34-4720-8f06-91a6c360e883','童丱須知 酒醴八篇 其三','史浩','宋','宋诗','song-poetry','','[]','爲子孫順爲臣忠，夫妻和睦弟恭兄。',32,'全唐诗/poet.song.115000.json','["爲子孫順爲臣忠，夫妻和睦弟恭兄。", "如何却致彜綸斁，只爲貪他酒味醲。"]'),
('a7c867e2-35cc-487b-af41-a223c2516785','童丱須知 酒醴八篇 其四','史浩','宋','宋诗','song-poetry','','[]','平日恂恂號古人，三杯纔飲亂天真。',32,'全唐诗/poet.song.115000.json','["平日恂恂號古人，三杯纔飲亂天真。", "精神憒憒如癡夢，贏得時時病在身。"]'),
('193914e9-9276-4fb1-9420-ea0c8949a271','童丱須知 酒醴八篇 其五','史浩','宋','宋诗','song-poetry','','[]','酒可忘憂更養神，直須少飲始爲真。',32,'全唐诗/poet.song.115000.json','["酒可忘憂更養神，直須少飲始爲真。", "君看阮籍劉伶輩，終爲沉酣喪此身。"]'),
('debf705d-41bb-4f74-a5e7-b91f46d3fa8c','童丱須知 酒醴八篇 其六','史浩','宋','宋诗','song-poetry','','[]','女子親傍禮法拘，合移孝道事翁姑。',32,'全唐诗/poet.song.115000.json','["女子親傍禮法拘，合移孝道事翁姑。", "若還徑醉無醒日，亦自無心相厥夫。"]'),
('48c5c9f2-15e0-4667-ad07-9eaccc8242e2','童丱須知 酒醴八篇 其七','史浩','宋','宋诗','song-poetry','','[]','居家姆傳未曾成，纔及笄年便有行。',32,'全唐诗/poet.song.115000.json','["居家姆傳未曾成，纔及笄年便有行。", "中饋既然長酩酊，兒孫婢僕盡縱橫。"]'),
('c8d23dad-0f37-4ec9-8e49-7883c50b462b','童丱須知 酒醴八篇 其八','史浩','宋','宋诗','song-poetry','','[]','休說私酤趁得錢，官場警捕致憂煎。',32,'全唐诗/poet.song.115000.json','["休說私酤趁得錢，官場警捕致憂煎。", "錐刀未必成家計，家計因茲却蕩然。"]'),
('066dee47-1c03-4e7f-a500-2de3dd8dc990','童丱須知 膳羞八篇 其一','史浩','宋','宋诗','song-poetry','','[]','聖主勤勤欲措刑，何嘗黷武愛興兵。',32,'全唐诗/poet.song.115000.json','["聖主勤勤欲措刑，何嘗黷武愛興兵。", "四方罷貢傷生物，愈見仁恩浹有情。"]'),
('5d532616-97ab-4021-92c4-69ff25fee1f4','童丱須知 膳羞八篇 其二','史浩','宋','宋诗','song-poetry','','[]','設牧端因饗鬼神，大亨亦爲養賢人。',32,'全唐诗/poet.song.115000.json','["設牧端因饗鬼神，大亨亦爲養賢人。", "掄材祈福緣何事，只爲蒼生不爲身。"]'),
('37aeac33-6e06-42c5-9aa3-69b2d0930dff','童丱須知 膳羞八篇 其三','史浩','宋','宋诗','song-poetry','','[]','滹沱麥飯出匆匆，禁臠天厨未必豐。',32,'全唐诗/poet.song.115000.json','["滹沱麥飯出匆匆，禁臠天厨未必豐。", "若使平安能念此，鉶羹土塯古人同。"]'),
('cd133838-a3c5-47df-ad07-25a1ab195adb','童丱須知 膳羞八篇 其四','史浩','宋','宋诗','song-poetry','','[]','嗟見時人大侈生，八珍同聚一杯羹。',32,'全唐诗/poet.song.115000.json','["嗟見時人大侈生，八珍同聚一杯羹。", "若知過口成汙穢，何用留心事割烹。"]'),
('09177190-5e39-43ed-802d-dc608914066a','童丱須知 膳羞八篇 其五','史浩','宋','宋诗','song-poetry','','[]','物因相勝還相啖，弱者多爲强者亨。',32,'全唐诗/poet.song.115000.json','["物因相勝還相啖，弱者多爲强者亨。", "勿謂天教充食類，斯人豈爲虎狼生。"]'),
('eb7a530d-3111-4149-a00c-ee799ffb56b7','童丱須知 膳羞八篇 其六','史浩','宋','宋诗','song-poetry','','[]','二膳朝朝飽即休，何須嗜殺苦營求。',32,'全唐诗/poet.song.115000.json','["二膳朝朝飽即休，何須嗜殺苦營求。", "魚鰕蟹蛤皆微細，數百方能滿一甌。"]'),
('ee8f9c1d-c453-40ff-be4e-891ae26ce258','童丱須知 膳羞八篇 其七','史浩','宋','宋诗','song-poetry','','[]','飛潛蠕動盡貪生，就死無辜或自鳴。',32,'全唐诗/poet.song.115000.json','["飛潛蠕動盡貪生，就死無辜或自鳴。", "只可爲親甘旨具，自家口腹莫頻亨。"]'),
('679e3c64-8970-4870-a772-e7f168a8b171','童丱須知 膳羞八篇 其八','史浩','宋','宋诗','song-poetry','','[]','戒殺當知有數端，聞聲見死敢加餐。',32,'全唐诗/poet.song.115000.json','["戒殺當知有數端，聞聲見死敢加餐。", "居家自作專因我，雖美還應下筯難。"]'),
('ea57f535-6b9f-4ae1-bfde-91ac7f23e8f2','童丱須知 梳粧八篇 其一','史浩','宋','宋诗','song-poetry','','[]','隨宜首飾莫留情，珠翠雖多未是榮。',32,'全唐诗/poet.song.115000.json','["隨宜首飾莫留情，珠翠雖多未是榮。", "不見孟光居儉約，荆釵却立萬年名。"]'),
('1ee9e6d0-b60b-4e56-9ef1-5908ac7dd00b','童丱須知 梳粧八篇 其二','史浩','宋','宋诗','song-poetry','','[]','南蕃有鳥翠葳蕤，千百爲羣自在飛。',32,'全唐诗/poet.song.115000.json','["南蕃有鳥翠葳蕤，千百爲羣自在飛。", "負痛銜寃無罪死，將來貴室縷冠衣。"]'),
('345ce78f-d02e-4ebc-9915-df7dff66b17d','童丱須知 梳粧八篇 其三','史浩','宋','宋诗','song-poetry','','[]','貴家所好若無偏，翠羽真珠不直錢。',32,'全唐诗/poet.song.115000.json','["貴家所好若無偏，翠羽真珠不直錢。", "簪珥一求難得貨，窮山深海盡騷然。"]'),
('192ffc1d-11d0-4c6c-9160-d75e483387af','童丱須知 梳粧八篇 其四','史浩','宋','宋诗','song-poetry','','[]','生靈膏血是緡錢，買得珍珠顆顆圓。',32,'全唐诗/poet.song.115000.json','["生靈膏血是緡錢，買得珍珠顆顆圓。", "痛惜鮫人在深海，風潮沉溺幾多船。"]'),
('4b172343-d71d-45a3-854d-7fdfb2047dc2','童丱須知 梳粧八篇 其五','史浩','宋','宋诗','song-poetry','','[]','北珠天産在戎蕃，不定還看走玉盤。',32,'全唐诗/poet.song.115000.json','["北珠天産在戎蕃，不定還看走玉盤。", "鉅萬費錢收拾得，到頭終不救饑寒。"]'),
('980f09b7-4ff2-427f-bbf6-a8a974ef3bc9','童丱須知 梳粧八篇 其六','史浩','宋','宋诗','song-poetry','','[]','繡草鋪茸玉作冠，四時花樣幾千般。',32,'全唐诗/poet.song.115000.json','["繡草鋪茸玉作冠，四時花樣幾千般。", "當思蓬首寒窗女，終歲無油兩鬢乾。"]'),
('2d4ad044-598e-4cd1-8a5b-b3fa679a3d1c','童丱須知 梳粧八篇 其七','史浩','宋','宋诗','song-poetry','','[]','倡優卑賤起淫風，塗澤唯知特地濃。',32,'全唐诗/poet.song.115000.json','["倡優卑賤起淫風，塗澤唯知特地濃。", "珍重賢門貞潔女，不施朱粉自雍容。"]'),
('73a953e5-942c-40ee-a82a-d2b03bd81d0f','童丱須知 梳粧八篇 其八','史浩','宋','宋诗','song-poetry','','[]','常須默坐悟前因，爲愛鉛華墮女身。',32,'全唐诗/poet.song.115000.json','["常須默坐悟前因，爲愛鉛華墮女身。", "若也於斯能改悔，來生定免落風塵。"]'),
('acf6effc-9729-4c28-9c88-3cbfa5d7acd7','童丱須知 稻粱八篇 其一','史浩','宋','宋诗','song-poetry','','[]','后稷星光燦混儀，天教墮地作農師。',32,'全唐诗/poet.song.115000.json','["后稷星光燦混儀，天教墮地作農師。", "牛羊腓字寒氷暖，自有神明默護持。"]'),
('379406bd-607a-4ba1-a1bd-40164adaf772','童丱須知 稻粱八篇 其二','史浩','宋','宋诗','song-poetry','','[]','方冊嘗觀無逸書，更於七月誦豳詩。',32,'全唐诗/poet.song.115000.json','["方冊嘗觀無逸書，更於七月誦豳詩。", "周公愛主真深切，稼穡艱難先使知。"]'),
('c92b6fb2-ba20-4434-82d3-6f3122a9ed1b','童丱須知 稻粱八篇 其三','史浩','宋','宋诗','song-poetry','','[]','能述先王播殖功，伯禽之後有僖公。',32,'全唐诗/poet.song.115000.json','["能述先王播殖功，伯禽之後有僖公。", "故雖牧養駉駉盛，務惜吾農不起戎。"]'),
('4598b794-fda5-475c-a513-bc19bc2a51bd','童丱須知 稻粱八篇 其四','史浩','宋','宋诗','song-poetry','','[]','文帝年年下璽書，唯憂農畝不豐餘。',32,'全唐诗/poet.song.115000.json','["文帝年年下璽書，唯憂農畝不豐餘。", "匈奴嫚侮吾甘忍，所喜千倉飽貯儲。"]'),
('0d2b14d9-3c1b-46cc-b6fb-005565965aaf','童丱須知 稻粱八篇 其五','史浩','宋','宋诗','song-poetry','','[]','武帝征誅不厭頻，太倉無復有陳陳。',32,'全唐诗/poet.song.115000.json','["武帝征誅不厭頻，太倉無復有陳陳。", "末年戶口多虛耗，却始封侯欲富民。"]'),
('6163fa90-ba75-49b7-a9d1-ca6ddf51c32c','童丱須知 稻粱八篇 其六','史浩','宋','宋诗','song-poetry','','[]','古者四民今六民，爲添釋老不耕耘。',32,'全唐诗/poet.song.115000.json','["古者四民今六民，爲添釋老不耕耘。", "三農重困皆因此，況有張頤百萬軍。"]'),
('72a52d6d-f8e0-4f68-821f-3255d370c984','童丱須知 稻粱八篇 其七','史浩','宋','宋诗','song-poetry','','[]','勿嫌糠粃勿嫌陳，當念農家種苦辛。',32,'全唐诗/poet.song.115000.json','["勿嫌糠粃勿嫌陳，當念農家種苦辛。", "輸得逋租盈廩廥，却歸耕隴作饑民。"]'),
('dbce39d1-00f7-4ac3-b3ba-0af90910bcba','童丱須知 稻粱八篇 其八','史浩','宋','宋诗','song-poetry','','[]','代耕有祿及嬰孩，飲啄當知所自來。',32,'全唐诗/poet.song.115000.json','["代耕有祿及嬰孩，飲啄當知所自來。", "若也食焉無怠事，庶於報國有涓埃。"]'),
('64618654-17d3-4d1d-a985-737fcf52de6e','天申節錫宴當筵致語口號  其一','史浩','宋','宋诗','song-poetry','','[]','帝眷炎圖億萬秋，真人秉籙御神州。',64,'全唐诗/poet.song.115000.json','["帝眷炎圖億萬秋，真人秉籙御神州。", "通和鄰壤邊聲息，仁浹群生協氣流。", "一札鳳飛瓊苑詔，千官花擁醉鄉遊。", "江城今日騰嘉頌，遥認中天絳闕浮。"]'),
('3baad234-0d90-4ef4-ad72-2e2eedd7c039','天申節錫宴當筵致語口號  其二','史浩','宋','宋诗','song-poetry','','[]','邑近蓬萊萃劉真，曉看簪履望堯雲。',64,'全唐诗/poet.song.115000.json','["邑近蓬萊萃劉真，曉看簪履望堯雲。", "三呼請祝聖人壽，億載長爲天下君。", "荷柄飛香浮碧斚，榴花照座舞紅裙。", "更聽既醉昇平雅，始信宸恩浹海垠。"]'),
('da024aa4-de43-4da1-ae73-ec5e39e04dbe','天申節望闕祝聖致語口號  其一','史浩','宋','宋诗','song-poetry','','[]','簪纓萬國拱堯雲，遥認霏烟靄帝閽。',64,'全唐诗/poet.song.115000.json','["簪纓萬國拱堯雲，遥認霏烟靄帝閽。", "始聽嵩呼徧夷夏，便知孝治感乾坤。", "鳳飛一札蟠桃宴，花覆千官湛露恩。", "歷數在躬無紀極，垂衣請頌有虞尊。"]'),
('5607b167-a0f2-4578-b997-0144e65c2188','天申節望闕祝聖致語口號  其二','史浩','宋','宋诗','song-poetry','','[]','萬國星聯拱北辰，曉看簪履拜堯雲。',64,'全唐诗/poet.song.115000.json','["萬國星聯拱北辰，曉看簪履拜堯雲。", "三呼請祝聖人壽，億載長爲天下君。", "樂奏廣庭聲縹緲，香騰寰海瑞氤氳。", "太平今日非無象，花覆千官玉臉熏。"]'),
('1473a488-8479-4b7e-a4d8-5e4e746be071','上明良慶會閣碑致語口號','史浩','宋','宋诗','song-poetry','','[]','綿綿寶曆與天長，興運重光屬我皇。',64,'全唐诗/poet.song.115000.json','["綿綿寶曆與天長，興運重光屬我皇。", "德洽化隆超漢晉，父慈子孝協虞唐。", "三階順軌時萬泰，萬國歸心道益昌。", "一自皋陶賡載後，于今始得頌明良。"]'),
('21d9886b-8665-4704-b8af-464a172ffbdb','叔父知縣慶宅并章服致語口號','史浩','宋','宋诗','song-poetry','','[]','簪纓濟濟佩鏘鏘，競集華堂獻壽觴。',64,'全唐诗/poet.song.115000.json','["簪纓濟濟佩鏘鏘，競集華堂獻壽觴。", "朱紱始聞新命誥，青氈俄睹舊門牆。", "梁闈琴瑟聲俱妙，謝砌芝蓀氣倍香。", "爛醉莫嫌歡未徹，從今三萬六千場。"]'),
('f81e9d66-2f8c-4718-95d1-55ef8652db06','代人納婿親會致語口號','史浩','宋','宋诗','song-poetry','','[]','人物宣城妙九州，乘龍果是屬清流。',64,'全唐诗/poet.song.115000.json','["人物宣城妙九州，乘龍果是屬清流。", "相逢解賦澄江練，上勝都歸疊嶂樓。", "畫戟林中銀漏迥，香梅影底玉杯浮。", "洞房咫尺笙歌沸，誰道華胥祇夢遊。"]'),
('f977ba50-08a9-468c-9607-9924518a8df8','叔父鹽簿慶宅致語口號','史浩','宋','宋诗','song-poetry','','[]','清曉簪裾碾畫輪，更循玉砌擁蘭蓀。',64,'全唐诗/poet.song.115000.json','["清曉簪裾碾畫輪，更循玉砌擁蘭蓀。", "定知廣厦新遺址，來向華堂上壽樽。", "歌遏錦雲聲縹緲，舞攢星蠟影翩翻。", "剩須拚却如泥醉，顯拜行符駟馬門。"]'),
('a8b952c7-a6c0-481a-9b77-15007893c5bb','餘姚待縣官致語口號','史浩','宋','宋诗','song-poetry','','[]','浙右風烟屬舜亭，幾年纔此萃群英。',64,'全唐诗/poet.song.115000.json','["浙右風烟屬舜亭，幾年纔此萃群英。", "棠敷靈蔭連天闊，湖泛恩波澈底清。", "醉吸霞光金盞窄，笑扶花影玉山傾。", "定知太史先占瑞，天外祥星一處明。"]'),
('ca8b9683-b180-44a1-8a3e-a0c3977f78ab','餘姚待新宰致語口號','史浩','宋','宋诗','song-poetry','','[]','清朝出宰是郎星，牛刃恢恢正發硎。',64,'全唐诗/poet.song.115000.json','["清朝出宰是郎星，牛刃恢恢正發硎。", "賓佐雍容心盡赤，杯盤酬對眼全青。", "政平况是庭無訟，俗易還聞戶不扃。", "贏得通宵恣歡謔，看看聯翮上朝廷。"]'),
('2044c14b-60ab-4ff3-aebe-965827ca9f81','代新餘姚高宰燕友致語口號','史浩','宋','宋诗','song-poetry','','[]','鬰葱佳氣擁茲辰，兩見姚江得主人。',64,'全唐诗/poet.song.115000.json','["鬰葱佳氣擁茲辰，兩見姚江得主人。", "報最已聞歌滿道，告新還善政如神。", "詞傳綺席鶑聲滑，酒吸紅波玉臉春。", "休向陽關惜分袂，他年接武侍嚴宸。"]'),
('4d84d1b0-f6d0-40a4-867e-4eb186170f0f','代餘姚高宰侍郎以下致語口號','史浩','宋','宋诗','song-poetry','','[]','舜亭風化儼當年，人物猶追之凱賢。',64,'全唐诗/poet.song.115000.json','["舜亭風化儼當年，人物猶追之凱賢。", "持橐有功先計相，題輿出治亦儒先。", "相看尹貳俱冰雪，消得杯盤列管弦。", "欲識他時風虎變，疑丞輔弼拱中天。"]'),
('97cd05dc-abe0-43f5-8d52-138e2a016bf3','餘姚縣燕貢士致語口號','史浩','宋','宋诗','song-poetry','','[]','玉京才子宴瑶池，雪壓梅梢春近時。',64,'全唐诗/poet.song.115000.json','["玉京才子宴瑶池，雪壓梅梢春近時。", "盡道舜江登舜牧，却歸堯殿侍堯咨。", "鵬摶看即掀雙翼，鯨飲何辭酒百巵。", "好是嫦娥倚丹桂，擬教人折一枝枝。"]'),
('28022b9b-c69e-4339-b925-438e77f5f2a7','代餘姚李宰燕交致語口號','史浩','宋','宋诗','song-poetry','','[]','鬰葱佳瑞藹姚州，令尹聯翩得勝流。',64,'全唐诗/poet.song.115000.json','["鬰葱佳瑞藹姚州，令尹聯翩得勝流。", "報最已聞騰茂績，告新行復著芳猷。", "歌傳白雪歡聲洽，酒浥青樽喜氣浮。", "莫惜通宵恣談謔，他年接武侍宸遊。"]'),
('f759b454-ebd5-4751-a140-bd637031d947','代趙倅燕廣德守錢郎中致語口號','史浩','宋','宋诗','song-poetry','','[]','清朝登用是儒宗，尤喜桐川協氣濃。',64,'全唐诗/poet.song.115000.json','["清朝登用是儒宗，尤喜桐川協氣濃。", "畫戟林中今長貳，紅蓮幕裏昔游從。", "雲飛共慶情方洽，鯨飲何妨量有容。", "且向山城足歡謔，他年接武亞夔龍。"]'),
('7c607206-47dc-4985-85e2-3161c7d3a180','代寄居餞明守王侍郎致語口號','史浩','宋','宋诗','song-poetry','','[]','芝封一札燕泥香，祖帳雍容綺席張。',64,'全唐诗/poet.song.115000.json','["芝封一札燕泥香，祖帳雍容綺席張。", "坐上共知環鮑謝，人間爭欲借龔黄。", "旌旜影裏傳金斝，衮繡光中拜玉皇。", "他日回頭東海岸，定應遺愛滿甘棠。"]'),
('04eb9e5a-5ab9-4f69-87f9-fe99236ac000','寄居爲諸學職慶壽致語口號','史浩','宋','宋诗','song-poetry','','[]','朝來太史上宸廷，爲說東鄞集壽星。',64,'全唐诗/poet.song.115000.json','["朝來太史上宸廷，爲說東鄞集壽星。", "已把湖山供笑樂，更催歌舞看娉婷。", "藍田有玉應千歲，韋室專門祇六經。", "接武定應成福祿，介眉何惜醉修齡。"]'),
('7387e77b-72a8-4922-b7f8-b3792b865f4e','寄居爲諸鄉老慶壽致語口號','史浩','宋','宋诗','song-poetry','','[]','海宇熙熙壽域中，耆儒最盛甬勾東。',64,'全唐诗/poet.song.115000.json','["海宇熙熙壽域中，耆儒最盛甬勾東。", "共開樽俎爲高會，尤喜鄉閭有義風。", "九老未應多白傅，四明何止一黄公。", "行看聯璧安車上，盡是當筵鶴髮翁。"]'),
('d5f73635-f2c0-4ee6-af0d-083056a9605d','四明尊老會致語口號  其一','史浩','宋','宋诗','song-poetry','','[]','東閣初開瑞靄凝，曉催簪履慶脩齡。',64,'全唐诗/poet.song.115000.json','["東閣初開瑞靄凝，曉催簪履慶脩齡。", "風回秀發扶疏綠，喜入方瞳的皪青。", "紗帽著花春不老，玉杯浮雪酒微醒。", "今朝太史占鄞鄮，無限文星作壽星。"]'),
('9644cb94-411a-41ee-93f9-296c6a7e3da4','四明尊老會致語口號  其二','史浩','宋','宋诗','song-poetry','','[]','山在虛無縹緲間，相望同是一鄉關。',64,'全唐诗/poet.song.115000.json','["山在虛無縹緲間，相望同是一鄉關。", "欲尊德齒成高會，且遣樽罍悅壽顔。", "歌罷青絲回雪髮，舞餘文錦繞雲鬟。", "□□□□□□醉，貴老行看一札頒。"]'),
('0432bd83-46ad-445f-8214-87e8c052894e','諸親慶賜第復會致語口號','史浩','宋','宋诗','song-poetry','','[]','鶴髮星星退急流，昔年兩作鳳池游。',64,'全唐诗/poet.song.115000.json','["鶴髮星星退急流，昔年兩作鳳池游。", "掛冠未許田間去，錫第還爲帝所留。", "剩喜親朋千里集，聊持歌舞一觥酬。", "莫辭醉席梅花地，嘉話歸傳古鄮州。"]'),
('6590dbf1-9b73-4f02-9328-a4e330405a26','諸親慶彌正彌遠及具叔懷恩命復會致語口號','史浩','宋','宋诗','song-poetry','','[]','都城賜第起祥雲，知是君王貴老人。',64,'全唐诗/poet.song.115000.json','["都城賜第起祥雲，知是君王貴老人。", "羅綺叢中喧鼓吹，樓臺影裏聚簪紳。", "剩添風月非錢買，贏得樽罍到手頻。", "他日華堂重此會，主賓朱紫耀青春。"]'),
('899179a9-8a23-4afc-b8f2-a40a376b0852','復明守謝直閣會致語口號','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鄮水鄞江喜氣浮，祇應共理得賢侯。',64,'全唐诗/poet.song.115000.json','["鄮水鄞江喜氣浮，祇應共理得賢侯。", "千帆過海欣無警，九穀登場慶有秋。", "聖主正思黄霸入，仙翁方伴赤松遊。", "一杯相遇何妨醉，春在西湖月在樓。"]'),
('315a355c-9f04-4899-babf-9cf53bc9889b','待魏丞相汪尚書趙侍郎致語口號','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','燕集西湖錦繡圍，花迎晴曉露方晞。',64,'全唐诗/poet.song.115000.json','["燕集西湖錦繡圍，花迎晴曉露方晞。", "把杯且共尋前約，控手何須悟昨非。", "已喜一翁歸綠野，更看三傑上黄扉。", "雲臺指日標鴻烈，應許嚴陵老釣磯。"]'),
('ad88f087-0aad-4bc1-b754-25a0002ea9a7','餞明守謝殿撰赴召致語口號','史浩','宋','宋诗','song-poetry','','[]','玉砌芝蘭慶有餘，藹然英譽走雲衢。',64,'全唐诗/poet.song.115000.json','["玉砌芝蘭慶有餘，藹然英譽走雲衢。", "澄清攬轡多持節，愷悌宜民屢剖符。", "聖主出綸催上道，邦人卧轍蔽行途。", "一巵聽取臨岐語，剩吐精忠作帝謨。"]'),
('930afb4b-635c-434f-9bcc-6616e83d0f4e','待明守楊少卿致語口號','史浩','宋','宋诗','song-poetry','','[]','鄮城鬰鬰藹祥烟，何幸分符得大賢。',64,'全唐诗/poet.song.115000.json','["鄮城鬰鬰藹祥烟，何幸分符得大賢。", "散利士知廉律己，救荒民仰食爲天。", "仁風行見周千里，雅俗俱欣受一廛。", "正恐最聞須召入，介眉今日且樽前。"]'),
('9d285643-aa93-4efc-a3c3-649bf4b7c456','復明守楊少卿會致語口號','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春入西湖繞岸花，十洲三島倍芳華。',64,'全唐诗/poet.song.115000.json','["春入西湖繞岸花，十洲三島倍芳華。", "夭桃來自神明胄，玉潤生從宰輔家。", "男室得時諧鳳侶，孫枝有客泛星槎。", "盍簪此日成高會，盛事他年梓里誇。"]'),
('f0a52408-1e81-4951-b696-7c81cd18b5c7','復趙倅會致語口號','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寶緒光華是似賢，遠移仙馭締姻聯。',64,'全唐诗/poet.song.115000.json','["寶緒光華是似賢，遠移仙馭締姻聯。", "高情已篤金蘭契，盛禮還開錦繡筵。", "小奉杯盤圖報答，剩陳絲竹且留連。", "細看四座神仙客，始信西湖即洞天。"]'),
('7c774305-a09a-40f1-b444-fdb95a5f39fb','納孫婦錢氏親會致語口號','史浩','宋','宋诗','song-poetry','','[]','夾路紅榴取次芳，三槐嫩綠影交相。',64,'全唐诗/poet.song.115000.json','["夾路紅榴取次芳，三槐嫩綠影交相。", "解裝初憩簪纓客，肆席爰開衮繡堂。", "西子隨車騰懿德，東床擇婿得仙郎。", "一巵何止千秋祝，更佇鳴騶下帝鄉。"]'),
('a3cb9287-a244-4ab1-be9d-04f06ea05eaf','待明守趙殿撰致語口號','史浩','宋','宋诗','song-poetry','','[]','潭潭大府坐真王，有子於今擁碧幢。',64,'全唐诗/poet.song.115000.json','["潭潭大府坐真王，有子於今擁碧幢。", "羽扇仁風辭霅水，熊幡和氣滿鄞江。", "舞翻回雪隨清吹，歌遏行雲度美腔。", "玉斝莫辭良夜飲，佇看星聚首吾邦。"]'),
('8a6ea114-3d6a-4a28-b4ab-39fe92893654','婿王肅之就成親會致語口號','史浩','宋','宋诗','song-poetry','','[]','太宰巖巖正拱宸，笑看雙鳳度東津。',64,'全唐诗/poet.song.115000.json','["太宰巖巖正拱宸，笑看雙鳳度東津。", "冰清愛弟爲佳婿，玉立難兄處上賓。", "火毓鵲爐香藹藹，月穿梅影酒粼粼。", "主人剩喜機雲集，唯祝聯鑣侍紫宸。"]'),
('908b7023-1922-4e6d-9c86-ef9036a00181','待王十六監岳致語口號','史浩','宋','宋诗','song-poetry','','[]','東皇旌旆到人寰，漏泄春工露一斑。',64,'全唐诗/poet.song.115000.json','["東皇旌旆到人寰，漏泄春工露一斑。", "已向江村訪梅萼，却來燈市賞鰲山。", "主賓冰玉歡無盡，伯季塤箎興不慳。", "欲識魯公須拜後，微黄一點見眉間。"]'),
('ae3ac8d1-1d1e-46a2-9d64-872aab31ec70','代彌堅就趙府作會致語口號','史浩','宋','宋诗','song-poetry','','[]','潭潭大府坐真王，中有神仙聚畫堂。',64,'全唐诗/poet.song.115000.json','["潭潭大府坐真王，中有神仙聚畫堂。", "玉潤曾聞韵琴瑟，冰清初喜見鸞凰。", "扶輿和氣笙歌沸，馥鬰春風錦繡光。", "他日諸孫成宅相，頷頭休羨郭汾陽。"]'),
('0a79cf99-5123-4c30-aefa-be0fffe5cdd5','諸親慶壽致語口號','史浩','宋','宋诗','song-poetry','','[]','鬰葱佳氣擁叢霄，又見端門遣使軺。',64,'全唐诗/poet.song.115000.json','["鬰葱佳氣擁叢霄，又見端門遣使軺。", "觴豆兼全真璀璨，茗香剩馥更飄颻。", "雙旌容與留千騎，三族耆龐聚一朝。", "正是瑶池八仙會，介眉何必羨松喬。"]'),
('90569ac0-8016-477d-82e4-6aa1f544ead2','六老會致語口號','史浩','宋','宋诗','song-poetry','','[]','六人四百四十歲，好似同資一氣生。',64,'全唐诗/poet.song.115000.json','["六人四百四十歲，好似同資一氣生。", "王母蟠桃三度熟，竇家仙桂五枝榮。", "蓬壺影裏環嘉客，衮繡堂中溢頌聲。", "太史占祥應入奏，光躔南斗壽星明。"]'),
('b7d92db4-83b5-47c6-b0d6-8f2f1e549720','五老會致語口號','史浩','宋','宋诗','song-poetry','','[]','昔日翱翔藝圃中，詞鋒凜凜各爭雄。',64,'全唐诗/poet.song.115000.json','["昔日翱翔藝圃中，詞鋒凜凜各爭雄。", "倦飛雅遂鴻冥志，良集皆成鶴髮翁。", "休問功名千古後，且欣花月一樽同。", "明朝太史應馳奏，壽象聯珠見甬東。"]'),
('23ab8784-79e7-4cdb-a8ea-5687e550fd69','待權明州延提刑致語口號','史浩','宋','宋诗','song-poetry','','[]','山水東鄞本自佳，使星臨照愈光華。',64,'全唐诗/poet.song.115000.json','["山水東鄞本自佳，使星臨照愈光華。", "甘棠美蔭踰千里，畫角仁聲度萬家。", "正喜泉香浮竹葉，更看杯影浸梅花。", "最聞便有芝封到，莫惜連宵暈臉霞。"]'),
('e9839b52-78c1-4498-8c76-66c03f71ee02','待胡少張王叔舉二孫婿致語口號','史浩','宋','宋诗','song-poetry','','[]','鬰葱佳氣靄鄞川，剩說侯門得二賢。',64,'全唐诗/poet.song.115000.json','["鬰葱佳氣靄鄞川，剩說侯門得二賢。", "天下中庸追遠躅，江東儁秀踵遺編。", "歌喉睍睆鶑同麗，舞袖翩翻蝶共妍。", "行看聯名登虎榜，親闈歸侍綵衣鮮。"]'),
('2b880a0e-dc26-4364-9bac-6020e0b7e9ae','姊加封太宜人慶會致語口號','史浩','宋','宋诗','song-poetry','','[]','鄮山鄞水百祥開，一軸絲綸天上來。',64,'全唐诗/poet.song.115000.json','["鄮山鄞水百祥開，一軸絲綸天上來。", "應爲教忠登仕籍，遂膺錫類到蘭陔。", "笙簧叢裏歌新闋，錦繡光中薦寶杯。", "從此芝封須疊至，長教壽母宴春臺。"]'),
('134dd70f-aacf-41fb-8971-31be42248773','德翁弟轉員郎慶會致語口號','史浩','宋','宋诗','song-poetry','','[]','鄮山鄞水百祥臻，天祐龍門萃達尊。',64,'全唐诗/poet.song.115000.json','["鄮山鄞水百祥臻，天祐龍門萃達尊。", "又見常珍登耄齒，更欣華秩亞星垣。", "龔黄政美褒宜重，箕翼光騰福正繁。", "他日老更興盛舉，會看兄弟迭承恩。"]'),
('c9f9619b-1a0f-4dfd-bbad-2a389e1ee6d6','燕新第鄉人致語口號','史浩','宋','宋诗','song-poetry','','[]','鄮山鄞水百祥開，壯士昂頭謝草萊。',64,'全唐诗/poet.song.115000.json','["鄮山鄞水百祥開，壯士昂頭謝草萊。", "戛玉鏘金俱傑出，紆青拖紫正朋來。", "未饒衛國多君子，何獨山東有相材。", "富貴功名隨步武，清時鐘鼓且銜杯。"]'),
('238add51-40eb-47d5-8595-f038f81fbec1','復諸親慶會致語口號','史浩','宋','宋诗','song-poetry','','[]','潭府今朝雅宴開，鬰紛佳氣靄蓬萊。',64,'全唐诗/poet.song.115000.json','["潭府今朝雅宴開，鬰紛佳氣靄蓬萊。", "笙歌叢裏環珠履，衮繡光中薦玉杯。", "已喜群仙來閬苑，更須三熟見瑶臺。", "料應太史占乾象，星斗森羅擁上臺。"]'),
('0705ef10-1fdb-4d79-84d8-be087d20a85f','寄居慶汪中嘉尚書年登七秩會致語口號','史浩','宋','宋诗','song-poetry','','[]','鄮山鄞水百祥開，天祐神仙間世來。',64,'全唐诗/poet.song.115000.json','["鄮山鄞水百祥開，天祐神仙間世來。", "剩喜千齡纔七秩，更祈八座上三臺。", "簫韶聲裏翻紅袖，衮繡光中釂玉杯。", "每閲十期成再會，方瞳丹臉永如孩。"]'),
('f14e0bed-8413-4bed-be10-fd4e1d744136','宴明守林郎中致語口號','史浩','宋','宋诗','song-poetry','','[]','春融綠野日遲遲，五馬相從燕喜時。',64,'全唐诗/poet.song.115000.json','["春融綠野日遲遲，五馬相從燕喜時。", "濕翠峰前揮玉麈，香梅影底引瑶巵。", "適聞聖主詢黄髮，將趣文翁上赤墀。", "且趁好天同一醉，陶陶莫問夜何其。"]'),
('2fa45109-9c18-422a-8b06-5889cea59584','宴奉使楊御藥致語口號','史浩','宋','宋诗','song-poetry','','[]','神聖相承樂太平，尊賢貴老有真情。',64,'全唐诗/poet.song.115000.json','["神聖相承樂太平，尊賢貴老有真情。", "煌煌鳳翮飛丹檢，赫赫軺車下紫清。", "觴豆交酬當美景，笙竽合樂起新聲。", "客星今喜使星聚，乾象森羅徹曉明。"]'),
('572405ef-c2cf-4b37-99dc-a8aa57d824f7','寄居慶汪中嘉尚書致語口號','史浩','宋','宋诗','song-poetry','','[]','剩喜群仙集四明，年踰七秩慶耆英。',64,'全唐诗/poet.song.115000.json','["剩喜群仙集四明，年踰七秩慶耆英。", "三章快遂歸田志，八座爭看衣錦榮。", "笑捧一巵龜鶴壽，歡騰六樂鳳鸞鳴。", "舉頭莫道長安遠，會見臨廱拜老更。"]'),
('905cdafe-2f25-4d22-9fc9-a08315e441e3','餞明守林郎中致語口號','史浩','宋','宋诗','song-poetry','','[]','聖主留神惠兆民，循良奉詔莫辭頻。',64,'全唐诗/poet.song.115000.json','["聖主留神惠兆民，循良奉詔莫辭頻。", "纔聞五袴喧三輔，又擁雙旗鎮七閩。", "操袂不須成作惡，舉觴方喜上通津。", "日邊正擬登黄霸，會見槐庭衮繡新。"]'),
('54a8e1bd-7dd9-47e9-9bf9-6a630c971b5d','待明州權府提刑虞察院致語口號','史浩','宋','宋诗','song-poetry','','[]','小春纔過氣紆徐，門外旌麾正塞途。',64,'全唐诗/poet.song.115000.json','["小春纔過氣紆徐，門外旌麾正塞途。", "剩喜二天臨制閫，却來三徑訪耆儒。", "酒浮沆瀣杯中液，茗瀹槍旗碗面腴。", "且趁良宵拚一醉，賜環行即上亨衢。"]'),
('52b9b7d8-6648-4520-82cd-14546cf71c78','宴明守高大卿致語口號','史浩','宋','宋诗','song-poetry','','[]','東風昨夜到林塘，千騎初臨綠野堂。',64,'全唐诗/poet.song.115000.json','["東風昨夜到林塘，千騎初臨綠野堂。", "樂裏何煩絲竹韵，座間自有雪梅芳。", "民安竟夜戶不閉，海靜無波帆穩張。", "趁此清平同一醉，金甌已覆潁川黄。"]'),
('ed3c4672-f333-41dd-ba29-a490895ace74','聞家中被盜作三頌勉之  其一','史浩','宋','宋诗','song-poetry','','[]','年饒穀擁困群耕，盜賊多從此輩生。',32,'全唐诗/poet.song.115000.json','["年饒穀擁困群耕，盜賊多從此輩生。", "料得欲偷偷既得，從今改惡不宵行。"]'),
('3f8d7f30-cadb-43cc-9b7a-2f1d1ab81e92','聞家中被盜作三頌勉之  其二','史浩','宋','宋诗','song-poetry','','[]','幾年補破得遮寒，今日空餘赤肉團。',32,'全唐诗/poet.song.115000.json','["幾年補破得遮寒，今日空餘赤肉團。", "從此便知元不有，細書詞理枉經官。"]'),
('ed08fbbd-3380-4f69-ae8e-df4b172ef24d','聞家中被盜作三頌勉之  其三','史浩','宋','宋诗','song-poetry','','[]','孟光衣服合山居，烟褐明青休著渠。',32,'全唐诗/poet.song.115000.json','["孟光衣服合山居，烟褐明青休著渠。", "欲得此曹心不動，只將荆布在冠裾。"]'),
('81566198-f7ff-445d-b828-a4943453f976','羽客熊葉二師言歸鐵柱以五十六言餞之','史浩','宋','宋诗','song-poetry','','[]','喜見洪都二散人，直疑吳許是前身。',64,'全唐诗/poet.song.115000.json','["喜見洪都二散人，直疑吳許是前身。", "看梅始識林和靖，載酒還尋賀季真。", "鐵柱擎天龍已蟄，星壇近斗月爲鄰。", "思歸却有他年約，來慶吾登九十春。"]'),
('a46e219e-16dd-4c97-a9cc-1e14ac56e409','次韵賁長老','史浩','宋','宋诗','song-poetry','','[]','露地當年說白牛，反令後學莫能由。',64,'全唐诗/poet.song.115000.json','["露地當年說白牛，反令後學莫能由。", "足行香陌無窮轍，家在清江欲盡頭。", "罣礙頓除猶是病，因緣未了且乘流。", "此山日夕浮佳氣，見則何煩蠟屐游。"]'),
('b35fbd1c-7b15-4c64-b7cf-79a0a8e84b63','適過寶奎壽居仁師出示王判院偈真隠老子走筆次韵','史浩','宋','宋诗','song-poetry','','[]','見了黄梅留一宿，此風久矣無人續。',128,'全唐诗/poet.song.115000.json','["見了黄梅留一宿，此風久矣無人續。", "相逢誰許問寒暄，箇中且自龜藏六。", "壽師嚴冷面如鐵，背負真乘腰不折。", "有時禪定出塵表，兀坐蒲團頭滿雪。", "平生俗物不掛目，終日翻經聊自足。", "不離當處常湛然，波澄倒影千山綠。", "邇來邂逅文中虎，一幅水藤爲下語。", "我今欲贊沒因由，只把茶甌對趙州。"]'),
('57bbba54-0499-47ad-9fa3-9e7bc93af6db','酬釋法平  其一','史浩','宋','宋诗','song-poetry','','[]','團團璧月印寒潭，時有清風掃碧嵐。',32,'全唐诗/poet.song.115000.json','["團團璧月印寒潭，時有清風掃碧嵐。", "照見山人方隠几，灑然無物自沈酣。"]'),
('f873933c-017e-4ab9-936f-345f7bb7fbc4','酬釋法平  其二','史浩','宋','宋诗','song-poetry','','[]','白鷺棲烟一點明，皎然壓倒語全清。',32,'全唐诗/poet.song.115000.json','["白鷺棲烟一點明，皎然壓倒語全清。", "莫言後代無人繼，仗錫行將擅此名。"]'),
('f9a2cf4f-6afc-43ac-99db-a5d27851f6c1','再次韻胡中方賞丹桂之什','史浩','宋','宋诗','song-poetry','','[]','鄮峰老子雙瞳碧，已悟人間空是色。',258,'全唐诗/poet.song.115000.json','["鄮峰老子雙瞳碧，已悟人間空是色。", "群花四季作芳菲，一笑觀之如不識。", "有時斗酒沽十千，狂歌爛醉群花前。", "紅紅白白自妖艷，誰曾着口論媸妍。", "惟聞丹桂藏青蒨，清芬正滿姮娥殿。", "却思一見無由緣，但寫奇標在團扇。", "忽聞移本下吾鄉，此願端知合得償。", "園工玉斧與換骨，坐使凡種皆天香。", "先皇得之植禁地，飫賞鈞天動仙吹。", "高燒鳳蠟類星繁，正恐夜深花欲睡。", "於今哀戚徧幽明，鼎湖仙駕超塵氛。", "遺髯注想文王囿，玉闌佳氣徒氤氳。", "胡君真材一二數，他日補天慕媧女。", "正欲攀枝效郗詵，會看聲名飛海宇。", "雄篇拂地如鏘金，俊逸清新洗我心。", "怪底斯人掉頭不肯住，明年射策君門去。"]'),
('ca3f7014-598e-4978-8021-b9aeb3276ea2','訪混樸吳尊師','史浩','宋','宋诗','song-poetry','','[]','何年隠四明，與世絕逢迎。',48,'全唐诗/poet.song.115000.json','["何年隠四明，與世絕逢迎。", "聖主方虛席，先生不入城。", "風雷隨地起，宮殿自天成。", "近喜籃輿穩，寧憂白髮生。"]'),
('0b1a87a1-7f33-4db3-b27e-dbe4c9cb6b7b','贈傅得一  其一','史浩','宋','宋诗','song-poetry','','[]','試問此行何所止，烏有鄉中無住里。',32,'全唐诗/poet.song.115000.json','["試問此行何所止，烏有鄉中無住里。", "醉時不覺醒時癡，世人誰識顛道士。"]'),
('31b1b502-82da-4c04-950a-3d6b0110a8d7','贈傅得一  其二','史浩','宋','宋诗','song-poetry','','[]','相識三十年，身顛心不顛。',24,'全唐诗/poet.song.115000.json','["相識三十年，身顛心不顛。", "有人還會得，即是地行仙。"]'),
('8bfa7a07-baf0-439f-be48-09dafec64a00','嚴光墓','史浩','宋','宋诗','song-poetry','','[]','玉匣蛟龍已草萊，一丘馬鬣尚封培。',32,'全唐诗/poet.song.115000.json','["玉匣蛟龍已草萊，一丘馬鬣尚封培。", "雲臺若也表名姓，千古誰知有釣臺。"]'),
('90dc8004-7299-43e5-9490-cf87c6c6e1b3','東錢湖','史浩','宋','宋诗','song-poetry','','[]','行李蕭蕭一擔秋，浪頭始得見漁舟。',64,'全唐诗/poet.song.115000.json','["行李蕭蕭一擔秋，浪頭始得見漁舟。", "晚烟籠樹鴉還集，碧水連天鷗自浮。", "十字港通霞嶼寺，二靈山到月波樓。", "于今幸遂歸湖願，長憶當年賀監游。"]'),
('55e69d6d-3fae-43ff-b4e9-9b00f792ae77','題墨花','史浩','宋','宋诗','song-poetry','','[]','元功初剪刻，妙處極玄玄。',24,'全唐诗/poet.song.115000.json','["元功初剪刻，妙處極玄玄。", "醉墨誰家筆，于今合自然。"]'),
('9495d9c2-86b3-40fb-8007-de432ccaf140','盡心堂','史浩','宋','宋诗','song-poetry','','[]','曲士懷軒裳，銖寸較得失。',288,'全唐诗/poet.song.115000.json','["曲士懷軒裳，銖寸較得失。", "紛紜戰寵辱，矛盾相撞抶。", "大方惟達人，天遊寄虛室。", "卷舒儻由己，出處要無必。", "時來作砭針，一起當療疾。", "時去收龍蛇，夭矯自超逸。", "隠見了無礙，妙迹那可詰。", "我公天人姿，宿有補天術。", "心宜盡心理，心靜與天一。", "當年風雨會，黄道賓出日。", "乾坤方瘡痍，塗炭入憂恤。", "神鋒指幽燕，酋領將斧鑕。", "世數有長消，匆匆謝簪紱。", "歸來卧林藪，道自無伸屈。", "慶堂示餘彥，親灑銀筆述。", "聊遺郢人斤，千載斲妙質。", "定應山水觀，中與胸趣匹。", "仰看衡雲飛，雲靜山崒嵂。", "俯眄湘流水，舟楫空蕩潏。", "可憐天東北，狼煙暗鬰律。", "神州見蒼莽，悲風爲蕭瑟。", "再拜願有期，經綸勿韜鬰。", "天心酌民言，公再調鼎實。", "風霆驅八荒，遊戲須一出。"]'),
('0299407e-0303-4c40-8de0-241fcf189731','喻彌陀偈','史浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','攪翻十里西湖水，化作四方八德池。',32,'全唐诗/poet.song.115000.json','["攪翻十里西湖水，化作四方八德池。", "浄洗衆生煩惱垢，人人見自性阿彌。"]'),
('88a10da5-5b8e-4bab-b6b3-ecd9c0da519a','以日者命狀寄王龜齡','唐文若','宋','宋诗','song-poetry','','[]','試把流年子細看，休將蠖屈比鵬摶。',32,'全唐诗/poet.song.115000.json','["試把流年子細看，休將蠖屈比鵬摶。", "君家大有回天力，不爲區區作好官。"]'),
('4e6a94a8-f689-4ad7-ac9c-d2df6475af82','題紹興煥文閣  其一','唐文若','宋','宋诗','song-poetry','','[]','山光水色借春妍，登盡參差下九天。',32,'全唐诗/poet.song.115000.json','["山光水色借春妍，登盡參差下九天。", "共看玉泉香案吏，重來點檢白雲篇。"]'),
('e3ef86d5-d50f-4882-a324-f9f1938345c4','題紹興煥文閣  其二','唐文若','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','三峨直上片雲飛，飛過匡廬惹住衣。',32,'全唐诗/poet.song.115000.json','["三峨直上片雲飛，飛過匡廬惹住衣。", "我亦朱轓暫容與，山南山北判清輝。"]'),
('5019ebe9-ac44-44f1-81a1-991188ff8dd1','登金山','唐文若','宋','宋诗','song-poetry','','[]','江流出岷蜀，萬折東南傾。',156,'全唐诗/poet.song.115000.json','["江流出岷蜀，萬折東南傾。", "茲山若巨舫，勢欲扼滄溟。", "天高象教尊，海岳朝百靈。", "雲水渺四極，下上涵日星。", "朱甍倚霄漢，倒影魚龍驚。", "重遊十年舊，挂席鷗鳥輕。", "維揚魏公幕，回首劍戟明。", "行都望北固，鐵甕高崢嶸。", "孤舟繫烟月，六尺僧窗橫。", "印師支遠儔，靜對如風鈴。", "曠懷憐此翁，得法世慮平。", "塵勞霜髮禿，風月冰壺清。", "乞詩寫崖壁，指月雙浮萍。"]'),
('58f99edd-0d1c-4506-90f8-a0bfb14df988','句  其一','唐文若','宋','宋诗','song-poetry','','[]','秋風髣髴吳江渡，鷗鷺參差夕陽影。',48,'全唐诗/poet.song.115000.json','["秋風髣髴吳江渡，鷗鷺參差夕陽影。", "垂虹納納卧譙門，雉堞耽耽俯漁艇。", "陽安小兒拍手笑，使君幻出江南景。"]'),
('d071cc2b-28ca-4dba-9107-5c6202b3723f','句  其二','唐文若','宋','宋诗','song-poetry','','[]','陽安城西百尺樓，畫棟翬飛出鼇嶺。',32,'全唐诗/poet.song.115000.json','["陽安城西百尺樓，畫棟翬飛出鼇嶺。", "蜀漢東南此地分，勝槩悠悠誰復領。"]'),
('f77b8895-47a7-41cc-8808-b1b1d3b43130','石千里來自崑山陳闊未幾倏爾言別輒成詩少舒戀戀  其一','陳之茂','宋','宋诗','song-poetry','','[]','零露滋百草，灼灼黄花披。',84,'全唐诗/poet.song.115000.json','["零露滋百草，灼灼黄花披。", "眷此忘憂物，一杯誰共持。", "人生豈無好，所樂在所知。", "開門望三益，邂逅得所思。", "鳴弦詠綢繆，歲暮以爲期。", "倏駕不可留，良會復何時。", "不愁道路隔，但恐人事違。"]'),
('81d202fc-0863-4a99-be54-df79029c7846','石千里來自崑山陳闊未幾倏爾言別輒成詩少舒戀戀  其二','陳之茂','宋','宋诗','song-poetry','','[]','烏鵲巢空壇，鸞鳳伏荆杞。',84,'全唐诗/poet.song.115000.json','["烏鵲巢空壇，鸞鳳伏荆杞。", "懷抱發永歎，感深念君子。", "斯人在空谷，弗御紈與綺。", "松柏培不榮，芝蘭種不起。", "浩浩歲月移，日暮雪霜底。", "物理固非常，循環有終始。", "但保千金軀，清尊傾綠蟻。"]'),
('9dc9fb47-5b60-46f2-98d6-8c1f658e5574','教子詩','余良弼','宋','宋诗','song-poetry','','[]','白髮無憑吾老矣，青春不再汝知乎。',64,'全唐诗/poet.song.115000.json','["白髮無憑吾老矣，青春不再汝知乎。", "年將弱冠非童子，學不成名豈丈夫。", "幸有明窗羣凈几，何勞鑿壁與編蒲。", "功成欲自殊頭角，記取韓公訓阿符。"]'),
('530838db-e247-484f-937d-7fcbb63a0227','詩一首','余良弼','宋','宋诗','song-poetry','','[]','萬僞何緣鬭一真，時間謾得面前人。',32,'全唐诗/poet.song.115000.json','["萬僞何緣鬭一真，時間謾得面前人。", "生男種女多喑啞，果報元來必有因。"]'),
('31a2db05-c4fb-4835-a687-ccde23e50643','句','余良弼','宋','宋诗','song-poetry','','[]','江流不復三峽險，天際自此中州寬。',16,'全唐诗/poet.song.115000.json','["江流不復三峽險，天際自此中州寬。"]'),
('2d1302fd-ca7a-4efb-a24a-c252ede67ada','題沖真觀','趙琥','宋','宋诗','song-poetry','','[]','琳館絕埃塵，溪山是四鄰。',48,'全唐诗/poet.song.115000.json','["琳館絕埃塵，溪山是四鄰。", "煙霞千古色，花木一庭春。", "月白琴聲朗，風清鶴唳頻。", "閒中時復醉，應笑市朝人。"]'),
('70173ed6-f5ad-4bc1-9285-0bc6f389fb64','密老','趙琥','宋','宋诗','song-poetry','','[]','匹馬飄然似轉蓬，一年兩度過湘東。',64,'全唐诗/poet.song.115000.json','["匹馬飄然似轉蓬，一年兩度過湘東。", "襟裙潤带黄梅雨，枕簟凉生若楝風。", "急急窮途將底用，區區苟祿有何功。", "輸他燕坐長廳老，點對濃香丈室中。"]'),
('b84d60f1-09df-41ac-9592-3c89f4b0a026','別友','趙琥','宋','宋诗','song-poetry','','[]','斜風細雨釀輕寒，握手相看話別難。',32,'全唐诗/poet.song.115000.json','["斜風細雨釀輕寒，握手相看話別難。", "有酒莫辭今日醉，鳳儀門外即陽關。"]'),
('7d0113da-cba1-45af-8032-d656eb222cef','題喜鵲棲樹','趙琥','宋','宋诗','song-poetry','','[]','梳翎刷羽立高柯，不落人間小網羅。',32,'全唐诗/poet.song.115000.json','["梳翎刷羽立高柯，不落人間小網羅。", "一點通靈良不謬，簷頭報我喜還多。"]'),
('cbd76433-35e9-4374-9274-591b4687b048','和潘良貴題三江亭韻','王伯庠','宋','宋诗','song-poetry','','[]','使君不受二毛侵，杖屨逍遥得勝尋。',64,'全唐诗/poet.song.115000.json','["使君不受二毛侵，杖屨逍遥得勝尋。", "撥遣簿書聊永日，登臨山水亦何心。", "殘梅墮雪垂垂白，弱柳摇春淡淡金。", "倚矚大江供一笑，幾多襦袴在謳吟。"]'),
('e78e0642-75eb-4474-a327-dfd1fd404941','恭和御製玉津園宴射  其一','曾懷','宋','宋诗','song-poetry','','[]','名園佳氣靄非烟，冠佩朝宗似百川。',64,'全唐诗/poet.song.115000.json','["名園佳氣靄非烟，冠佩朝宗似百川。", "五品并令陪宴射，四鍭端欲序賓賢。", "恩涵春意魚翻藻，威入秋聲雁落弦。", "竣事更容窺典雅，宸章應陋柏梁篇。"]'),
('403c77eb-2e7e-4bab-a497-5de3519f1d98','恭和御製玉津園宴射  其二','曾懷','宋','宋诗','song-poetry','','[]','江山秋日冠輕烟，別苑風光勝輞川。',64,'全唐诗/poet.song.115000.json','["江山秋日冠輕烟，別苑風光勝輞川。", "位設虎侯恢盛典，枝穿楊葉校名賢。", "禮均湛露宣飛斝，樂奏鈞天着發弦。", "聖主經文與緯武，全勝巡幸射蛟篇。"]'),
('04f40d54-842e-4909-9810-bd449a0c5655','與王伯芻  其一','楊愿','宋','宋诗','song-poetry','','[]','冷官廳事客來稀，種綠陰陰結夏帷。',32,'全唐诗/poet.song.115000.json','["冷官廳事客來稀，種綠陰陰結夏帷。", "忽得君詩愜人意，陶家風到北窗時。"]'),
('47573ba2-9630-4d90-b0fe-4b2cfa70b87b','與王伯芻  其二','楊愿','宋','宋诗','song-poetry','','[]','只今侍讀周夫子，屢說君詩似杜詩。',32,'全唐诗/poet.song.115000.json','["只今侍讀周夫子，屢說君詩似杜詩。", "速把冠塵盡彈却，玉堂宵直伴王維。"]'),
('3c9f7a0b-ac6a-48b5-a9cf-8b316b73755d','惜梅','楊煒','宋','宋诗','song-poetry','','[]','廿年作伴似相知，積霰層冰花滿枝。',32,'全唐诗/poet.song.115000.json','["廿年作伴似相知，積霰層冰花滿枝。", "何事一朝攀折盡，暗香疏影繫人思。"]'),
('5322eaf2-46e9-4eb9-8c27-171a0a1e82dd','偈','釋慧空','宋','宋诗','song-poetry','','[]','先打春牛頭，後打春牛尾，驚起虛空入藕絲裏。',65,'全唐诗/poet.song.115000.json','["先打春牛頭，後打春牛尾，驚起虛空入藕絲裏。", "釋迦無路潛蹤，彌勒急走千里。", "文殊却知落處，撫掌大笑歡喜。", "春風昨夜入門來，便見千華生碓嘴。"]'),
('6398e965-941b-4f94-8f07-06c5bbbba4ee','頌古十首  其一','釋慧空','宋','宋诗','song-poetry','','[]','做得些兒活計成，人前賣弄逞才能。',32,'全唐诗/poet.song.115000.json','["做得些兒活計成，人前賣弄逞才能。", "直饒踏殺人無數，也是西川老鬼精。"]'),
('07762557-497e-43be-8c73-1f227cc1da88','頌古十首  其二','釋慧空','宋','宋诗','song-poetry','','[]','從頭數到一二三，倒數却成三二一。',32,'全唐诗/poet.song.115000.json','["從頭數到一二三，倒數却成三二一。", "直饒善會大衍算，掐指巡文數不出。"]'),
('29d05182-7f20-41e1-81b0-6b0c1c6682c9','頌古十首  其三','釋慧空','宋','宋诗','song-poetry','','[]','動絃別曲，葉落知秋。',20,'全唐诗/poet.song.115000.json','["動絃別曲，葉落知秋。", "擬議不來，休休休休。"]'),
('8d736f55-478b-43c3-a335-8d58875e1b70','頌古十首  其四','釋慧空','宋','宋诗','song-poetry','','[]','主人無德客無機，石火光中閃電飛。',32,'全唐诗/poet.song.115000.json','["主人無德客無機，石火光中閃電飛。", "同死同生同得失，此心能有幾人知。"]'),
('b58559ba-7b37-4686-aa64-e959aef0be34','頌古十首  其五','釋慧空','宋','宋诗','song-poetry','','[]','鬼門貼卦鬼猶驚，又見毛頭掃帚星。',32,'全唐诗/poet.song.115000.json','["鬼門貼卦鬼猶驚，又見毛頭掃帚星。", "若得過關公驗正，夜深把手御街行。"]'),
('89cd92b7-123c-40b6-83a0-8b4e44c077d3','頌古十首  其六','釋慧空','宋','宋诗','song-poetry','','[]','連馬連人劈一刀，虛空迸血湧波濤。',32,'全唐诗/poet.song.115000.json','["連馬連人劈一刀，虛空迸血湧波濤。", "千千萬萬人爭看，誰解分開蓋膽毛。"]'),
('4b056bda-a588-4c9e-9c23-f54a69729e43','頌古十首  其七','釋慧空','宋','宋诗','song-poetry','','[]','卧龍纔奮迅，猛虎便咆哮。',28,'全唐诗/poet.song.115000.json','["卧龍纔奮迅，猛虎便咆哮。", "時人只見波濤湧，不知新月出林梢。"]'),
('3c3999ed-156a-46e3-9b9e-2d5d7f3e57d9','頌古十首  其八','釋慧空','宋','宋诗','song-poetry','','[]','丈二鋼釘，八尺鐵橛。',20,'全唐诗/poet.song.115000.json','["丈二鋼釘，八尺鐵橛。", "插在眼中，猶自不瞥。"]'),
('04053679-9080-4017-856d-d23dc0b40e29','頌古十首  其九','釋慧空','宋','宋诗','song-poetry','','[]','尀耐溈山老鬼精，垂鈎便要釣鯤鯨。',32,'全唐诗/poet.song.115000.json','["尀耐溈山老鬼精，垂鈎便要釣鯤鯨。", "幾多頭角爲龍去，蝦蟹依前努眼睛。"]'),
('d5200b80-3be6-4e26-bb99-f74b4e828bd2','頌古十首  其一○','釋慧空','宋','宋诗','song-poetry','','[]','一箭射落天邊雁，千人萬人著眼看。',32,'全唐诗/poet.song.115000.json','["一箭射落天邊雁，千人萬人著眼看。", "不知此箭自何來，湖南長老何曾見。"]'),
('713b1f52-9c07-4ea0-a953-86e2a3f23886','宮女睡','胡拂道','宋','宋诗','song-poetry','','[]','御手指嬋娟，青春白晝眠。',48,'全唐诗/poet.song.115000.json','["御手指嬋娟，青春白晝眠。", "羅衣香汗透，寶髻翠雲偏。", "柳葉眉間秀，桃花臉上鮮。", "夢魂何處去，身在帝王邊。"]'),
('f170de9d-f4cb-48b9-917c-a937601f85cd','重修龍堂詩','鄭漻','宋','宋诗','song-poetry','','[]','龍德蟠際，在蟲莫知。',156,'全唐诗/poet.song.115000.json','["龍德蟠際，在蟲莫知。", "實尸雨霖，鞭雷摇幟。", "蠢蠢生齒，腹饑謀食。", "四時罔避，力穡藝稷。", "耕深耰疾，人不勝天。", "雲蒸霧滃，頼龍以全。", "茲山由里名澄江，奫淪崒嵂龍之汪。", "飛液遇坎堪濫觴，荆扉挹啖逾蔗漿。", "焦土石裂暍欲僵，捧甖膏流收豐穰。", "天漏資車翻手强，掃氛駁翳開扶桑。", "鄭公慶餘森珪璋，使君成民神且康。", "報功新廟益熾昌，龍兮無專白雲鄉。"]'),
('fb8e7160-c67f-4ad9-909b-eb0976a84aaf','岳陽','范綜','宋','宋诗','song-poetry','','[]','萬里山川寬眼界，兩湖風月送天涯。',32,'全唐诗/poet.song.115000.json','["萬里山川寬眼界，兩湖風月送天涯。", "雲通巫峽襄王夢，鵩吊長沙賈誼家。"]'),
('75fb5617-315a-4751-b240-e5e2adabc4da','七星山','李弼','宋','宋诗','song-poetry','','[]','乘興上東山，天風拂壯顔。',48,'全唐诗/poet.song.115000.json','["乘興上東山，天風拂壯顔。", "七星連地脈，一竅透天關。", "玄鶴何年去，丹爐盡日閒。", "我因厭塵俗，到此不知還。"]'),
('1613aa26-a443-41e7-88bf-f58d9f3454bb','次吳說避地白巖山中書懷韻','鄧仁憲','宋','宋诗','song-poetry','','[]','避地南來極，吾鄉北斗邊。',48,'全唐诗/poet.song.115000.json','["避地南來極，吾鄉北斗邊。", "風塵今阻隔，途路舊迍邅。", "閭里千門盛，湖山百卉鮮。", "故鄉歸未得，飛夢入青天。"]'),
('d6de8789-7853-481b-8a10-f1e2121fc309','次廉布書事三首呈郎中機宜韻  其一','鄧仁憲','宋','宋诗','song-poetry','','[]','狎鷗東海上，結友竹林賢。',48,'全唐诗/poet.song.115000.json','["狎鷗東海上，結友竹林賢。", "國難知誰救，途窮祇自憐。", "空花迷眼界，秋月契心禪。", "未起歸歟興，重尋載酒船。"]'),
('bf696810-3773-4b46-9a66-690cd662362c','次廉布書事三首呈郎中機宜韻  其二','鄧仁憲','宋','宋诗','song-poetry','','[]','五星不循軌，征戰未應休。',48,'全唐诗/poet.song.115000.json','["五星不循軌，征戰未應休。", "婦歎懷空室，鶴鳴增舊愁。", "劉公三見顧，諸葛萬機投。", "四海今多病，維摩分外憂。"]'),
('a6eb86e6-1d2d-45fe-96cb-528c98f549e3','次廉布書事三首呈郎中機宜韻  其三','鄧仁憲','宋','宋诗','song-poetry','','[]','明月杖頭掛，嘯歌滄海邊。',48,'全唐诗/poet.song.115000.json','["明月杖頭掛，嘯歌滄海邊。", "自聞獅子吼，盡吐野狐涎。", "酒興如流水，詩情似直絃。", "岩花應未老，更上白雲巔。"]'),
('403840c2-1c85-484b-b05e-e6a46cc19f21','瀑布泉','鄧仁憲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','鮫人對泣號且呼，灑落瀛洲萬斛珠。',128,'全唐诗/poet.song.115000.json','["鮫人對泣號且呼，灑落瀛洲萬斛珠。", "海神知貴不敢受，天池瀉下扶焦枯。", "初疑素霓隨銀漢，盡似明月投氷壺。", "廬山瀑布幾千丈，較此不可分錙銖。", "膠西先生春睡足，喜見晴光漱寒玉。", "武陵迷路初不知，錯認松風響岩谷。", "金波滿泛琉璃鍾，長揖雲峯謝拘束。", "更約青蓮社裏人，同向蒼崖結茆屋。"]'),
('ebd3c2f4-07f9-4384-9c15-03fdca9196b5','種梅  其一','史文卿','宋','宋诗','song-poetry','','[]','呼僮耕雲種瑶樹，斗挂青冥下風露。',32,'全唐诗/poet.song.115000.json','["呼僮耕雲種瑶樹，斗挂青冥下風露。", "隔林野鶴不知寒，爲我飛來復飛去。"]'),
('95cacf57-f8e7-4c97-9c09-9558072ef6e8','種梅  其二','史文卿','宋','宋诗','song-poetry','','[]','素與梅花自有緣，又移幾本種庭前。',32,'全唐诗/poet.song.115000.json','["素與梅花自有緣，又移幾本種庭前。", "鏡中一半閒風月，不屬王郎載雪船。"]'),
('b66b990d-ff4c-49c5-a6f3-562a0c46c5b1','惜春','史文卿','宋','宋诗','song-poetry','','[]','秀麥條桑翦翦寒，錦屏殘夢怯衣單。',32,'全唐诗/poet.song.115000.json','["秀麥條桑翦翦寒，錦屏殘夢怯衣單。", "惜春只怕春歸去，多插瓶花在處安。"]'),
('502bfd98-f1f2-46c3-9e03-e19ee944cdb3','秋詞  其一','史文卿','宋','宋诗','song-poetry','','[]','寫就秋詞雁影稀，背燈無語獨眠遲。',32,'全唐诗/poet.song.115000.json','["寫就秋詞雁影稀，背燈無語獨眠遲。", "畫欄點滴芭蕉雨，一夜將愁向阿誰。"]'),
('6a0c51e9-950e-451c-a974-5cafaae6984f','秋詞  其二','史文卿','宋','宋诗','song-poetry','','[]','桂枝風動小山幽，雨過陂池水漫流。',32,'全唐诗/poet.song.115000.json','["桂枝風動小山幽，雨過陂池水漫流。", "擬作楚騷吟未了，一行新雁數聲秋。"]'),
('08ffe63b-3bbd-48e4-860c-c92f209c622e','枯梅','史文卿','宋','宋诗','song-poetry','','[]','樛枝半著古苔痕，萬斛寒香一點春。',32,'全唐诗/poet.song.115000.json','["樛枝半著古苔痕，萬斛寒香一點春。", "總爲古今吟不盡，十分清瘦似詩人。"]'),
('4c45ac70-1161-4d44-8dd8-e70212dff323','偶成','史文卿','宋','宋诗','song-poetry','','[]','一生富貴皆空夢，千古英雄只斷碑。',32,'全唐诗/poet.song.115000.json','["一生富貴皆空夢，千古英雄只斷碑。", "幾欲含毫作天問，西風吹恨入江籬。"]'),
('fef537c9-8c0c-489c-9611-48e2f3cddf44','萬杉寺','史文卿','宋','宋诗','song-poetry','','[]','君恩報答果何如，手植松杉一萬株。',64,'全唐诗/poet.song.115000.json','["君恩報答果何如，手植松杉一萬株。", "溪足斷邊橫畧彴，峯頭好處見浮屠。", "鳳書御墨藏飛白，龍吐山泉散作珠。", "包帚祝堯同此類，刻崖大慶擬嵩呼。"]'),
('9f64e175-ffd6-48d5-b302-09a53d473b49','次韻何文縝墨梅二絕  其一','張子文','宋','宋诗','song-poetry','','[]','偃蹇江頭卧夕陽，懶將玉雪鬭春妍。',32,'全唐诗/poet.song.115000.json','["偃蹇江頭卧夕陽，懶將玉雪鬭春妍。", "心期老氏能知白，興寄揚雄獨守玄。"]'),
('3594cab8-91ec-4329-a42d-13aecb63f0ab','次韻何文縝墨梅二絕  其二','張子文','宋','宋诗','song-poetry','','[]','仙衣雲樣拂輕緇，林下神情特地宜。',32,'全唐诗/poet.song.115000.json','["仙衣雲樣拂輕緇，林下神情特地宜。", "妒婦津頭風恐急，壞妝聊爲變冰姿。"]'),
('ac0b4ec6-a98f-4619-a837-8e8af4e3fbc7','墨梅三絕  其一','張子文','宋','宋诗','song-poetry','','[]','筆端喚醒玉梅魂，滿袖春風不見痕。',32,'全唐诗/poet.song.115000.json','["筆端喚醒玉梅魂，滿袖春風不見痕。", "未許捲簾新月上，却教煙雨惱黄昏。"]'),
('45d6f7c6-ceec-49bf-bece-2d8c83b7607b','墨梅三絕  其二','張子文','宋','宋诗','song-poetry','','[]','憶昨江湖倒載歸，暗香夾路雨霏微。',32,'全唐诗/poet.song.115000.json','["憶昨江湖倒載歸，暗香夾路雨霏微。", "誰人貌得春風景，遠看如煙近却非。"]'),
('4117a8c8-ac4a-4a85-9465-1e3aa5086cc9','墨梅三絕  其三','張子文','宋','宋诗','song-poetry','','[]','逸少池邊發興新，管城別作一家春。',32,'全唐诗/poet.song.115000.json','["逸少池邊發興新，管城別作一家春。", "臨風玉笛無人會，鬒髮空歸想太真。"]'),
('4209d035-8a75-466a-b2fb-b0f953055728','題湧月亭二首  其一','黄子善','宋','宋诗','song-poetry','','[]','滄波空碧接青天，潮滿江平月正圓。',64,'全唐诗/poet.song.115000.json','["滄波空碧接青天，潮滿江平月正圓。", "風颭浪花來不盡，水涵輪影去無邊。", "舟中賞客方酣寢，窗下書生猶未眠。", "我欲携琴頻訪戴，越吟應許夜深傳。"]'),
('bdee7cac-121c-4845-aff0-40fce94aaa9b','題湧月亭二首  其二','黄子善','宋','宋诗','song-poetry','','[]','星河耿耿障雲披，劍氣崢嶸徹紫微。',64,'全唐诗/poet.song.115000.json','["星河耿耿障雲披，劍氣崢嶸徹紫微。", "輪輾碧空凌象緯，波翻清影射窗扉。", "寒光照夜潛蛟動，皓色穿林宿鳥飛。", "草樹無烟衣有露，夜深吟賞欲忘歸。"]'),
('1c1bba12-0678-41b9-b25f-20b57b6eae83','句','王俊彥','宋','宋诗','song-poetry','','[]','不雜人間種，恐遭天上殃。',12,'全唐诗/poet.song.115000.json','["不雜人間種，恐遭天上殃。"]'),
('93fcbd60-31ea-4dd8-824b-560527d12b4f','中和堂','宋高宗','宋','宋诗','song-poetry','','[]','六龍轉淮海，萬騎臨吳津。',96,'全唐诗/poet.song.115000.json','["六龍轉淮海，萬騎臨吳津。", "王者本無外，駕言蘇遠民。", "瞻彼草木秀，感此瘡痍新。", "登堂望稽山，懷哉夏禹勤。", "神功既盛大，後世蒙其仁。", "願同越句踐，焦思先吾身。", "艱難務遵養，聖賢有屈伸。", "高風動君子，屬意種蠡臣。"]'),
('c7e80c03-f7ae-40f3-81f2-2b3e26be14ab','梅巖','宋高宗','宋','宋诗','song-poetry','','[]','怪石蒼巖影翠霞，梅梢疎瘦正橫斜。',32,'全唐诗/poet.song.115000.json','["怪石蒼巖影翠霞，梅梢疎瘦正橫斜。", "得因祀事來尋勝，試探春風第一花。"]'),
('e4f3d306-6530-4f0a-8a45-a5bbecc65bab','漁父詞  其一','宋高宗','宋','宋诗','song-poetry','','[]','一湖春水夜來生，幾疊春山遠更橫。',32,'全唐诗/poet.song.115000.json','["一湖春水夜來生，幾疊春山遠更橫。", "煙艇小，釣絲輕，贏得閑中萬古名。"]'),
('0857f04d-dc84-4f99-8f4d-a7b1f041e04c','漁父詞  其二','宋高宗','宋','宋诗','song-poetry','','[]','薄晚煙林淡翠微，江邊秋月已明暉。',32,'全唐诗/poet.song.115000.json','["薄晚煙林淡翠微，江邊秋月已明暉。", "縱遠抱，適天機，水底閑雲片段飛。"]'),
('6db62731-0f49-4233-ae06-cdaf3a8120c8','漁父詞  其三','宋高宗','宋','宋诗','song-poetry','','[]','雪灑清江江上船，一錢何得買江天。',32,'全唐诗/poet.song.115000.json','["雪灑清江江上船，一錢何得買江天。", "催短棹，去長川，魚蟹來傾酒舍煙。"]'),
('937f6d73-5acc-46d3-996e-f22df93a683d','漁父詞  其四','宋高宗','宋','宋诗','song-poetry','','[]','青草開時已過船，錦鱗躍處浪痕圓。',32,'全唐诗/poet.song.115000.json','["青草開時已過船，錦鱗躍處浪痕圓。", "竹葉酒，柳花氊，有意沙鷗伴我眠。"]'),
('9b120e8c-f16d-46c7-bef3-5eebcab0ca9b','漁父詞  其五','宋高宗','宋','宋诗','song-poetry','','[]','扁舟小纜荻花風，四合青山暮靄中。',32,'全唐诗/poet.song.115000.json','["扁舟小纜荻花風，四合青山暮靄中。", "明細火，倚孤松，但願樽中酒不空。"]'),
('edded8f9-6065-474f-a8f0-31d0b5f867d0','漁父詞  其六','宋高宗','宋','宋诗','song-poetry','','[]','儂家活計豈能名，萬頃波心月影清。',32,'全唐诗/poet.song.115000.json','["儂家活計豈能名，萬頃波心月影清。", "傾綠酒，糝藜羹，保任衣中一物靈。"]'),
('67d41966-76dc-4066-bf7d-67ec44072a82','漁父詞  其七','宋高宗','宋','宋诗','song-poetry','','[]','駭浪吞舟脫巨鱗，結繩爲網也難任。',32,'全唐诗/poet.song.115000.json','["駭浪吞舟脫巨鱗，結繩爲網也難任。", "綸乍放，餌初沉，淺釣纖鱗味更深。"]'),
('5dba705c-153e-450a-a9e8-80866dda2c1d','漁父詞  其八','宋高宗','宋','宋诗','song-poetry','','[]','魚信還催花信開，花風得得爲誰來。',32,'全唐诗/poet.song.115000.json','["魚信還催花信開，花風得得爲誰來。", "舒柳眼，落梅腮，浪煖桃花夜轉雷。"]'),
('c65850bc-2650-4a75-bb6d-653edd49aa49','漁父詞  其九','宋高宗','宋','宋诗','song-poetry','','[]','莫莫朝朝冬復春，高車駟馬趁朝身。',32,'全唐诗/poet.song.115000.json','["莫莫朝朝冬復春，高車駟馬趁朝身。", "金拄屋，粟盈囷，那知江漢獨醒人。"]'),
('e166005e-67a8-435a-b801-2b7b4c398753','漁父詞  其一○','宋高宗','宋','宋诗','song-poetry','','[]','遠水無涯山有鄰，相看歲晚更情親。',32,'全唐诗/poet.song.115000.json','["遠水無涯山有鄰，相看歲晚更情親。", "笛裏月，酒中身，舉頭無我一般人。"]'),
('e9f1e024-7052-4ec2-a74d-bb1d418b6a08','漁父詞  其一一','宋高宗','宋','宋诗','song-poetry','','[]','誰云漁父是愚翁，一葉浮家萬慮空。',32,'全唐诗/poet.song.115000.json','["誰云漁父是愚翁，一葉浮家萬慮空。", "輕破浪，細迎風，睡起蓬窗日正中。"]'),
('2ca8776b-21ea-4af4-947a-b52893d71eb4','漁父詞  其一二','宋高宗','宋','宋诗','song-poetry','','[]','水涵微雨湛虛明，小笠輕簑未要晴。',32,'全唐诗/poet.song.115000.json','["水涵微雨湛虛明，小笠輕簑未要晴。", "明鑒裏，縠紋生，白鷺飛來空外聲。"]'),
('8f045bc7-4070-4f30-bf6a-04adc096bb97','漁父詞  其一三','宋高宗','宋','宋诗','song-poetry','','[]','無數菰蒲閒藕花，棹歌輕舉酌流霞。',32,'全唐诗/poet.song.115000.json','["無數菰蒲閒藕花，棹歌輕舉酌流霞。", "隨家好，轉山斜，也有孤村三兩家。"]');
